(function(){
  var V={"1 Chronicles 16:34": {"t": "Oh give thanks to Yahweh, for he is good, for his loving kindness endures forever.", "tr": "World English Bible"}, "1 Chronicles 29:11": {"t": "Yours, Yahweh, is the greatness, the power, the glory, the victory, and the majesty! For all that is in the heavens and in the earth is yours. Yours is the kingdom, Yahweh, and you are exalted as head above all.", "tr": "World English Bible"}, "1 Corinthians 11:23-26": {"t": "For I received from the Lord that which also I delivered to you, that the Lord Jesus on the night in which he was betrayed took bread. When he had given thanks, he broke it, and said, “Take, eat. This is my body, which is broken for you. Do this in memory of me.” In the same way he also took the cup, after supper, saying, “This cup is the new covenant in my blood. Do this, as often as you drink, in memory of me.” For as often as you eat this bread and drink this cup, you proclaim the Lord’s death until he comes.", "tr": "World English Bible"}, "1 Corinthians 11:3": {"t": "But I would have you know that the head of every man is Christ, and the head of the woman is the man, and the head of Christ is God.", "tr": "World English Bible"}, "1 Corinthians 11:5": {"t": "But every woman praying or prophesying with her head unveiled dishonors her head. For it is one and the same thing as if she were shaved.", "tr": "World English Bible"}, "1 Corinthians 13:12": {"t": "For now we see in a mirror, dimly, but then face to face. Now I know in part, but then I will know fully, even as I was also fully known.", "tr": "World English Bible"}, "1 Corinthians 13:4-7": {"t": "Love is patient and is kind; love doesn’t envy. Love doesn’t brag, is not proud, doesn’t behave itself inappropriately, doesn’t seek its own way, is not provoked, takes no account of evil; doesn’t rejoice in unrighteousness, but rejoices with the truth; bears all things, believes all things, hopes all things, endures all things.", "tr": "World English Bible"}, "1 Corinthians 15:20": {"t": "But now Christ has been raised from the dead. He became the first fruits of those who are asleep.", "tr": "World English Bible"}, "1 Corinthians 15:3-4": {"t": "For I delivered to you first of all that which I also received: that Christ died for our sins according to the Scriptures, that he was buried, that he was raised on the third day according to the Scriptures,", "tr": "World English Bible"}, "1 Corinthians 15:3-7": {"t": "For I delivered to you first of all that which I also received: that Christ died for our sins according to the Scriptures, that he was buried, that he was raised on the third day according to the Scriptures, and that he appeared to Cephas, then to the twelve. Then he appeared to over five hundred brothers at once, most of whom remain until now, but some have also fallen asleep. Then he appeared to James, then to all the apostles,", "tr": "World English Bible"}, "1 Corinthians 15:3-8": {"t": "For I delivered to you first of all that which I also received: that Christ died for our sins according to the Scriptures, that he was buried, that he was raised on the third day according to the Scriptures, and that he appeared to Cephas, then to the twelve. Then he appeared to over five hundred brothers at once, most of whom remain until now, but some have also fallen asleep. Then he appeared to James, then to all the apostles, and last of all, as to the child born at the wrong time, he appeared to me also.", "tr": "World English Bible"}, "1 Corinthians 16:21": {"t": "This greeting is by me, Paul, with my own hand.", "tr": "World English Bible"}, "1 Corinthians 4:4": {"t": "For I know nothing against myself. Yet I am not justified by this, but he who judges me is the Lord.", "tr": "World English Bible"}, "1 Corinthians 5:5": {"t": "are to deliver such a one to Satan for the destruction of the flesh, that the spirit may be saved in the day of the Lord Jesus.", "tr": "World English Bible"}, "1 Corinthians 5:7": {"t": "Purge out the old yeast, that you may be a new lump, even as you are unleavened. For indeed Christ, our Passover, has been sacrificed in our place.", "tr": "World English Bible"}, "1 Corinthians 6:9-11": {"t": "Or don’t you know that the unrighteous will not inherit the Kingdom of God? Don’t be deceived. Neither the sexually immoral, nor idolaters, nor adulterers, nor male prostitutes, nor homosexuals, nor thieves, nor covetous, nor drunkards, nor slanderers, nor extortionists, will inherit the Kingdom of God. Such were some of you, but you were washed. But you were sanctified. But you were justified in the name of the Lord Jesus, and in the Spirit of our God.", "tr": "World English Bible"}, "1 Corinthians 7:34": {"t": "There is also a difference between a wife and a virgin. The unmarried woman cares about the things of the Lord, that she may be holy both in body and in spirit. But she who is married cares about the things of the world—how she may please her husband.", "tr": "World English Bible"}, "1 Corinthians 8:6": {"t": "yet to us there is one God, the Father, of whom are all things, and we for him; and one Lord, Jesus Christ, through whom are all things, and we live through him.", "tr": "World English Bible"}, "1 John 1:1": {"t": "That which was from the beginning, that which we have heard, that which we have seen with our eyes, that which we saw, and our hands touched, concerning the Word of life", "tr": "World English Bible"}, "1 John 1:9": {"t": "If we confess our sins, he is faithful and righteous to forgive us the sins, and to cleanse us from all unrighteousness.", "tr": "World English Bible"}, "1 John 4:18": {"t": "There is no fear in love; but perfect love casts out fear, because fear has punishment. He who fears is not made perfect in love.", "tr": "World English Bible"}, "1 John 4:8": {"t": "He who doesn’t love doesn’t know God, for God is love.", "tr": "World English Bible"}, "1 John 5:13": {"t": "These things I have written to you who believe in the name of the Son of God, that you may know that you have eternal life, and that you may continue to believe in the name of the Son of God.", "tr": "World English Bible"}, "1 Kings 10:23-24": {"t": "So king Solomon exceeded all the kings of the earth in riches and in wisdom. All the earth sought the presence of Solomon, to hear his wisdom, which God had put in his heart.", "tr": "World English Bible"}, "1 Kings 11:11": {"t": "Therefore Yahweh said to Solomon, “Because this is done by you, and you have not kept my covenant and my statutes, which I have commanded you, I will surely tear the kingdom from you, and will give it to your servant.", "tr": "World English Bible"}, "1 Kings 11:31, 12:20": {"t": "He said to Jeroboam, “Take ten pieces; for thus says Yahweh, the God of Israel, ‘Behold, I will tear the kingdom out of the hand of Solomon, and will give ten tribes to you", "tr": "World English Bible"}, "1 Kings 11:4": {"t": "When Solomon was old, his wives turned away his heart after other gods; and his heart was not perfect with Yahweh his God, as was the heart of David his father.", "tr": "World English Bible"}, "1 Kings 11:9-13": {"t": "Yahweh was angry with Solomon, because his heart was turned away from Yahweh, the God of Israel, who had appeared to him twice, and had commanded him concerning this thing, that he should not go after other gods: but he didn’t keep that which Yahweh commanded. Therefore Yahweh said to Solomon, “Because this is done by you, and you have not kept my covenant and my statutes, which I have commanded you, I will surely tear the kingdom from you, and will give it to your servant. Notwithstanding I will not do it in your days, for David your father’s sake; but I will tear it out of the hand of your son. However I will not tear away all the kingdom; but I will give one tribe to your son, for David [the passage continues in your Bible]", "tr": "World English Bible"}, "1 Kings 12:13-16": {"t": "The king answered the people roughly, and abandoned the counsel of the old men which they had given him, and spoke to them according to the counsel of the young men, saying, “My father made your yoke heavy, but I will add to your yoke. My father chastised you with whips, but I will chastise you with scorpions.” So the king didn’t listen to the people; for it was a thing brought about of Yahweh, that he might establish his word, which Yahweh spoke by Ahijah the Shilonite to Jeroboam the son of Nebat. When all Israel saw that the king didn’t listen to them, the people answered the king, saying, “What portion have we in David? Neither do we have an inheritance in the son of Jesse. To your [the passage continues in your Bible]", "tr": "World English Bible"}, "1 Kings 12:16-20": {"t": "When all Israel saw that the king didn’t listen to them, the people answered the king, saying, “What portion have we in David? Neither do we have an inheritance in the son of Jesse. To your tents, Israel! Now see to your own house, David.” So Israel departed to their tents. But as for the children of Israel who lived in the cities of Judah, Rehoboam reigned over them. Then king Rehoboam sent Adoram, who was over the men subject to forced labor; and all Israel stoned him to death with stones. King Rehoboam made speed to get him up to his chariot, to flee to Jerusalem. So Israel rebelled against the house of David to this day. When all Israel heard that Jeroboam was returned, they sent and [the passage continues in your Bible]", "tr": "World English Bible"}, "1 Kings 12:21-24": {"t": "When Rehoboam had come to Jerusalem, he assembled all the house of Judah, and the tribe of Benjamin, a hundred and eighty thousand chosen men, who were warriors, to fight against the house of Israel, to bring the kingdom again to Rehoboam the son of Solomon. But the word of God came to Shemaiah the man of God, saying, “Speak to Rehoboam the son of Solomon, king of Judah, and to all the house of Judah and Benjamin, and to the rest of the people, saying, ‘Thus says Yahweh, “You shall not go up, nor fight against your brothers, the children of Israel. Everyone return to his house; for this thing is of me.”’” So they listened to Yahweh’s word, and returned and went their way, according to Yahweh’s word.", "tr": "World English Bible"}, "1 Kings 12:28-29": {"t": "Whereupon the king took counsel, and made two calves of gold; and he said to them, “It is too much for you to go up to Jerusalem. Look and see your gods, Israel, which brought you up out of the land of Egypt!” He set the one in Bethel, and the other put he in Dan.", "tr": "World English Bible"}, "1 Kings 12:28-30": {"t": "Whereupon the king took counsel, and made two calves of gold; and he said to them, “It is too much for you to go up to Jerusalem. Look and see your gods, Israel, which brought you up out of the land of Egypt!” He set the one in Bethel, and the other put he in Dan. This thing became a sin; for the people went to worship before the one, even to Dan.", "tr": "World English Bible"}, "1 Kings 12:31-32": {"t": "He made houses of high places, and made priests from among all the people, who were not of the sons of Levi. Jeroboam ordained a feast in the eighth month, on the fifteenth day of the month, like the feast that is in Judah, and he went up to the altar; he did so in Bethel, sacrificing to the calves that he had made: and he placed in Bethel the priests of the high places that he had made.", "tr": "World English Bible"}, "1 Kings 13:4": {"t": "When the king heard the saying of the man of God, which he cried against the altar in Bethel, Jeroboam put out his hand from the altar, saying, “Seize him!” His hand, which he put out against him, dried up, so that he could not draw it back again to himself.", "tr": "World English Bible"}, "1 Kings 14:16": {"t": "He will give Israel up because of the sins of Jeroboam, which he has sinned, and with which he has made Israel to sin.”", "tr": "World English Bible"}, "1 Kings 14:22-26": {"t": "Judah did that which was evil in the sight of Yahweh, and they provoked him to jealousy with their sins which they committed, above all that their fathers had done. For they also built them high places, and pillars, and Asherah poles, on every high hill, and under every green tree; and there were also sodomites in the land: they did according to all the abominations of the nations which Yahweh drove out before the children of Israel. In the fifth year of king Rehoboam, Shishak king of Egypt came up against Jerusalem; and he took away the treasures of Yahweh’s house, and the treasures of the king’s house; he even took away all: and he took away all the shields of gold which Solomon had made.", "tr": "World English Bible"}, "1 Kings 15:1-3": {"t": "Now in the eighteenth year of king Jeroboam the son of Nebat began Abijam to reign over Judah. He reigned three years in Jerusalem: and his mother’s name was Maacah the daughter of Abishalom. He walked in all the sins of his father, which he had done before him; and his heart was not perfect with Yahweh his God, as the heart of David his father.", "tr": "World English Bible"}, "1 Kings 15:11": {"t": "Asa did that which was right in the eyes of Yahweh, as did David his father.", "tr": "World English Bible"}, "1 Kings 15:16-17, 20": {"t": "There was war between Asa and Baasha king of Israel all their days. Baasha king of Israel went up against Judah, and built Ramah, that he might not allow anyone to go out or come in to Asa king of Judah.", "tr": "World English Bible"}, "1 Kings 15:25-26": {"t": "Nadab the son of Jeroboam began to reign over Israel in the second year of Asa king of Judah; and he reigned over Israel two years. He did that which was evil in the sight of Yahweh, and walked in the way of his father, and in his sin with which he made Israel to sin.", "tr": "World English Bible"}, "1 Kings 15:27-28": {"t": "Baasha the son of Ahijah, of the house of Issachar, conspired against him; and Baasha struck him at Gibbethon, which belonged to the Philistines; for Nadab and all Israel were laying siege to Gibbethon. Even in the third year of Asa king of Judah, Baasha killed him, and reigned in his place.", "tr": "World English Bible"}, "1 Kings 15:28, 33": {"t": "Even in the third year of Asa king of Judah, Baasha killed him, and reigned in his place.", "tr": "World English Bible"}, "1 Kings 15:29-30": {"t": "As soon as he was king, he struck all the house of Jeroboam. He didn’t leave to Jeroboam any who breathed, until he had destroyed him; according to the saying of Yahweh, which he spoke by his servant Ahijah the Shilonite; for the sins of Jeroboam which he sinned, and with which he made Israel to sin, because of his provocation with which he provoked Yahweh, the God of Israel, to anger.", "tr": "World English Bible"}, "1 Kings 15:34": {"t": "He did that which was evil in the sight of Yahweh, and walked in the way of Jeroboam, and in his sin with which he made Israel to sin.", "tr": "World English Bible"}, "1 Kings 15:4-5": {"t": "Nevertheless for David’s sake, Yahweh his God gave him a lamp in Jerusalem, to set up his son after him, and to establish Jerusalem; because David did that which was right in the eyes of Yahweh, and didn’t turn aside from anything that he commanded him all the days of his life, except only in the matter of Uriah the Hittite.", "tr": "World English Bible"}, "1 Kings 16:1-4": {"t": "Yahweh’s word came to Jehu the son of Hanani against Baasha, saying, “Because I exalted you out of the dust, and made you prince over my people Israel, and you have walked in the way of Jeroboam, and have made my people Israel to sin, to provoke me to anger with their sins; behold, I will utterly sweep away Baasha and his house; and I will make your house like the house of Jeroboam the son of Nebat. The dogs will eat Baasha’s descendants who die in the city; and he who dies of his in the field the birds of the sky will eat.”", "tr": "World English Bible"}, "1 Kings 16:11-12": {"t": "When he began to reign, as soon as he sat on his throne, he struck all the house of Baasha: he didn’t leave him a single one who urinates on a wall, neither of his relatives, nor of his friends. Thus Zimri destroyed all the house of Baasha, according to Yahweh’s word, which he spoke against Baasha by Jehu the prophet,", "tr": "World English Bible"}, "1 Kings 16:11-13": {"t": "When he began to reign, as soon as he sat on his throne, he struck all the house of Baasha: he didn’t leave him a single one who urinates on a wall, neither of his relatives, nor of his friends. Thus Zimri destroyed all the house of Baasha, according to Yahweh’s word, which he spoke against Baasha by Jehu the prophet, for all the sins of Baasha, and the sins of Elah his son, which they sinned, and with which they made Israel to sin, to provoke Yahweh, the God of Israel, to anger with their vanities.", "tr": "World English Bible"}, "1 Kings 16:15": {"t": "In the twenty-seventh year of Asa king of Judah, Zimri reigned seven days in Tirzah. Now the people were encamped against Gibbethon, which belonged to the Philistines.", "tr": "World English Bible"}, "1 Kings 16:16-17": {"t": "The people who were encamped heard say, Zimri has conspired, and has also struck the king: therefore all Israel made Omri, the captain of the army, king over Israel that day in the camp. Omri went up from Gibbethon, and all Israel with him, and they besieged Tirzah.", "tr": "World English Bible"}, "1 Kings 16:18-19": {"t": "When Zimri saw that the city was taken, he went into the castle of the king’s house, and burnt the king’s house over him with fire, and died, for his sins which he sinned in doing that which was evil in the sight of Yahweh, in walking in the way of Jeroboam, and in his sin which he did, to make Israel to sin.", "tr": "World English Bible"}, "1 Kings 16:21": {"t": "Then were the people of Israel divided into two parts: half of the people followed Tibni the son of Ginath, to make him king; and half followed Omri.", "tr": "World English Bible"}, "1 Kings 16:22": {"t": "But the people who followed Omri prevailed against the people who followed Tibni the son of Ginath: so Tibni died, and Omri reigned.", "tr": "World English Bible"}, "1 Kings 16:23": {"t": "In the thirty-first year of Asa king of Judah, Omri began to reign over Israel for twelve years. He reigned six years in Tirzah.", "tr": "World English Bible"}, "1 Kings 16:24": {"t": "He bought the hill Samaria of Shemer for two talents of silver; and he built on the hill, and called the name of the city which he built, after the name of Shemer, the owner of the hill, Samaria.", "tr": "World English Bible"}, "1 Kings 16:25": {"t": "Omri did that which was evil in the sight of Yahweh, and dealt wickedly above all who were before him.", "tr": "World English Bible"}, "1 Kings 16:26": {"t": "For he walked in all the way of Jeroboam the son of Nebat, and in his sins with which he made Israel to sin, to provoke Yahweh, the God of Israel, to anger with their vanities.", "tr": "World English Bible"}, "1 Kings 16:29-30": {"t": "In the thirty-eighth year of Asa king of Judah began Ahab the son of Omri to reign over Israel: and Ahab the son of Omri reigned over Israel in Samaria twenty-two years. Ahab the son of Omri did that which was evil in the sight of Yahweh above all that were before him.", "tr": "World English Bible"}, "1 Kings 16:31-32": {"t": "As if it had been a light thing for him to walk in the sins of Jeroboam the son of Nebat, he took as wife Jezebel the daughter of Ethbaal king of the Sidonians, and went and served Baal, and worshiped him. He reared up an altar for Baal in the house of Baal, which he had built in Samaria.", "tr": "World English Bible"}, "1 Kings 16:8": {"t": "In the twenty-sixth year of Asa king of Judah, Elah the son of Baasha began to reign over Israel in Tirzah for two years.", "tr": "World English Bible"}, "1 Kings 16:9": {"t": "His servant Zimri, captain of half his chariots, conspired against him. Now he was in Tirzah, drinking himself drunk in the house of Arza, who was over the household in Tirzah:", "tr": "World English Bible"}, "1 Kings 16:9-10": {"t": "His servant Zimri, captain of half his chariots, conspired against him. Now he was in Tirzah, drinking himself drunk in the house of Arza, who was over the household in Tirzah: and Zimri went in and struck him, and killed him, in the twenty-seventh year of Asa king of Judah, and reigned in his place.", "tr": "World English Bible"}, "1 Kings 17:1": {"t": "Elijah the Tishbite, who was of the foreigners of Gilead, said to Ahab, “As Yahweh, the God of Israel, lives, before whom I stand, there shall not be dew nor rain these years, but according to my word.”", "tr": "World English Bible"}, "1 Kings 18:21": {"t": "Elijah came near to all the people, and said, “How long will you waver between the two sides? If Yahweh is God, follow him; but if Baal, then follow him.” The people answered him not a word.", "tr": "World English Bible"}, "1 Kings 18:36-39": {"t": "At the time of the offering of the offering, Elijah the prophet came near, and said, “Yahweh, the God of Abraham, of Isaac, and of Israel, let it be known this day that you are God in Israel, and that I am your servant, and that I have done all these things at your word. Hear me, Yahweh, hear me, that this people may know that you, Yahweh, are God, and that you have turned their heart back again.” Then the fire of Yahweh fell, and consumed the burnt offering, and the wood, and the stones, and the dust, and licked up the water that was in the trench. When all the people saw it, they fell on their faces. They said, “Yahweh, he is God! Yahweh, he is God!”", "tr": "World English Bible"}, "1 Kings 18:38-39": {"t": "Then the fire of Yahweh fell, and consumed the burnt offering, and the wood, and the stones, and the dust, and licked up the water that was in the trench. When all the people saw it, they fell on their faces. They said, “Yahweh, he is God! Yahweh, he is God!”", "tr": "World English Bible"}, "1 Kings 19:11-13": {"t": "He said, “Go out, and stand on the mountain before Yahweh.” Behold, Yahweh passed by, and a great and strong wind tore the mountains, and broke in pieces the rocks before Yahweh; but Yahweh was not in the wind. After the wind an earthquake; but Yahweh was not in the earthquake. After the earthquake a fire passed; but Yahweh was not in the fire: and after the fire a still small voice. It was so, when Elijah heard it, that he wrapped his face in his mantle, and went out, and stood in the entrance of the cave. Behold, a voice came to him, and said, “What are you doing here, Elijah?”", "tr": "World English Bible"}, "1 Kings 1:39": {"t": "Zadok the priest took the horn of oil from the Tent, and anointed Solomon. They blew the trumpet; and all the people said, “Long live king Solomon!”", "tr": "World English Bible"}, "1 Kings 22:34-38": {"t": "A certain man drew his bow at random, and struck the king of Israel between the joints of the armor. Therefore he said to the driver of his chariot, “Turn your hand, and carry me out of the battle; for I am severely wounded.” The battle increased that day. The king was propped up in his chariot facing the Syrians, and died at evening. The blood ran out of the wound into the bottom of the chariot. A cry went throughout the army about the going down of the sun, saying, “Every man to his city, and every man to his country!” So the king died, and was brought to Samaria; and they buried the king in Samaria. They washed the chariot by the pool of Samaria; and the dogs licked up his blood where [the passage continues in your Bible]", "tr": "World English Bible"}, "1 Kings 22:42-43": {"t": "Jehoshaphat was thirty-five years old when he began to reign; and he reigned twenty-five years in Jerusalem. His mother’s name was Azubah the daughter of Shilhi. He walked in all the way of Asa his father; He didn’t turn aside from it, doing that which was right in the eyes of Yahweh: however the high places were not taken away; the people still sacrificed and burnt incense in the high places.", "tr": "World English Bible"}, "1 Kings 22:51-53": {"t": "Ahaziah the son of Ahab began to reign over Israel in Samaria in the seventeenth year of Jehoshaphat king of Judah, and he reigned two years over Israel. He did that which was evil in the sight of Yahweh, and walked in the way of his father, and in the way of his mother, and in the way of Jeroboam the son of Nebat, in which he made Israel to sin. He served Baal, and worshiped him, and provoked to anger Yahweh, the God of Israel, according to all that his father had done.", "tr": "World English Bible"}, "1 Kings 3:9-12": {"t": "Give your servant therefore an understanding heart to judge your people, that I may discern between good and evil; for who is able to judge this your great people?” The speech pleased the Lord, that Solomon had asked this thing. God said to him, “Because you have asked this thing, and have not asked for yourself long life, neither have asked riches for yourself, nor have asked the life of your enemies, but have asked for yourself understanding to discern justice; behold, I have done according to your word. Behold, I have given you a wise and an understanding heart; so that there has been no one like you before you, neither after you shall any arise like you.", "tr": "World English Bible"}, "1 Kings 3:9-13": {"t": "Give your servant therefore an understanding heart to judge your people, that I may discern between good and evil; for who is able to judge this your great people?” The speech pleased the Lord, that Solomon had asked this thing. God said to him, “Because you have asked this thing, and have not asked for yourself long life, neither have asked riches for yourself, nor have asked the life of your enemies, but have asked for yourself understanding to discern justice; behold, I have done according to your word. Behold, I have given you a wise and an understanding heart; so that there has been no one like you before you, neither after you shall any arise like you. I have also given you that which [the passage continues in your Bible]", "tr": "World English Bible"}, "1 Kings 6:1": {"t": "In the four hundred and eightieth year after the children of Israel had come out of the land of Egypt, in the fourth year of Solomon’s reign over Israel, in the month Ziv, which is the second month, he began to build Yahweh’s house.", "tr": "World English Bible"}, "1 Kings 6:11-14": {"t": "Yahweh’s word came to Solomon, saying, “Concerning this house which you are building, if you will walk in my statutes, and execute my ordinances, and keep all my commandments to walk in them; then I will establish my word with you, which I spoke to David your father. I will dwell among the children of Israel, and will not forsake my people Israel.” So Solomon built the house, and finished it.", "tr": "World English Bible"}, "1 Kings 8:10-11": {"t": "It came to pass, when the priests had come out of the holy place, that the cloud filled Yahweh’s house, so that the priests could not stand to minister by reason of the cloud; for Yahweh’s glory filled Yahweh’s house.", "tr": "World English Bible"}, "1 Kings 8:27": {"t": "But will God in very deed dwell on the earth? Behold, heaven and the heaven of heavens can’t contain you; how much less this house that I have built!", "tr": "World English Bible"}, "1 Peter 2:9": {"t": "But you are a chosen race, a royal priesthood, a holy nation, a people for God’s own possession, that you may proclaim the excellence of him who called you out of darkness into his marvelous light:", "tr": "World English Bible"}, "1 Peter 3:15": {"t": "But sanctify the Lord God in your hearts; and always be ready to give an answer to everyone who asks you a reason concerning the hope that is in you, with humility and fear:", "tr": "World English Bible"}, "1 Peter 4:16": {"t": "But if one of you suffers for being a Christian, let him not be ashamed; but let him glorify God in this matter.", "tr": "World English Bible"}, "1 Peter 5:7": {"t": "casting all your worries on him, because he cares for you.", "tr": "World English Bible"}, "1 Samuel 10:1": {"t": "Then Samuel took the vial of oil, and poured it on his head, and kissed him, and said, “Isn’t it that Yahweh has anointed you to be prince over his inheritance?", "tr": "World English Bible"}, "1 Samuel 11:11": {"t": "On the next day, Saul put the people in three companies; and they came into the midst of the camp in the morning watch, and struck the Ammonites until the heat of the day. Those who remained were scattered, so that no two of them were left together.", "tr": "World English Bible"}, "1 Samuel 13:13-14": {"t": "Samuel said to Saul, “You have done foolishly. You have not kept the commandment of Yahweh your God, which he commanded you; for now Yahweh would have established your kingdom on Israel forever. But now your kingdom shall not continue. Yahweh has sought for himself a man after his own heart, and Yahweh has appointed him to be prince over his people, because you have not kept that which Yahweh commanded you.”", "tr": "World English Bible"}, "1 Samuel 15:22": {"t": "Samuel said, “Has Yahweh as great delight in burnt offerings and sacrifices, as in obeying the voice of Yahweh? Behold, to obey is better than sacrifice, and to listen than the fat of rams.", "tr": "World English Bible"}, "1 Samuel 15:22-23": {"t": "Samuel said, “Has Yahweh as great delight in burnt offerings and sacrifices, as in obeying the voice of Yahweh? Behold, to obey is better than sacrifice, and to listen than the fat of rams. For rebellion is as the sin of witchcraft, and stubbornness is as idolatry and teraphim. Because you have rejected Yahweh’s word, he has also rejected you from being king.”", "tr": "World English Bible"}, "1 Samuel 15:26": {"t": "Samuel said to Saul, “I will not return with you; for you have rejected Yahweh’s word, and Yahweh has rejected you from being king over Israel.”", "tr": "World English Bible"}, "1 Samuel 16:13": {"t": "Then Samuel took the horn of oil, and anointed him in the midst of his brothers: and the Spirit of Yahweh came mightily on David from that day forward. So Samuel rose up, and went to Ramah.", "tr": "World English Bible"}, "1 Samuel 16:7": {"t": "But Yahweh said to Samuel, “Don’t look on his face, or on the height of his stature; because I have rejected him: for I see not as man sees; for man looks at the outward appearance, but Yahweh looks at the heart.”", "tr": "World English Bible"}, "1 Samuel 31:4-6": {"t": "Then Saul said to his armor bearer, “Draw your sword, and thrust me through with it, lest these uncircumcised come and thrust me through, and abuse me!” But his armor bearer would not; for he was terrified. Therefore Saul took his sword, and fell on it. When his armor bearer saw that Saul was dead, he likewise fell on his sword, and died with him. So Saul died, and his three sons, and his armor bearer, and all his men, that same day together.", "tr": "World English Bible"}, "1 Samuel 8:5": {"t": "and they said to him, “Behold, you are old, and your sons don’t walk in your ways: now make us a king to judge us like all the nations.”", "tr": "World English Bible"}, "1 Samuel 8:7": {"t": "Yahweh said to Samuel, “Listen to the voice of the people in all that they tell you; for they have not rejected you, but they have rejected me, that I should not be king over them.", "tr": "World English Bible"}, "1 Samuel 9:15-17": {"t": "Now Yahweh had revealed to Samuel a day before Saul came, saying, “Tomorrow about this time I will send you a man out of the land of Benjamin, and you shall anoint him to be prince over my people Israel; and he shall save my people out of the hand of the Philistines: for I have looked on my people, because their cry has come to me.” When Samuel saw Saul, Yahweh said to him, “Behold, the man of whom I spoke to you! this same shall have authority over my people.”", "tr": "World English Bible"}, "1 Thessalonians 4:16-17": {"t": "For the Lord himself will descend from heaven with a shout, with the voice of the archangel, and with God’s trumpet. The dead in Christ will rise first, then we who are alive, who are left, will be caught up together with them in the clouds, to meet the Lord in the air. So we will be with the Lord forever.", "tr": "World English Bible"}, "1 Thessalonians 5:11": {"t": "Therefore exhort one another, and build each other up, even as you also do.", "tr": "World English Bible"}, "1 Timothy 2:12": {"t": "But I don’t permit a woman to teach, nor to exercise authority over a man, but to be in quietness.", "tr": "World English Bible"}, "1 Timothy 2:4": {"t": "who desires all people to be saved and come to full knowledge of the truth.", "tr": "World English Bible"}, "1 Timothy 3:11": {"t": "Their wives in the same way must be reverent, not slanderers, temperate, faithful in all things.", "tr": "World English Bible"}, "1 Timothy 3:16": {"t": "Without controversy, the mystery of godliness is great: God was revealed in the flesh, justified in the spirit, seen by angels, preached among the nations, believed on in the world, and received up in glory.", "tr": "World English Bible"}, "1 Timothy 5:18": {"t": "For the Scripture says, “You shall not muzzle the ox when it treads out the grain.” And, “The laborer is worthy of his wages.”", "tr": "World English Bible"}, "1 Timothy 5:3-10": {"t": "Honor widows who are widows indeed. But if any widow has children or grandchildren, let them learn first to show piety towards their own family, and to repay their parents, for this is acceptable in the sight of God. Now she who is a widow indeed, and desolate, has her hope set on God, and continues in petitions and prayers night and day. But she who gives herself to pleasure is dead while she lives. Also command these things, that they may be without reproach. But if anyone doesn’t provide for his own, and especially his own household, he has denied the faith, and is worse than an unbeliever. Let no one be enrolled as a widow under sixty years old, having been the wife of one man, being [the passage continues in your Bible]", "tr": "World English Bible"}, "1 Timothy 5:9-10,14": {"t": "Let no one be enrolled as a widow under sixty years old, having been the wife of one man, being approved by good works, if she has brought up children, if she has been hospitable to strangers, if she has washed the saints’ feet, if she has relieved the afflicted, and if she has diligently followed every good work.", "tr": "World English Bible"}, "1 Timothy 6:10": {"t": "For the love of money is a root of all kinds of evil. Some have been led astray from the faith in their greed, and have pierced themselves through with many sorrows.", "tr": "World English Bible"}, "2 Chronicles 12:6-7": {"t": "Then the princes of Israel and the king humbled themselves; and they said, “Yahweh is righteous.” When Yahweh saw that they humbled themselves, Yahweh’s word came to Shemaiah, saying, “They have humbled themselves. I will not destroy them; but I will grant them some deliverance, and my wrath shall not be poured out on Jerusalem by the hand of Shishak.", "tr": "World English Bible"}, "2 Chronicles 13:15-18": {"t": "Then the men of Judah gave a shout. As the men of Judah shouted, God struck Jeroboam and all Israel before Abijah and Judah. The children of Israel fled before Judah; and God delivered them into their hand. Abijah and his people killed them with a great slaughter: so there fell down slain of Israel five hundred thousand chosen men. Thus the children of Israel were brought under at that time, and the children of Judah prevailed, because they relied on Yahweh, the God of their fathers.", "tr": "World English Bible"}, "2 Chronicles 13:8-12": {"t": "“Now you think to withstand the kingdom of Yahweh in the hand of the sons of David; and you are a great multitude, and there are with you the golden calves which Jeroboam made you for gods. Haven’t you driven out the priests of Yahweh, the sons of Aaron, and the Levites, and made priests for yourselves after the ways of the peoples of other lands? so that whoever comes to consecrate himself with a young bull and seven rams, the same may be a priest of those who are no gods. “But as for us, Yahweh is our God, and we have not forsaken him; and we have priests ministering to Yahweh, the sons of Aaron, and the Levites in their work: and they burn to Yahweh every morning and every evening burnt [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Chronicles 14:11-12": {"t": "Asa cried to Yahweh his God, and said, “Yahweh, there is no one besides you to help, between the mighty and him who has no strength. Help us, Yahweh our God; for we rely on you, and in your name are we come against this multitude. Yahweh, you are our God. Don’t let man prevail against you.” So Yahweh struck the Ethiopians before Asa, and before Judah; and the Ethiopians fled.", "tr": "World English Bible"}, "2 Chronicles 15:8-12": {"t": "When Asa heard these words, and the prophecy of Oded the prophet, he took courage, and put away the abominations out of all the land of Judah and Benjamin, and out of the cities which he had taken from the hill country of Ephraim; and he renewed the altar of Yahweh, that was before the porch of Yahweh. He gathered all Judah and Benjamin, and those who lived with them out of Ephraim and Manasseh, and out of Simeon: for they fell to him out of Israel in abundance, when they saw that Yahweh his God was with him. So they gathered themselves together at Jerusalem in the third month, in the fifteenth year of the reign of Asa. They sacrificed to Yahweh in that day, of the plunder which they had [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Chronicles 16:7-9": {"t": "At that time Hanani the seer came to Asa king of Judah, and said to him, “Because you have relied on the king of Syria, and have not relied on Yahweh your God, therefore is the army of the king of Syria escaped out of your hand. Weren’t the Ethiopians and the Lubim a huge army, with chariots and horsemen exceeding many? Yet, because you relied on Yahweh, he delivered them into your hand. For the eyes of Yahweh run back and forth throughout the whole earth, to show himself strong in the behalf of them whose heart is perfect toward him. Herein you have done foolishly; for from henceforth you shall have wars.”", "tr": "World English Bible"}, "2 Chronicles 17:7-9": {"t": "Also in the third year of his reign he sent his princes, even Ben Hail, and Obadiah, and Zechariah, and Nethanel, and Micaiah, to teach in the cities of Judah; and with them the Levites, even Shemaiah, and Nethaniah, and Zebadiah, and Asahel, and Shemiramoth, and Jehonathan, and Adonijah, and Tobijah, and Tobadonijah, the Levites; and with them Elishama and Jehoram, the priests. They taught in Judah, having the book of Yahweh’s law with them; and they went about throughout all the cities of Judah, and taught among the people.", "tr": "World English Bible"}, "2 Chronicles 18:1": {"t": "Now Jehoshaphat had riches and honor in abundance; and he joined affinity with Ahab.", "tr": "World English Bible"}, "2 Chronicles 20:21-22": {"t": "When he had taken counsel with the people, he appointed those who should sing to Yahweh, and give praise in holy array, as they went out before the army, and say, Give thanks to Yahweh; for his loving kindness endures forever. When they began to sing and to praise, Yahweh set ambushers against the children of Ammon, Moab, and Mount Seir, who had come against Judah; and they were struck.", "tr": "World English Bible"}, "2 Chronicles 20:3": {"t": "Jehoshaphat was alarmed, and set himself to seek to Yahweh. He proclaimed a fast throughout all Judah.", "tr": "World English Bible"}, "2 Chronicles 21:12-15": {"t": "A letter came to him from Elijah the prophet, saying, “Thus says Yahweh, the God of David your father, ‘Because you have not walked in the ways of Jehoshaphat your father, nor in the ways of Asa king of Judah, but have walked in the way of the kings of Israel, and have made Judah and the inhabitants of Jerusalem to play the prostitute, like the house of Ahab did, and also have slain your brothers of your father’s house, who were better than yourself: behold, Yahweh will strike with a great plague your people, and your children, and your wives, and all your substance; and you shall have great sickness by disease of your bowels, until your bowels fall out by reason of the sickness, day by day.’”", "tr": "World English Bible"}, "2 Chronicles 21:18-20": {"t": "After all this Yahweh struck him in his bowels with an incurable disease. In process of time, at the end of two years, his bowels fell out by reason of his sickness, and he died of severe diseases. His people made no burning for him, like the burning of his fathers. Thirty-two years old was he when he began to reign, and he reigned in Jerusalem eight years: and he departed without being desired; and they buried him in the city of David, but not in the tombs of the kings.", "tr": "World English Bible"}, "2 Chronicles 21:4": {"t": "Now when Jehoram was risen up over the kingdom of his father, and had strengthened himself, he killed all his brothers with the sword, and various also of the princes of Israel.", "tr": "World English Bible"}, "2 Chronicles 21:5-6": {"t": "Jehoram was thirty-two years old when he began to reign; and he reigned eight years in Jerusalem. He walked in the way of the kings of Israel, as did the house of Ahab; for he had the daughter of Ahab as wife: and he did that which was evil in the sight of Yahweh.", "tr": "World English Bible"}, "2 Chronicles 22:10": {"t": "Now when Athaliah the mother of Ahaziah saw that her son was dead, she arose and destroyed all the royal seed of the house of Judah.", "tr": "World English Bible"}, "2 Chronicles 22:2-4": {"t": "Forty-two years old was Ahaziah when he began to reign; and he reigned one year in Jerusalem: and his mother’s name was Athaliah the daughter of Omri. He also walked in the ways of the house of Ahab; for his mother was his counselor to do wickedly. He did that which was evil in the sight of Yahweh, as did the house of Ahab; for they were his counselors after the death of his father, to his destruction.", "tr": "World English Bible"}, "2 Chronicles 22:7-9": {"t": "Now the destruction of Ahaziah was of God, in that he went to Joram: for when he had come, he went out with Jehoram against Jehu the son of Nimshi, whom Yahweh had anointed to cut off the house of Ahab. When Jehu was executing judgment on the house of Ahab, he found the princes of Judah, and the sons of the brothers of Ahaziah, serving Ahaziah, and killed them. He sought Ahaziah, and they caught him (now he was hiding in Samaria), and they brought him to Jehu, and killed him; and they buried him, for they said, “He is the son of Jehoshaphat, who sought Yahweh with all his heart.” The house of Ahaziah had no power to hold the kingdom.", "tr": "World English Bible"}, "2 Chronicles 24:17-22": {"t": "Now after the death of Jehoiada came the princes of Judah, and made obeisance to the king. Then the king listened to them. They abandoned the house of Yahweh, the God of their fathers, and served the Asherah poles and the idols; and wrath came on Judah and Jerusalem for this their guiltiness. Yet he sent prophets to them, to bring them again to Yahweh; and they testified against them: but they would not give ear. The Spirit of God came on Zechariah the son of Jehoiada the priest; and he stood above the people, and said to them, “Thus says God, ‘Why do you disobey the commandments of Yahweh, so that you can’t prosper? Because you have forsaken Yahweh, he has also forsaken you.’” They [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Chronicles 24:23-25": {"t": "At the end of the year, the army of the Syrians came up against him: and they came to Judah and Jerusalem, and destroyed all the princes of the people from among the people, and sent all their plunder to the king of Damascus. For the army of the Syrians came with a small company of men; and Yahweh delivered a very great army into their hand, because they had forsaken Yahweh, the God of their fathers. So they executed judgment on Joash. When they were departed for him (for they left him very sick), his own servants conspired against him for the blood of the sons of Jehoiada the priest, and killed him on his bed, and he died; and they buried him in the city of David, but they didn’t bury him [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Chronicles 25:14-15": {"t": "Now after Amaziah had come from the slaughter of the Edomites, he brought the gods of the children of Seir, and set them up to be his gods, and bowed down himself before them, and burned incense to them. Therefore Yahweh’s anger was kindled against Amaziah, and he sent to him a prophet, who said to him, “Why have you sought after the gods of the people, which have not delivered their own people out of your hand?”", "tr": "World English Bible"}, "2 Chronicles 25:20-24": {"t": "But Amaziah would not listen; for it was of God, that he might deliver them into the hand of their enemies, because they had sought after the gods of Edom. So Joash king of Israel went up; and he and Amaziah king of Judah looked one another in the face at Beth Shemesh, which belongs to Judah. Judah was defeated by Israel; and they fled every man to his tent. Joash king of Israel took Amaziah king of Judah, the son of Joash the son of Jehoahaz, at Beth Shemesh, and brought him to Jerusalem, and broke down the wall of Jerusalem from the gate of Ephraim to the corner gate, four hundred cubits. He took all the gold and silver, and all the vessels that were found in God’s house with Obed-Edom, [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Chronicles 25:27": {"t": "Now from the time that Amaziah turned away from following Yahweh, they made a conspiracy against him in Jerusalem. He fled to Lachish; but they sent after him to Lachish, and killed him there.", "tr": "World English Bible"}, "2 Chronicles 26:16-21": {"t": "But when he was strong, his heart was lifted up, so that he did corruptly, and he trespassed against Yahweh his God; for he went into Yahweh’s temple to burn incense on the altar of incense. Azariah the priest went in after him, and with him eighty priests of Yahweh, who were valiant men: and they resisted Uzziah the king, and said to him, “It isn’t for you, Uzziah, to burn incense to Yahweh, but for the priests the sons of Aaron, who are consecrated to burn incense. Go out of the sanctuary; for you have trespassed; neither shall it be for your honor from Yahweh God.” Then Uzziah was angry; and he had a censer in his hand to burn incense; and while he was angry with the priests, the leprosy [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Chronicles 26:3-5": {"t": "Sixteen years old was Uzziah when he began to reign; and he reigned fifty-two years in Jerusalem: and his mother’s name was Jechiliah, of Jerusalem. He did that which was right in the eyes of Yahweh, according to all that his father Amaziah had done. He set himself to seek God in the days of Zechariah, who had understanding in the vision of God: and as long as he sought Yahweh, God made him to prosper.", "tr": "World English Bible"}, "2 Chronicles 26:8": {"t": "The Ammonites gave tribute to Uzziah: and his name spread abroad even to the entrance of Egypt; for he grew exceeding strong.", "tr": "World English Bible"}, "2 Chronicles 27:3-5": {"t": "He built the upper gate of Yahweh’s house, and on the wall of Ophel he built much. Moreover he built cities in the hill country of Judah, and in the forests he built castles and towers. He fought also with the king of the children of Ammon, and prevailed against them. The children of Ammon gave him the same year one hundred talents of silver, and ten thousand measures of wheat, and ten thousand of barley. The children of Ammon gave that much to him in the second year also, and in the third.", "tr": "World English Bible"}, "2 Chronicles 27:6": {"t": "So Jotham became mighty, because he ordered his ways before Yahweh his God.", "tr": "World English Bible"}, "2 Chronicles 29:3": {"t": "He in the first year of his reign, in the first month, opened the doors of Yahweh’s house, and repaired them.", "tr": "World English Bible"}, "2 Chronicles 30:26": {"t": "So there was great joy in Jerusalem; for since the time of Solomon the son of David king of Israel there was not the like in Jerusalem.", "tr": "World English Bible"}, "2 Chronicles 33:12-13": {"t": "When he was in distress, he begged Yahweh his God, and humbled himself greatly before the God of his fathers. He prayed to him; and he was entreated by him, and heard his supplication, and brought him again to Jerusalem into his kingdom. Then Manasseh knew that Yahweh was God.", "tr": "World English Bible"}, "2 Chronicles 33:22-23": {"t": "He did that which was evil in the sight of Yahweh, as did Manasseh his father; and Amon sacrificed to all the engraved images which Manasseh his father had made, and served them. He didn’t humble himself before Yahweh, as Manasseh his father had humbled himself; but this same Amon trespassed more and more.", "tr": "World English Bible"}, "2 Chronicles 36:22-23": {"t": "Now in the first year of Cyrus king of Persia, that Yahweh’s word by the mouth of Jeremiah might be accomplished, Yahweh stirred up the spirit of Cyrus king of Persia, so that he made a proclamation throughout all his kingdom, and put it also in writing, saying, “Thus says Cyrus king of Persia, ‘Yahweh, the God of heaven, has given all the kingdoms of the earth to me; and he has commanded me to build him a house in Jerusalem, which is in Judah. Whoever there is among you of all his people, Yahweh his God be with him, and let him go up.’”", "tr": "World English Bible"}, "2 Chronicles 36:23": {"t": "“Thus says Cyrus king of Persia, ‘Yahweh, the God of heaven, has given all the kingdoms of the earth to me; and he has commanded me to build him a house in Jerusalem, which is in Judah. Whoever there is among you of all his people, Yahweh his God be with him, and let him go up.’”", "tr": "World English Bible"}, "2 Chronicles 7:14": {"t": "if my people, who are called by my name, shall humble themselves, and pray, and seek my face, and turn from their wicked ways; then I will hear from heaven, and will forgive their sin, and will heal their land.", "tr": "World English Bible"}, "2 Corinthians 12:8-9": {"t": "Concerning this thing, I begged the Lord three times that it might depart from me. He has said to me, “My grace is sufficient for you, for my power is made perfect in weakness.” Most gladly therefore I will rather glory in my weaknesses, that the power of Christ may rest on me.", "tr": "World English Bible"}, "2 Corinthians 12:9": {"t": "He has said to me, “My grace is sufficient for you, for my power is made perfect in weakness.” Most gladly therefore I will rather glory in my weaknesses, that the power of Christ may rest on me.", "tr": "World English Bible"}, "2 Corinthians 5:17": {"t": "Therefore if anyone is in Christ, he is a new creation. The old things have passed away. Behold, all things have become new.", "tr": "World English Bible"}, "2 Corinthians 5:21": {"t": "For him who knew no sin he made to be sin on our behalf; so that in him we might become the righteousness of God.", "tr": "World English Bible"}, "2 Corinthians 7:14": {"t": "For if in anything I have boasted to him on your behalf, I was not disappointed. But as we spoke all things to you in truth, so our glorying also which I made before Titus was found to be truth.", "tr": "World English Bible"}, "2 John 1:6": {"t": "This is love, that we should walk according to his commandments. This is the commandment, even as you heard from the beginning, that you should walk in it.", "tr": "World English Bible"}, "2 John 1:9": {"t": "Whoever transgresses and doesn’t remain in the teaching of Christ, doesn’t have God. He who remains in the teaching, the same has both the Father and the Son.", "tr": "World English Bible"}, "2 Kings 10:25-28": {"t": "As soon as he had made an end of offering the burnt offering, Jehu said to the guard and to the captains, “Go in, and kill them! Let no one escape.” They struck them with the edge of the sword; and the guard and the captains cast them out, and went to the city of the house of Baal. They brought out the pillars that were in the house of Baal, and burned them. They broke down the pillar of Baal, and broke down the house of Baal, and made it a latrine, to this day. Thus Jehu destroyed Baal out of Israel.", "tr": "World English Bible"}, "2 Kings 10:30-31": {"t": "Yahweh said to Jehu, “Because you have done well in executing that which is right in my eyes, and have done to the house of Ahab according to all that was in my heart, your sons of the fourth generation shall sit on the throne of Israel.” But Jehu took no heed to walk in the law of Yahweh, the God of Israel, with all his heart. He didn’t depart from the sins of Jeroboam, with which he made Israel to sin.", "tr": "World English Bible"}, "2 Kings 11:1": {"t": "Now when Athaliah the mother of Ahaziah saw that her son was dead, she arose and destroyed all the seed royal.", "tr": "World English Bible"}, "2 Kings 11:13-16": {"t": "When Athaliah heard the noise of the guard and of the people, she came to the people into Yahweh’s house: and she looked, and behold, the king stood by the pillar, as the tradition was, and the captains and the trumpets by the king; and all the people of the land rejoiced, and blew trumpets. Then Athaliah tore her clothes, and cried, “Treason! Treason!” Jehoiada the priest commanded the captains of hundreds who were set over the army, and said to them, “Bring her out between the ranks. Kill him who follows her with the sword.” For the priest said, “Don’t let her be slain in Yahweh’s house.” So they made way for her; and she went by the way of the horses’ entry to the king’s house. She was slain there.", "tr": "World English Bible"}, "2 Kings 11:2-3": {"t": "But Jehosheba, the daughter of king Joram, sister of Ahaziah, took Joash the son of Ahaziah, and stole him away from among the king’s sons who were slain, even him and his nurse, and put them in the bedroom; and they hid him from Athaliah, so that he was not slain; He was with her hidden in Yahweh’s house six years. Athaliah reigned over the land.", "tr": "World English Bible"}, "2 Kings 11:21": {"t": "Jehoash was seven years old when he began to reign.", "tr": "World English Bible"}, "2 Kings 12:2": {"t": "Jehoash did that which was right in the eyes of Yahweh all his days in which Jehoiada the priest instructed him.", "tr": "World English Bible"}, "2 Kings 12:4-5": {"t": "Jehoash said to the priests, “All the money of the holy things that is brought into Yahweh’s house, in current money, the money of the persons for whom each man is rated, and all the money that it comes into any man’s heart to bring into Yahweh’s house, let the priests take it to them, every man from his acquaintance; and they shall repair the breaches of the house, wherever any breach shall be found.”", "tr": "World English Bible"}, "2 Kings 13:1": {"t": "In the twenty-third year of Joash the son of Ahaziah, king of Judah, Jehoahaz the son of Jehu began to reign over Israel in Samaria for seventeen years.", "tr": "World English Bible"}, "2 Kings 13:10-11": {"t": "In the thirty-seventh year of Joash king of Judah, Jehoash the son of Jehoahaz began to reign over Israel in Samaria for sixteen years. He did that which was evil in the sight of Yahweh; he didn’t depart from all the sins of Jeroboam the son of Nebat, with which he made Israel to sin; but he walked therein.", "tr": "World English Bible"}, "2 Kings 13:14-19": {"t": "Now Elisha was fallen sick of his sickness of which he died: and Joash the king of Israel came down to him, and wept over him, and said, “My father, my father, the chariots of Israel and its horsemen!” Elisha said to him, “Take bow and arrows”; and he took to him bow and arrows. He said to the king of Israel, “Put your hand on the bow”; and he put his hand on it. Elisha laid his hands on the king’s hands. He said, “Open the window eastward”; and he opened it. Then Elisha said, “Shoot!” and he shot. He said, “Yahweh’s arrow of victory, even the arrow of victory over Syria; for you shall strike the Syrians in Aphek, until you have consumed them.” He said, “Take the arrows”; and he took them. [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Kings 13:2-3": {"t": "He did that which was evil in the sight of Yahweh, and followed the sins of Jeroboam the son of Nebat, with which he made Israel to sin; he didn’t depart from it. Yahweh’s anger was kindled against Israel, and he delivered them into the hand of Hazael king of Syria, and into the hand of Benhadad the son of Hazael, continually.", "tr": "World English Bible"}, "2 Kings 13:21": {"t": "As they were burying a man, behold, they saw a band of raiders; and they threw the man into Elisha’s tomb. As soon as the man touched the bones of Elisha, he revived, and stood up on his feet.", "tr": "World English Bible"}, "2 Kings 13:25": {"t": "Jehoash the son of Jehoahaz took again out of the hand of Benhadad the son of Hazael the cities which he had taken out of the hand of Jehoahaz his father by war. Joash struck him three times, and recovered the cities of Israel.", "tr": "World English Bible"}, "2 Kings 13:4-5": {"t": "Jehoahaz begged Yahweh, and Yahweh listened to him; for he saw the oppression of Israel, how that the king of Syria oppressed them. (Yahweh gave Israel a savior, so that they went out from under the hand of the Syrians; and the children of Israel lived in their tents as before.", "tr": "World English Bible"}, "2 Kings 13:7": {"t": "For he didn’t leave to Jehoahaz of the people any more than fifty horsemen, and ten chariots, and ten thousand footmen; for the king of Syria destroyed them, and made them like the dust in threshing.", "tr": "World English Bible"}, "2 Kings 14:11-14": {"t": "But Amaziah would not listen. So Jehoash king of Israel went up; and he and Amaziah king of Judah looked one another in the face at Beth Shemesh, which belongs to Judah. Judah was defeated by Israel; and they fled every man to his tent. Jehoash king of Israel took Amaziah king of Judah, the son of Jehoash the son of Ahaziah, at Beth Shemesh, and came to Jerusalem, and broke down the wall of Jerusalem from the gate of Ephraim to the corner gate, four hundred cubits. He took all the gold and silver, and all the vessels that were found in Yahweh’s house, and in the treasures of the king’s house, the hostages also, and returned to Samaria.", "tr": "World English Bible"}, "2 Kings 14:23": {"t": "In the fifteenth year of Amaziah the son of Joash king of Judah, Jeroboam the son of Joash king of Israel began to reign in Samaria for forty-one years.", "tr": "World English Bible"}, "2 Kings 14:25": {"t": "He restored the border of Israel from the entrance of Hamath to the sea of the Arabah, according to Yahweh’s word, the God of Israel, which he spoke by his servant Jonah the son of Amittai, the prophet, who was of Gath Hepher.", "tr": "World English Bible"}, "2 Kings 14:25-27": {"t": "He restored the border of Israel from the entrance of Hamath to the sea of the Arabah, according to Yahweh’s word, the God of Israel, which he spoke by his servant Jonah the son of Amittai, the prophet, who was of Gath Hepher. For Yahweh saw the affliction of Israel, that it was very bitter; for there was no one shut up nor left at large, neither was there any helper for Israel. Yahweh didn’t say that he would blot out the name of Israel from under the sky; but he saved them by the hand of Jeroboam the son of Joash.", "tr": "World English Bible"}, "2 Kings 14:3-4": {"t": "He did that which was right in the eyes of Yahweh, yet not like David his father: he did according to all that Joash his father had done. However the high places were not taken away: the people still sacrificed and burnt incense in the high places.", "tr": "World English Bible"}, "2 Kings 14:5-6": {"t": "As soon as the kingdom was established in his hand, he killed his servants who had slain the king his father: but the children of the murderers he didn’t put to death; according to that which is written in the book of the law of Moses, as Yahweh commanded, saying, “The fathers shall not be put to death for the children, nor the children be put to death for the fathers; but every man shall die for his own sin.”", "tr": "World English Bible"}, "2 Kings 15:12": {"t": "This was Yahweh’s word which he spoke to Jehu, saying, “Your sons to the fourth generation shall sit on the throne of Israel.” So it came to pass.", "tr": "World English Bible"}, "2 Kings 15:13": {"t": "Shallum the son of Jabesh began to reign in the thirty-ninth year of Uzziah king of Judah; and he reigned for a month in Samaria.", "tr": "World English Bible"}, "2 Kings 15:14": {"t": "Menahem the son of Gadi went up from Tirzah, and came to Samaria, and struck Shallum the son of Jabesh in Samaria, and killed him, and reigned in his place.", "tr": "World English Bible"}, "2 Kings 15:16-17": {"t": "Then Menahem struck Tiphsah, and all who were therein, and its borders, from Tirzah: because they didn’t open to him, therefore he struck it; and all the women therein who were with child he ripped up. In the nine and thirtieth year of Azariah king of Judah, Menahem the son of Gadi began to reign over Israel for ten years in Samaria.", "tr": "World English Bible"}, "2 Kings 15:19-20": {"t": "There came against the land Pul the king of Assyria; and Menahem gave Pul one thousand talents of silver, that his hand might be with him to confirm the kingdom in his hand. Menahem exacted the money of Israel, even of all the mighty men of wealth, of each man fifty shekels of silver, to give to the king of Assyria. So the king of Assyria turned back, and didn’t stay there in the land.", "tr": "World English Bible"}, "2 Kings 15:23-24": {"t": "In the fiftieth year of Azariah king of Judah Pekahiah the son of Menahem began to reign over Israel in Samaria for two years. He did that which was evil in the sight of Yahweh: he didn’t depart from the sins of Jeroboam the son of Nebat, with which he made Israel to sin.", "tr": "World English Bible"}, "2 Kings 15:25": {"t": "Pekah the son of Remaliah, his captain, conspired against him, and struck him in Samaria, in the castle of the king’s house, with Argob and Arieh; and with him were fifty men of the Gileadites: and he killed him, and reigned in his place.", "tr": "World English Bible"}, "2 Kings 15:27": {"t": "In the two and fiftieth year of Azariah king of Judah Pekah the son of Remaliah began to reign over Israel in Samaria for twenty years.", "tr": "World English Bible"}, "2 Kings 15:29": {"t": "In the days of Pekah king of Israel came Tiglath Pileser king of Assyria, and took Ijon, and Abel Beth Maacah, and Janoah, and Kedesh, and Hazor, and Gilead, and Galilee, all the land of Naphtali; and he carried them captive to Assyria.", "tr": "World English Bible"}, "2 Kings 15:30": {"t": "Hoshea the son of Elah made a conspiracy against Pekah the son of Remaliah, and struck him, and killed him, and reigned in his place, in the twentieth year of Jotham the son of Uzziah.", "tr": "World English Bible"}, "2 Kings 15:32-34": {"t": "In the second year of Pekah the son of Remaliah king of Israel began Jotham the son of Uzziah king of Judah to reign. He was twenty-five years old when he began to reign; and he reigned sixteen years in Jerusalem: and his mother’s name was Jerusha the daughter of Zadok. He did that which was right in the eyes of Yahweh; he did according to all that his father Uzziah had done.", "tr": "World English Bible"}, "2 Kings 15:35-37": {"t": "However the high places were not taken away: the people still sacrificed and burned incense in the high places. He built the upper gate of Yahweh’s house. Now the rest of the acts of Jotham, and all that he did, aren’t they written in the book of the chronicles of the kings of Judah? In those days Yahweh began to send against Judah Rezin the king of Syria, and Pekah the son of Remaliah.", "tr": "World English Bible"}, "2 Kings 15:8-10": {"t": "In the thirty-eighth year of Azariah king of Judah, Zechariah the son of Jeroboam reigned over Israel in Samaria six months. He did that which was evil in the sight of Yahweh, as his fathers had done: he didn’t depart from the sins of Jeroboam the son of Nebat, with which he made Israel to sin. Shallum the son of Jabesh conspired against him, and struck him before the people, and killed him, and reigned in his place.", "tr": "World English Bible"}, "2 Kings 16:10-12": {"t": "King Ahaz went to Damascus to meet Tiglath Pileser king of Assyria, and saw the altar that was at Damascus; and king Ahaz sent to Urijah the priest the fashion of the altar, and its pattern, according to all its workmanship. Urijah the priest built an altar: according to all that king Ahaz had sent from Damascus, so Urijah the priest made it for the coming of king Ahaz from Damascus. When the king had come from Damascus, the king saw the altar: and the king drew near to the altar, and offered on it.", "tr": "World English Bible"}, "2 Kings 16:2-4": {"t": "Twenty years old was Ahaz when he began to reign; and he reigned sixteen years in Jerusalem: and he didn’t do that which was right in the eyes of Yahweh his God, like David his father. But he walked in the way of the kings of Israel, yes, and made his son to pass through the fire, according to the abominations of the nations, whom Yahweh cast out from before the children of Israel. He sacrificed and burnt incense in the high places, and on the hills, and under every green tree.", "tr": "World English Bible"}, "2 Kings 16:7-8": {"t": "So Ahaz sent messengers to Tiglath Pileser king of Assyria, saying, “I am your servant and your son. Come up, and save me out of the hand of the king of Syria, and out of the hand of the king of Israel, who rise up against me.” Ahaz took the silver and gold that was found in Yahweh’s house, and in the treasures of the king’s house, and sent it for a present to the king of Assyria.", "tr": "World English Bible"}, "2 Kings 17:1-2": {"t": "In the twelfth year of Ahaz king of Judah, Hoshea the son of Elah began to reign in Samaria over Israel for nine years. He did that which was evil in the sight of Yahweh, yet not as the kings of Israel who were before him.", "tr": "World English Bible"}, "2 Kings 17:3-4": {"t": "Against him came up Shalmaneser king of Assyria; and Hoshea became his servant, and brought him tribute. The king of Assyria found conspiracy in Hoshea; for he had sent messengers to So king of Egypt, and offered no tribute to the king of Assyria, as he had done year by year: therefore the king of Assyria shut him up, and bound him in prison.", "tr": "World English Bible"}, "2 Kings 17:5-6": {"t": "Then the king of Assyria came up throughout all the land, and went up to Samaria, and besieged it three years. In the ninth year of Hoshea the king of Assyria took Samaria, and carried Israel away to Assyria, and placed them in Halah, and on the Habor, the river of Gozan, and in the cities of the Medes.", "tr": "World English Bible"}, "2 Kings 17:6": {"t": "In the ninth year of Hoshea the king of Assyria took Samaria, and carried Israel away to Assyria, and placed them in Halah, and on the Habor, the river of Gozan, and in the cities of the Medes.", "tr": "World English Bible"}, "2 Kings 17:7-18": {"t": "It was so, because the children of Israel had sinned against Yahweh their God, who brought them up out of the land of Egypt from under the hand of Pharaoh king of Egypt, and had feared other gods, and walked in the statutes of the nations, whom Yahweh cast out from before the children of Israel, and of the kings of Israel, which they made. The children of Israel did secretly things that were not right against Yahweh their God: and they built them high places in all their cities, from the tower of the watchmen to the fortified city; and they set them up pillars and Asherah poles on every high hill, and under every green tree; and there they burnt incense in all the high places, as did the [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Kings 17:7-23": {"t": "It was so, because the children of Israel had sinned against Yahweh their God, who brought them up out of the land of Egypt from under the hand of Pharaoh king of Egypt, and had feared other gods, and walked in the statutes of the nations, whom Yahweh cast out from before the children of Israel, and of the kings of Israel, which they made. The children of Israel did secretly things that were not right against Yahweh their God: and they built them high places in all their cities, from the tower of the watchmen to the fortified city; and they set them up pillars and Asherah poles on every high hill, and under every green tree; and there they burnt incense in all the high places, as did the [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Kings 17:7-8": {"t": "It was so, because the children of Israel had sinned against Yahweh their God, who brought them up out of the land of Egypt from under the hand of Pharaoh king of Egypt, and had feared other gods, and walked in the statutes of the nations, whom Yahweh cast out from before the children of Israel, and of the kings of Israel, which they made.", "tr": "World English Bible"}, "2 Kings 18:13": {"t": "Now in the fourteenth year of king Hezekiah, Sennacherib king of Assyria came up against all the fortified cities of Judah, and took them.", "tr": "World English Bible"}, "2 Kings 18:5": {"t": "He trusted in Yahweh, the God of Israel; so that after him was no one like him among all the kings of Judah, nor among them that were before him.", "tr": "World English Bible"}, "2 Kings 19:10-13": {"t": "‘Thus you shall speak to Hezekiah king of Judah, saying, “Don’t let your God in whom you trust deceive you, saying, Jerusalem will not be given into the hand of the king of Assyria. Behold, you have heard what the kings of Assyria have done to all lands, by destroying them utterly. Will you be delivered? Have the gods of the nations delivered them, which my fathers have destroyed, Gozan, and Haran, and Rezeph, and the children of Eden that were in Telassar? Where is the king of Hamath, and the king of Arpad, and the king of the city of Sepharvaim, of Hena, and Ivvah?”’”", "tr": "World English Bible"}, "2 Kings 19:14-15": {"t": "Hezekiah received the letter from the hand of the messengers, and read it. Then Hezekiah went up to Yahweh’s house, and spread it before Yahweh. Hezekiah prayed before Yahweh, and said, “Yahweh, the God of Israel, who sit above the cherubim, you are the God, even you alone, of all the kingdoms of the earth. You have made heaven and earth.", "tr": "World English Bible"}, "2 Kings 19:14-16": {"t": "Hezekiah received the letter from the hand of the messengers, and read it. Then Hezekiah went up to Yahweh’s house, and spread it before Yahweh. Hezekiah prayed before Yahweh, and said, “Yahweh, the God of Israel, who sit above the cherubim, you are the God, even you alone, of all the kingdoms of the earth. You have made heaven and earth. Incline your ear, Yahweh, and hear. Open your eyes, Yahweh, and see. Hear the words of Sennacherib, with which he has sent to defy the living God.", "tr": "World English Bible"}, "2 Kings 19:35-36": {"t": "That night, Yahweh’s angel went out, and struck one hundred eighty-five thousand in the camp of the Assyrians. When men arose early in the morning, behold, these were all dead bodies. So Sennacherib king of Assyria departed, and went and returned, and lived at Nineveh.", "tr": "World English Bible"}, "2 Kings 1:16-17": {"t": "He said to him, “Thus says Yahweh, ‘Because you have sent messengers to inquire of Baal Zebub, the god of Ekron, is it because there is no God in Israel to inquire of his word? Therefore you shall not come down from the bed where you have gone up, but shall surely die.’” So he died according to Yahweh’s word which Elijah had spoken. Jehoram began to reign in his place in the second year of Jehoram the son of Jehoshaphat king of Judah; because he had no son.", "tr": "World English Bible"}, "2 Kings 1:2-3": {"t": "Ahaziah fell down through the lattice in his upper room that was in Samaria, and was sick. So he sent messengers, and said to them, “Go, inquire of Baal Zebub, the god of Ekron, whether I will recover of this sickness.” But Yahweh’s angel said to Elijah the Tishbite, “Arise, go up to meet the messengers of the king of Samaria, and tell them, ‘Is it because there is no God in Israel, that you go to inquire of Baal Zebub, the god of Ekron?", "tr": "World English Bible"}, "2 Kings 20:5-6": {"t": "“Turn back, and tell Hezekiah the prince of my people, ‘Thus says Yahweh, the God of David your father, “I have heard your prayer. I have seen your tears. Behold, I will heal you. On the third day, you shall go up to Yahweh’s house. I will add to your days fifteen years. I will deliver you and this city out of the hand of the king of Assyria. I will defend this city for my own sake, and for my servant David’s sake.”’”", "tr": "World English Bible"}, "2 Kings 21:11-13": {"t": "“Because Manasseh king of Judah has done these abominations, and has done wickedly above all that the Amorites did, who were before him, and has made Judah also to sin with his idols; therefore thus says Yahweh, the God of Israel, ‘Behold, I bring such evil on Jerusalem and Judah, that whoever hears of it, both his ears shall tingle. I will stretch over Jerusalem the line of Samaria, and the plummet of the house of Ahab; and I will wipe Jerusalem as a man wipes a dish, wiping it and turning it upside down.", "tr": "World English Bible"}, "2 Kings 21:16": {"t": "Moreover Manasseh shed innocent blood very much, until he had filled Jerusalem from one end to another; besides his sin with which he made Judah to sin, in doing that which was evil in the sight of Yahweh.", "tr": "World English Bible"}, "2 Kings 21:19": {"t": "Amon was twenty-two years old when he began to reign; and he reigned two years in Jerusalem: and his mother’s name was Meshullemeth the daughter of Haruz of Jotbah.", "tr": "World English Bible"}, "2 Kings 21:2-6": {"t": "He did that which was evil in the sight of Yahweh, after the abominations of the nations whom Yahweh cast out before the children of Israel. For he built again the high places which Hezekiah his father had destroyed; and he reared up altars for Baal, and made an Asherah, as did Ahab king of Israel, and worshiped all the army of the sky, and served them. He built altars in Yahweh’s house, of which Yahweh said, “I will put my name in Jerusalem.” He built altars for all the army of the sky in the two courts of Yahweh’s house. He made his son to pass through the fire, and practiced sorcery, and used enchantments, and dealt with those who had familiar spirits, and with wizards: he worked much [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Kings 21:23-24": {"t": "The servants of Amon conspired against him, and put the king to death in his own house. But the people of the land killed all those who had conspired against king Amon; and the people of the land made Josiah his son king in his place.", "tr": "World English Bible"}, "2 Kings 22:1-2": {"t": "Josiah was eight years old when he began to reign; and he reigned thirty-one years in Jerusalem: and his mother’s name was Jedidah the daughter of Adaiah of Bozkath. He did that which was right in the eyes of Yahweh, and walked in all the way of David his father, and didn’t turn aside to the right hand or to the left.", "tr": "World English Bible"}, "2 Kings 22:8-11": {"t": "Hilkiah the high priest said to Shaphan the scribe, “I have found the book of the law in Yahweh’s house.” Hilkiah delivered the book to Shaphan, and he read it. Shaphan the scribe came to the king, and brought the king word again, and said, “Your servants have emptied out the money that was found in the house, and have delivered it into the hand of the workmen who have the oversight of Yahweh’s house.” Shaphan the scribe told the king, saying, “Hilkiah the priest has delivered a book to me.” Shaphan read it before the king. When the king had heard the words of the book of the law, he tore his clothes.", "tr": "World English Bible"}, "2 Kings 23:1-3": {"t": "The king sent, and they gathered to him all the elders of Judah and of Jerusalem. The king went up to Yahweh’s house, and all the men of Judah and all the inhabitants of Jerusalem with him, and the priests, and the prophets, and all the people, both small and great: and he read in their ears all the words of the book of the covenant which was found in Yahweh’s house. The king stood by the pillar, and made a covenant before Yahweh, to walk after Yahweh, and to keep his commandments, and his testimonies, and his statutes, with all his heart, and all his soul, to confirm the words of this covenant that were written in this book: and all the people stood to the covenant.", "tr": "World English Bible"}, "2 Kings 23:21-23": {"t": "The king commanded all the people, saying, “Keep the Passover to Yahweh your God, as it is written in this book of the covenant.” Surely there was not kept such a Passover from the days of the judges who judged Israel, nor in all the days of the kings of Israel, nor of the kings of Judah; but in the eighteenth year of king Josiah was this Passover kept to Yahweh in Jerusalem.", "tr": "World English Bible"}, "2 Kings 23:25": {"t": "Like him was there no king before him, who turned to Yahweh with all his heart, and with all his soul, and with all his might, according to all the law of Moses; neither after him arose there any like him.", "tr": "World English Bible"}, "2 Kings 23:25, 29": {"t": "Like him was there no king before him, who turned to Yahweh with all his heart, and with all his soul, and with all his might, according to all the law of Moses; neither after him arose there any like him.", "tr": "World English Bible"}, "2 Kings 23:30-31": {"t": "His servants carried him in a chariot dead from Megiddo, and brought him to Jerusalem, and buried him in his own tomb. The people of the land took Jehoahaz the son of Josiah, and anointed him, and made him king in his father’s place. Jehoahaz was twenty-three years old when he began to reign; and he reigned three months in Jerusalem: and his mother’s name was Hamutal the daughter of Jeremiah of Libnah.", "tr": "World English Bible"}, "2 Kings 23:32": {"t": "He did that which was evil in the sight of Yahweh, according to all that his fathers had done.", "tr": "World English Bible"}, "2 Kings 23:33-34": {"t": "Pharaoh Necoh put him in bonds at Riblah in the land of Hamath, that he might not reign in Jerusalem; and put the land to a tribute of one hundred talents of silver, and a talent of gold. Pharaoh Necoh made Eliakim the son of Josiah king in the place of Josiah his father, and changed his name to Jehoiakim: but he took Jehoahaz away; and he came to Egypt, and died there.", "tr": "World English Bible"}, "2 Kings 23:34-36": {"t": "Pharaoh Necoh made Eliakim the son of Josiah king in the place of Josiah his father, and changed his name to Jehoiakim: but he took Jehoahaz away; and he came to Egypt, and died there. Jehoiakim gave the silver and the gold to Pharaoh; but he taxed the land to give the money according to the commandment of Pharaoh: he exacted the silver and the gold of the people of the land, of everyone according to his taxation, to give it to Pharaoh Necoh. Jehoiakim was twenty-five years old when he began to reign; and he reigned eleven years in Jerusalem: and his mother’s name was Zebidah the daughter of Pedaiah of Rumah.", "tr": "World English Bible"}, "2 Kings 24:1-2": {"t": "In his days Nebuchadnezzar king of Babylon came up, and Jehoiakim became his servant three years: then he turned and rebelled against him. Yahweh sent against him bands of the Chaldeans, and bands of the Syrians, and bands of the Moabites, and bands of the children of Ammon, and sent them against Judah to destroy it, according to Yahweh’s word, which he spoke by his servants the prophets.", "tr": "World English Bible"}, "2 Kings 24:11-12": {"t": "Nebuchadnezzar king of Babylon came to the city, while his servants were besieging it; and Jehoiachin the king of Judah went out to the king of Babylon, he, and his mother, and his servants, and his princes, and his officers: and the king of Babylon took him in the eighth year of his reign.", "tr": "World English Bible"}, "2 Kings 24:12-16": {"t": "and Jehoiachin the king of Judah went out to the king of Babylon, he, and his mother, and his servants, and his princes, and his officers: and the king of Babylon took him in the eighth year of his reign. He carried out there all the treasures of Yahweh’s house, and the treasures of the king’s house, and cut in pieces all the vessels of gold, which Solomon king of Israel had made in Yahweh’s temple, as Yahweh had said. He carried away all Jerusalem, and all the princes, and all the mighty men of valor, even ten thousand captives, and all the craftsmen and the smiths; no one remained, except the poorest sort of the people of the land. He carried away Jehoiachin to Babylon; and the king’s [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Kings 24:14-15": {"t": "He carried away all Jerusalem, and all the princes, and all the mighty men of valor, even ten thousand captives, and all the craftsmen and the smiths; no one remained, except the poorest sort of the people of the land. He carried away Jehoiachin to Babylon; and the king’s mother, and the king’s wives, and his officers, and the chief men of the land, carried he into captivity from Jerusalem to Babylon.", "tr": "World English Bible"}, "2 Kings 24:17-18": {"t": "The king of Babylon made Mattaniah, Jehoiachin’s father’s brother, king in his place, and changed his name to Zedekiah. Zedekiah was twenty-one years old when he began to reign; and he reigned eleven years in Jerusalem: and his mother’s name was Hamutal the daughter of Jeremiah of Libnah.", "tr": "World English Bible"}, "2 Kings 24:4": {"t": "and also for the innocent blood that he shed; for he filled Jerusalem with innocent blood: and Yahweh would not pardon.", "tr": "World English Bible"}, "2 Kings 24:8-9": {"t": "Jehoiachin was eighteen years old when he began to reign; and he reigned in Jerusalem three months: and his mother’s name was Nehushta the daughter of Elnathan of Jerusalem. He did that which was evil in the sight of Yahweh, according to all that his father had done.", "tr": "World English Bible"}, "2 Kings 25:1": {"t": "In the ninth year of his reign, in the tenth month, in the tenth day of the month, Nebuchadnezzar king of Babylon came, he and all his army, against Jerusalem, and encamped against it; and they built forts against it around it.", "tr": "World English Bible"}, "2 Kings 25:1-9": {"t": "In the ninth year of his reign, in the tenth month, in the tenth day of the month, Nebuchadnezzar king of Babylon came, he and all his army, against Jerusalem, and encamped against it; and they built forts against it around it. So the city was besieged to the eleventh year of king Zedekiah. On the ninth day of the fourth month the famine was severe in the city, so that there was no bread for the people of the land. Then a breach was made in the city, and all the men of war fled by night by the way of the gate between the two walls, which was by the king’s garden (now the Chaldeans were against the city around it); and the king went by the way of the Arabah. But the army of the Chaldeans [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Kings 25:27-30": {"t": "In the thirty-seventh year of the captivity of Jehoiachin king of Judah, in the twelfth month, on the seven and twentieth day of the month, Evilmerodach king of Babylon, in the year that he began to reign, lifted up the head of Jehoiachin king of Judah out of prison; and he spoke kindly to him, and set his throne above the throne of the kings who were with him in Babylon, and changed his prison garments. Jehoiachin ate bread before him continually all the days of his life: and for his allowance, there was a continual allowance given him of the king, every day a portion, all the days of his life.", "tr": "World English Bible"}, "2 Kings 25:6-7": {"t": "Then they took the king, and carried him up to the king of Babylon to Riblah; and they gave judgment on him. They killed the sons of Zedekiah before his eyes, and put out the eyes of Zedekiah, and bound him in fetters, and carried him to Babylon.", "tr": "World English Bible"}, "2 Kings 25:8-10": {"t": "Now in the fifth month, on the seventh day of the month, which was the nineteenth year of king Nebuchadnezzar, king of Babylon, came Nebuzaradan the captain of the guard, a servant of the king of Babylon, to Jerusalem. He burnt Yahweh’s house, and the king’s house; and all the houses of Jerusalem, even every great house, burnt he with fire. All the army of the Chaldeans, who were with the captain of the guard, broke down the walls around Jerusalem.", "tr": "World English Bible"}, "2 Kings 2:11": {"t": "As they still went on, and talked, behold, a chariot of fire and horses of fire separated them; and Elijah went up by a whirlwind into heaven.", "tr": "World English Bible"}, "2 Kings 2:9-10": {"t": "When they had gone over, Elijah said to Elisha, “Ask what I shall do for you, before I am taken from you.” Elisha said, “Please let a double portion of your spirit be on me.” He said, “You have asked a hard thing. If you see me when I am taken from you, it shall be so for you; but if not, it shall not be so.”", "tr": "World English Bible"}, "2 Kings 3:1": {"t": "Now Jehoram the son of Ahab began to reign over Israel in Samaria in the eighteenth year of Jehoshaphat king of Judah, and reigned twelve years.", "tr": "World English Bible"}, "2 Kings 3:2-3": {"t": "He did that which was evil in the sight of Yahweh, but not like his father, and like his mother; for he put away the pillar of Baal that his father had made. Nevertheless he held to the sins of Jeroboam the son of Nebat, with which he made Israel to sin; he didn’t depart from it.", "tr": "World English Bible"}, "2 Kings 4:32-35": {"t": "When Elisha had come into the house, behold, the child was dead, and laid on his bed. He went in therefore, and shut the door on them both, and prayed to Yahweh. He went up, and lay on the child, and put his mouth on his mouth, and his eyes on his eyes, and his hands on his hands. He stretched himself on him; and the flesh of the child grew warm. Then he returned, and walked in the house once back and forth; and went up, and stretched himself on him. Then the child sneezed seven times, and the child opened his eyes.", "tr": "World English Bible"}, "2 Kings 5:14": {"t": "Then went he down, and dipped himself seven times in the Jordan, according to the saying of the man of God; and his flesh was restored like the flesh of a little child, and he was clean.", "tr": "World English Bible"}, "2 Kings 7:1, 16": {"t": "Elisha said, “Hear Yahweh’s word. Thus says Yahweh, ‘Tomorrow about this time a measure of fine flour will be sold for a shekel, and two measures of barley for a shekel, in the gate of Samaria.’”", "tr": "World English Bible"}, "2 Kings 8:19": {"t": "However Yahweh would not destroy Judah, for David his servant’s sake, as he promised him to give to him a lamp for his children always.", "tr": "World English Bible"}, "2 Kings 9:24": {"t": "Jehu drew his bow with his full strength, and struck Joram between his arms; and the arrow went out at his heart, and he sunk down in his chariot.", "tr": "World English Bible"}, "2 Kings 9:27": {"t": "But when Ahaziah the king of Judah saw this, he fled by the way of the garden house. Jehu followed after him, and said, “Strike him also in the chariot!” They struck him at the ascent of Gur, which is by Ibleam. He fled to Megiddo, and died there.", "tr": "World English Bible"}, "2 Kings 9:33-37": {"t": "He said, “Throw her down!” So they threw her down; and some of her blood was sprinkled on the wall, and on the horses. Then he trampled her under foot. When he had come in, he ate and drink; and he said, “See now to this cursed woman, and bury her; for she is a king’s daughter.” They went to bury her; but they found no more of her than the skull, and the feet, and the palms of her hands. Therefore they came back, and told him. He said, “This is Yahweh’s word, which he spoke by his servant Elijah the Tishbite, saying, ‘The dogs will eat the flesh of Jezebel on the plot of Jezreel, and the body of Jezebel shall be as dung on the face of the field in the portion of Jezreel, so that they shall [the passage continues in your Bible]", "tr": "World English Bible"}, "2 Kings 9:6-7": {"t": "He arose, and went into the house. Then he poured the oil on his head, and said to him, “Thus says Yahweh, the God of Israel, ‘I have anointed you king over the people of Yahweh, even over Israel. You shall strike the house of Ahab your master, that I may avenge the blood of my servants the prophets, and the blood of all the servants of Yahweh, at the hand of Jezebel.", "tr": "World English Bible"}, "2 Peter 1:21": {"t": "For no prophecy ever came by the will of man: but holy men of God spoke, being moved by the Holy Spirit.", "tr": "World English Bible"}, "2 Peter 3:16": {"t": "as also in all of his letters, speaking in them of these things. In those, there are some things that are hard to understand, which the ignorant and unsettled twist, as they also do to the other Scriptures, to their own destruction.", "tr": "World English Bible"}, "2 Peter 3:9": {"t": "The Lord is not slow concerning his promise, as some count slowness; but is patient with us, not wishing that any should perish, but that all should come to repentance.", "tr": "World English Bible"}, "2 Samuel 12:13": {"t": "David said to Nathan, “I have sinned against Yahweh.” Nathan said to David, “Yahweh also has put away your sin. You will not die.", "tr": "World English Bible"}, "2 Samuel 5:12": {"t": "David perceived that Yahweh had established him king over Israel, and that he had exalted his kingdom for his people Israel’s sake.", "tr": "World English Bible"}, "2 Samuel 5:3": {"t": "So all the elders of Israel came to the king to Hebron; and king David made a covenant with them in Hebron before Yahweh; and they anointed David king over Israel.", "tr": "World English Bible"}, "2 Samuel 5:6-7": {"t": "The king and his men went to Jerusalem against the Jebusites, the inhabitants of the land, who spoke to David, saying, “Unless you take away the blind and the lame, you shall not come in here”; thinking, “David can’t come in here.” Nevertheless David took the stronghold of Zion; the same is the city of David.", "tr": "World English Bible"}, "2 Samuel 5:6-9": {"t": "The king and his men went to Jerusalem against the Jebusites, the inhabitants of the land, who spoke to David, saying, “Unless you take away the blind and the lame, you shall not come in here”; thinking, “David can’t come in here.” Nevertheless David took the stronghold of Zion; the same is the city of David. David said on that day, “Whoever strikes the Jebusites, let him get up to the watercourse, and strike the lame and the blind, who are hated by David’s soul.” Therefore they say, “The blind and the lame can’t come into the house.” David lived in the stronghold, and called it the city of David. David built around from Millo and inward.", "tr": "World English Bible"}, "2 Samuel 6:12-15": {"t": "It was told king David, saying, “Yahweh has blessed the house of Obed-Edom, and all that pertains to him, because of the ark of God.” David went and brought up the ark of God from the house of Obed-Edom into the city of David with joy. It was so, that, when those who bore Yahweh’s ark had gone six paces, he sacrificed an ox and a fattened calf. David danced before Yahweh with all his might; and David was clothed in a linen ephod. So David and all the house of Israel brought up Yahweh’s ark with shouting, and with the sound of the trumpet.", "tr": "World English Bible"}, "2 Samuel 7:12-13": {"t": "When your days are fulfilled, and you shall sleep with your fathers, I will set up your seed after you, who shall proceed out of your bowels, and I will establish his kingdom. He shall build a house for my name, and I will establish the throne of his kingdom forever.", "tr": "World English Bible"}, "2 Samuel 7:12-16": {"t": "When your days are fulfilled, and you shall sleep with your fathers, I will set up your seed after you, who shall proceed out of your bowels, and I will establish his kingdom. He shall build a house for my name, and I will establish the throne of his kingdom forever. I will be his father, and he shall be my son. If he commits iniquity, I will chasten him with the rod of men, and with the stripes of the children of men; but my loving kindness shall not depart from him, as I took it from Saul, whom I put away before you. Your house and your kingdom shall be made sure forever before you. Your throne shall be established forever.”’”", "tr": "World English Bible"}, "2 Samuel 7:16": {"t": "Your house and your kingdom shall be made sure forever before you. Your throne shall be established forever.”’”", "tr": "World English Bible"}, "2 Thessalonians 2:15": {"t": "So then, brothers, stand firm, and hold the traditions which you were taught by us, whether by word, or by letter.", "tr": "World English Bible"}, "2 Thessalonians 3:10": {"t": "For even when we were with you, we commanded you this: “If anyone will not work, neither let him eat.”", "tr": "World English Bible"}, "2 Thessalonians 3:17": {"t": "The greeting of me, Paul, with my own hand, which is the sign in every letter: this is how I write.", "tr": "World English Bible"}, "2 Timothy 3:15": {"t": "From infancy, you have known the holy Scriptures which are able to make you wise for salvation through faith, which is in Christ Jesus.", "tr": "World English Bible"}, "2 Timothy 3:15-17": {"t": "From infancy, you have known the holy Scriptures which are able to make you wise for salvation through faith, which is in Christ Jesus. Every Scripture is God-breathed and profitable for teaching, for reproof, for correction, and for instruction in righteousness, that the man of God may be complete, thoroughly equipped for every good work.", "tr": "World English Bible"}, "2 Timothy 3:16-17": {"t": "Every Scripture is God-breathed and profitable for teaching, for reproof, for correction, and for instruction in righteousness, that the man of God may be complete, thoroughly equipped for every good work.", "tr": "World English Bible"}, "2 Timothy 4:6-8": {"t": "For I am already being offered, and the time of my departure has come. I have fought the good fight. I have finished the course. I have kept the faith. From now on, there is stored up for me the crown of righteousness, which the Lord, the righteous judge, will give to me on that day; and not to me only, but also to all those who have loved his appearing.", "tr": "World English Bible"}, "2 Timothy 4:7": {"t": "I have fought the good fight. I have finished the course. I have kept the faith.", "tr": "World English Bible"}, "3 John 1:11": {"t": "Beloved, don’t imitate that which is evil, but that which is good. He who does good is of God. He who does evil hasn’t seen God.", "tr": "World English Bible"}, "3 John 1:4": {"t": "I have no greater joy than this, to hear about my children walking in truth.", "tr": "World English Bible"}, "Acts 12:1-2": {"t": "Now about that time, King Herod stretched out his hands to oppress some of the assembly. He killed James, the brother of John, with the sword.", "tr": "World English Bible"}, "Acts 12:23": {"t": "Immediately an angel of the Lord struck him, because he didn’t give God the glory, and he was eaten by worms and died.", "tr": "World English Bible"}, "Acts 12:6-10": {"t": "The same night when Herod was about to bring him out, Peter was sleeping between two soldiers, bound with two chains. Guards in front of the door kept the prison. And behold, an angel of the Lord stood by him, and a light shone in the cell. He struck Peter on the side, and woke him up, saying, “Stand up quickly!” His chains fell off from his hands. The angel said to him, “Get dressed and put on your sandals.” He did so. He said to him, “Put on your cloak, and follow me.” And he went out and followed him. He didn’t know that what was being done by the angel was real, but thought he saw a vision. When they were past the first and the second guard, they came to the iron gate that leads into [the passage continues in your Bible]", "tr": "World English Bible"}, "Acts 13:22": {"t": "When he had removed him, he raised up David to be their king, to whom he also testified, ‘I have found David the son of Jesse, a man after my heart, who will do all my will.’", "tr": "World English Bible"}, "Acts 13:51": {"t": "But they shook off the dust of their feet against them, and came to Iconium.", "tr": "World English Bible"}, "Acts 15:1-2": {"t": "Some men came down from Judea and taught the brothers, “Unless you are circumcised after the custom of Moses, you can’t be saved.” Therefore when Paul and Barnabas had no small discord and discussion with them, they appointed Paul and Barnabas, and some others of them, to go up to Jerusalem to the apostles and elders about this question.", "tr": "World English Bible"}, "Acts 15:11": {"t": "But we believe that we are saved through the grace of the Lord Jesus, just as they are.”", "tr": "World English Bible"}, "Acts 15:28-29": {"t": "For it seemed good to the Holy Spirit, and to us, to lay no greater burden on you than these necessary things: that you abstain from things sacrificed to idols, from blood, from things strangled, and from sexual immorality, from which if you keep yourselves, it will be well with you. Farewell.”", "tr": "World English Bible"}, "Acts 17:26-27": {"t": "He made from one blood every nation of men to dwell on all the surface of the earth, having determined appointed seasons, and the boundaries of their dwellings, that they should seek the Lord, if perhaps they might reach out for him and find him, though he is not far from each one of us.", "tr": "World English Bible"}, "Acts 18:26": {"t": "He began to speak boldly in the synagogue. But when Priscilla and Aquila heard him, they took him aside, and explained to him the way of God more accurately.", "tr": "World English Bible"}, "Acts 1:6-11": {"t": "Therefore when they had come together, they asked him, “Lord, are you now restoring the kingdom to Israel?” He said to them, “It isn’t for you to know times or seasons which the Father has set within his own authority. But you will receive power when the Holy Spirit has come upon you. You will be witnesses to me in Jerusalem, in all Judea and Samaria, and to the uttermost parts of the earth.” When he had said these things, as they were looking, he was taken up, and a cloud received him out of their sight. While they were looking steadfastly into the sky as he went, behold, two men stood by them in white clothing, who also said, “You men of Galilee, why do you stand looking into the sky? [the passage continues in your Bible]", "tr": "World English Bible"}, "Acts 1:8": {"t": "But you will receive power when the Holy Spirit has come upon you. You will be witnesses to me in Jerusalem, in all Judea and Samaria, and to the uttermost parts of the earth.”", "tr": "World English Bible"}, "Acts 2:1-4": {"t": "Now when the day of Pentecost had come, they were all with one accord in one place. Suddenly there came from the sky a sound like the rushing of a mighty wind, and it filled all the house where they were sitting. Tongues like fire appeared and were distributed to them, and one sat on each of them. They were all filled with the Holy Spirit, and began to speak with other languages, as the Spirit gave them the ability to speak.", "tr": "World English Bible"}, "Acts 2:1-41": {"t": "Now when the day of Pentecost had come, they were all with one accord in one place. Suddenly there came from the sky a sound like the rushing of a mighty wind, and it filled all the house where they were sitting. Tongues like fire appeared and were distributed to them, and one sat on each of them. They were all filled with the Holy Spirit, and began to speak with other languages, as the Spirit gave them the ability to speak. Now there were dwelling in Jerusalem Jews, devout men, from every nation under the sky. When this sound was heard, the multitude came together, and were bewildered, because everyone heard them speaking in his own language. They were all amazed and marveled, saying to [the passage continues in your Bible]", "tr": "World English Bible"}, "Acts 2:38": {"t": "Peter said to them, “Repent, and be baptized, every one of you, in the name of Jesus Christ for the forgiveness of sins, and you will receive the gift of the Holy Spirit.", "tr": "World English Bible"}, "Acts 2:41": {"t": "Then those who gladly received his word were baptized. There were added that day about three thousand souls.", "tr": "World English Bible"}, "Acts 2:42": {"t": "They continued steadfastly in the apostles’ teaching and fellowship, in the breaking of bread, and prayer.", "tr": "World English Bible"}, "Acts 4:12": {"t": "There is salvation in none other, for neither is there any other name under heaven, that is given among men, by which we must be saved!”", "tr": "World English Bible"}, "Acts 4:20": {"t": "for we can’t help telling the things which we saw and heard.”", "tr": "World English Bible"}, "Acts 5:29": {"t": "But Peter and the apostles answered, “We must obey God rather than men.", "tr": "World English Bible"}, "Acts 5:3-4": {"t": "But Peter said, “Ananias, why has Satan filled your heart to lie to the Holy Spirit, and to keep back part of the price of the land? While you kept it, didn’t it remain your own? After it was sold, wasn’t it in your power? How is it that you have conceived this thing in your heart? You haven’t lied to men, but to God.”", "tr": "World English Bible"}, "Acts 7:51": {"t": "“You stiff-necked and uncircumcised in heart and ears, you always resist the Holy Spirit! As your fathers did, so you do.", "tr": "World English Bible"}, "Acts 9:3-6": {"t": "As he traveled, he got close to Damascus, and suddenly a light from the sky shone around him. He fell on the earth, and heard a voice saying to him, “Saul, Saul, why do you persecute me?” He said, “Who are you, Lord?” The Lord said, “I am Jesus, whom you are persecuting. Butrise up, and enter into the city, and you will be told what you must do.”", "tr": "World English Bible"}, "Amos 1:1": {"t": "The words of Amos, who was among the herdsmen of Tekoa, which he saw concerning Israel in the days of Uzziah king of Judah, and in the days of Jeroboam the son of Joash king of Israel, two years before the earthquake.", "tr": "World English Bible"}, "Amos 5:14": {"t": "Seek good, and not evil, that you may live; and so Yahweh, the God of Armies, will be with you, as you say.", "tr": "World English Bible"}, "Amos 5:24": {"t": "But let justice roll on like rivers, and righteousness like a mighty stream.", "tr": "World English Bible"}, "Amos 7:14-15": {"t": "Then Amos answered Amaziah, “I was no prophet, neither was I a prophet’s son; but I was a herdsman, and a farmer of sycamore figs; and Yahweh took me from following the flock, and Yahweh said to me, ‘Go, prophesy to my people Israel.’", "tr": "World English Bible"}, "Amos 9:11": {"t": "In that day I will raise up the tent of David who is fallen, and close up its breaches, and I will raise up its ruins, and I will build it as in the days of old;", "tr": "World English Bible"}, "Colossians 1:15-16": {"t": "who is the image of the invisible God, the firstborn of all creation. For by him all things were created, in the heavens and on the earth, things visible and things invisible, whether thrones or dominions or principalities or powers; all things have been created through him, and for him.", "tr": "World English Bible"}, "Colossians 1:16": {"t": "For by him all things were created, in the heavens and on the earth, things visible and things invisible, whether thrones or dominions or principalities or powers; all things have been created through him, and for him.", "tr": "World English Bible"}, "Colossians 1:16-17": {"t": "For by him all things were created, in the heavens and on the earth, things visible and things invisible, whether thrones or dominions or principalities or powers; all things have been created through him, and for him. He is before all things, and in him all things are held together.", "tr": "World English Bible"}, "Colossians 1:17": {"t": "He is before all things, and in him all things are held together.", "tr": "World English Bible"}, "Colossians 2:8": {"t": "Be careful that you don’t let anyone rob you through his philosophy and vain deceit, after the tradition of men, after the elements of the world, and not after Christ.", "tr": "World English Bible"}, "Colossians 2:9": {"t": "For in him all the fullness of the Godhead dwells bodily,", "tr": "World English Bible"}, "Colossians 3:1-2": {"t": "If then you were raised together with Christ, seek the things that are above, where Christ is, seated on the right hand of God. Set your mind on the things that are above, not on the things that are on the earth.", "tr": "World English Bible"}, "Colossians 3:13": {"t": "bearing with one another, and forgiving each other, if any man has a complaint against any; even as Christ forgave you, so you also do.", "tr": "World English Bible"}, "Daniel 11:31": {"t": "Forces shall stand on his part, and they shall profane the sanctuary, even the fortress, and shall take away the continual burnt offering, and they shall set up the abomination that makes desolate.", "tr": "World English Bible"}, "Daniel 1:1-4": {"t": "In the third year of the reign of Jehoiakim king of Judah came Nebuchadnezzar king of Babylon to Jerusalem, and besieged it. The Lord gave Jehoiakim king of Judah into his hand, with part of the vessels of the house of God; and he carried them into the land of Shinar to the house of his god: and he brought the vessels into the treasure house of his god. The king spoke to Ashpenaz the master of his eunuchs, that he should bring in some of the children of Israel, even of the seed royal and of the nobles; youths in whom was no defect, but well-favored, and skillful in all wisdom, and endowed with knowledge, and understanding science, and such as had ability to stand in the king’s palace; and [the passage continues in your Bible]", "tr": "World English Bible"}, "Daniel 1:1-6": {"t": "In the third year of the reign of Jehoiakim king of Judah came Nebuchadnezzar king of Babylon to Jerusalem, and besieged it. The Lord gave Jehoiakim king of Judah into his hand, with part of the vessels of the house of God; and he carried them into the land of Shinar to the house of his god: and he brought the vessels into the treasure house of his god. The king spoke to Ashpenaz the master of his eunuchs, that he should bring in some of the children of Israel, even of the seed royal and of the nobles; youths in whom was no defect, but well-favored, and skillful in all wisdom, and endowed with knowledge, and understanding science, and such as had ability to stand in the king’s palace; and [the passage continues in your Bible]", "tr": "World English Bible"}, "Daniel 2:21": {"t": "He changes the times and the seasons; he removes kings, and sets up kings; he gives wisdom to the wise, and knowledge to those who have understanding;", "tr": "World English Bible"}, "Daniel 2:27-28": {"t": "Daniel answered before the king, and said, The secret which the king has demanded can neither wise men, enchanters, magicians, nor soothsayers, show to the king; but there is a God in heaven who reveals secrets, and he has made known to the king Nebuchadnezzar what shall be in the latter days. Your dream, and the visions of your head on your bed, are these:", "tr": "World English Bible"}, "Daniel 2:44": {"t": "In the days of those kings shall the God of heaven set up a kingdom which shall never be destroyed, nor shall its sovereignty be left to another people; but it shall break in pieces and consume all these kingdoms, and it shall stand forever.", "tr": "World English Bible"}, "Daniel 6:10": {"t": "When Daniel knew that the writing was signed, he went into his house (now his windows were open in his room toward Jerusalem) and he kneeled on his knees three times a day, and prayed, and gave thanks before his God, as he did before.", "tr": "World English Bible"}, "Daniel 7:13-14": {"t": "I saw in the night visions, and behold, there came with the clouds of the sky one like a son of man, and he came even to the ancient of days, and they brought him near before him. There was given him dominion, and glory, and a kingdom, that all the peoples, nations, and languages should serve him: his dominion is an everlasting dominion, which shall not pass away, and his kingdom that which shall not be destroyed.", "tr": "World English Bible"}, "Daniel 9:24-26": {"t": "Seventy weeks are decreed on your people and on your holy city, to finish disobedience, and to make an end of sins, and to make reconciliation for iniquity, and to bring in everlasting righteousness, and to seal up vision and prophecy, and to anoint the most holy. Know therefore and discern, that from the going out of the commandment to restore and to build Jerusalem to the Anointed One, the prince, shall be seven weeks, and sixty-two weeks: it shall be built again, with street and moat, even in troubled times. After the sixty-two weeks the Anointed One shall be cut off, and shall have nothing: and the people of the prince who shall come shall destroy the city and the sanctuary; and its end [the passage continues in your Bible]", "tr": "World English Bible"}, "Daniel 9:26": {"t": "After the sixty-two weeks the Anointed One shall be cut off, and shall have nothing: and the people of the prince who shall come shall destroy the city and the sanctuary; and its end shall be with a flood, and even to the end shall be war; desolations are determined.", "tr": "World English Bible"}, "Deuteronomy 30:19": {"t": "I call heaven and earth to witness against you this day, that I have set before you life and death, the blessing and the curse. Therefore choose life, that you may live, you and your descendants;", "tr": "World English Bible"}, "Deuteronomy 6:4": {"t": "Hear, Israel: Yahweh is our God. Yahweh is one.", "tr": "World English Bible"}, "Deuteronomy 6:4-5": {"t": "Hear, Israel: Yahweh is our God. Yahweh is one. You shall love Yahweh your God with all your heart, with all your soul, and with all your might.", "tr": "World English Bible"}, "Ecclesiastes 12:13": {"t": "This is the end of the matter. All has been heard. Fear God, and keep his commandments; for this is the whole duty of man.", "tr": "World English Bible"}, "Ecclesiastes 1:2": {"t": "“Vanity of vanities,” says the Preacher; “Vanity of vanities, all is vanity.”", "tr": "World English Bible"}, "Ecclesiastes 3:11": {"t": "He has made everything beautiful in its time. He has also set eternity in their hearts, yet so that man can’t find out the work that God has done from the beginning even to the end.", "tr": "World English Bible"}, "Ephesians 2:8-9": {"t": "for by grace you have been saved through faith, and that not of yourselves; it is the gift of God, not of works, that no one would boast.", "tr": "World English Bible"}, "Ephesians 4:12": {"t": "for the perfecting of the saints, to the work of serving, to the building up of the body of Christ;", "tr": "World English Bible"}, "Ephesians 4:3-6": {"t": "being eager to keep the unity of the Spirit in the bond of peace. There is one body, and one Spirit, even as you also were called in one hope of your calling; one Lord, one faith, one baptism, one God and Father of all, who is over all, and through all, and in us all.", "tr": "World English Bible"}, "Ephesians 5:22": {"t": "Wives, be subject to your own husbands, as to the Lord.", "tr": "World English Bible"}, "Ephesians 5:22-33": {"t": "Wives, be subject to your own husbands, as to the Lord. For the husband is the head of the wife, and Christ also is the head of the assembly, being himself the savior of the body. But as the assembly is subject to Christ, so let the wives also be to their own husbands in everything. Husbands, love your wives, even as Christ also loved the assembly, and gave himself up for it; that he might sanctify it, having cleansed it by the washing of water with the word, that he might present the assembly to himself gloriously, not having spot or wrinkle or any such thing; but that it should be holy and without defect. Even so husbands also ought to love their own wives as their own bodies. He who [the passage continues in your Bible]", "tr": "World English Bible"}, "Ephesians 5:31": {"t": "“For this cause a man will leave his father and mother, and will be joined to his wife. The two will become one flesh.”", "tr": "World English Bible"}, "Ephesians 6:11": {"t": "Put on the whole armor of God, that you may be able to stand against the wiles of the devil.", "tr": "World English Bible"}, "Esther 1:1": {"t": "Now in the days of Ahasuerus (this is Ahasuerus who reigned from India even to Ethiopia, over one hundred twenty-seven provinces),", "tr": "World English Bible"}, "Esther 4:14": {"t": "For if you remain silent now, then relief and deliverance will come to the Jews from another place, but you and your father’s house will perish. Who knows if you haven’t come to the kingdom for such a time as this?”", "tr": "World English Bible"}, "Esther 9:22": {"t": "as the days in which the Jews had rest from their enemies, and the month which was turned to them from sorrow to gladness, and from mourning into a good day; that they should make them days of feasting and gladness, and of sending presents of food to one another, and gifts to the needy.", "tr": "World English Bible"}, "Exodus 12:29-32": {"t": "At midnight, Yahweh struck all the firstborn in the land of Egypt, from the firstborn of Pharaoh who sat on his throne to the firstborn of the captive who was in the dungeon; and all the firstborn of livestock. Pharaoh rose up in the night, he, and all his servants, and all the Egyptians; and there was a great cry in Egypt, for there was not a house where there was not one dead. He called for Moses and Aaron by night, and said, “Rise up, get out from among my people, both you and the children of Israel; and go, serve Yahweh, as you have said! Take both your flocks and your herds, as you have said, and be gone; and bless me also!”", "tr": "World English Bible"}, "Exodus 14:21-31": {"t": "Moses stretched out his hand over the sea, and Yahweh caused the sea to go back by a strong east wind all the night, and made the sea dry land, and the waters were divided. The children of Israel went into the midst of the sea on the dry ground, and the waters were a wall to them on their right hand, and on their left. The Egyptians pursued, and went in after them into the midst of the sea: all of Pharaoh’s horses, his chariots, and his horsemen. In the morning watch, Yahweh looked out on the Egyptian army through the pillar of fire and of cloud, and confused the Egyptian army. He took off their chariot wheels, and they drove them heavily; so that the Egyptians said, “Let’s flee from the [the passage continues in your Bible]", "tr": "World English Bible"}, "Exodus 19:16-20": {"t": "On the third day, when it was morning, there were thunders and lightnings, and a thick cloud on the mountain, and the sound of an exceedingly loud trumpet; and all the people who were in the camp trembled. Moses led the people out of the camp to meet God; and they stood at the lower part of the mountain. Mount Sinai, all it, smoked, because Yahweh descended on it in fire; and its smoke ascended like the smoke of a furnace, and the whole mountain quaked greatly. When the sound of the trumpet grew louder and louder, Moses spoke, and God answered him by a voice. Yahweh came down on Mount Sinai, to the top of the mountain. Yahweh called Moses to the top of the mountain, and Moses went up.", "tr": "World English Bible"}, "Exodus 1:22": {"t": "Pharaoh commanded all his people, saying, “You shall cast every son who is born into the river, and every daughter you shall save alive.”", "tr": "World English Bible"}, "Exodus 20:1-17": {"t": "God spoke all these words, saying, “I am Yahweh your God, who brought you out of the land of Egypt, out of the house of bondage. “You shall have no other gods before me. “You shall not make for yourselves an idol, nor any image of anything that is in the heavens above, or that is in the earth beneath, or that is in the water under the earth: you shall not bow yourself down to them, nor serve them, for I, Yahweh your God, am a jealous God, visiting the iniquity of the fathers on the children, on the third and on the fourth generation of those who hate me, and showing loving kindness to thousands of those who love me and keep my commandments. “You shall not take the name of Yahweh your God in [the passage continues in your Bible]", "tr": "World English Bible"}, "Exodus 20:13": {"t": "“You shall not murder.", "tr": "World English Bible"}, "Exodus 20:2": {"t": "“I am Yahweh your God, who brought you out of the land of Egypt, out of the house of bondage.", "tr": "World English Bible"}, "Exodus 20:2-3": {"t": "“I am Yahweh your God, who brought you out of the land of Egypt, out of the house of bondage. “You shall have no other gods before me.", "tr": "World English Bible"}, "Exodus 20:3": {"t": "“You shall have no other gods before me.", "tr": "World English Bible"}, "Exodus 21:2": {"t": "“If you buy a Hebrew servant, he shall serve six years and in the seventh he shall go out free without paying anything.", "tr": "World English Bible"}, "Exodus 2:2-10": {"t": "The woman conceived, and bore a son. When she saw that he was a fine child, she hid him three months. When she could no longer hide him, she took a papyrus basket for him, and coated it with tar and with pitch. She put the child in it, and laid it in the reeds by the river’s bank. His sister stood far off, to see what would be done to him. Pharaoh’s daughter came down to bathe at the river. Her maidens walked along by the riverside. She saw the basket among the reeds, and sent her handmaid to get it. She opened it, and saw the child, and behold, the baby cried. She had compassion on him, and said, “This is one of the Hebrews’ children.” Then his sister said to Pharaoh’s daughter, “Should I [the passage continues in your Bible]", "tr": "World English Bible"}, "Exodus 3": {"t": "Now Moses was keeping the flock of Jethro, his father-in-law, the priest of Midian, and he led the flock to the back of the wilderness, and came to God’s mountain, to Horeb. Yahweh’s angel appeared to him in a flame of fire out of the midst of a bush. He looked, and behold, the bush burned with fire, and the bush was not consumed. Moses said, “I will turn aside now, and see this great sight, why the bush is not burnt.” When Yahweh saw that he turned aside to see, God called to him out of the midst of the bush, and said, “Moses! Moses!” He said, “Here I am.” He said, “Don’t come close. Take your sandals off of your feet, for the place you are standing on is holy ground.” Moreover he said, “I [the passage continues in your Bible]", "tr": "World English Bible"}, "Exodus 3:14": {"t": "God said to Moses, “I AM WHO I AM,” and he said, “You shall tell the children of Israel this: ‘I AM has sent me to you.’”", "tr": "World English Bible"}, "Ezekiel 1:1-3": {"t": "Now in the thirtieth year, in the fourth month, in the fifth of the month, as I was among the captives by the river Chebar, the heavens were opened, and I saw visions of God. In the fifth of the month, which was the fifth year of king Jehoiachin’s captivity, Yahweh’s word came expressly to Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the river Chebar; and the hand of Yahweh was there on him.", "tr": "World English Bible"}, "Ezekiel 1:26-28": {"t": "Above the expanse that was over their heads was the likeness of a throne, as the appearance of a sapphire stone; and on the likeness of the throne was a likeness as the appearance of a man on it above. I saw as it were glowing metal, as the appearance of fire within it all around, from the appearance of his waist and upward; and from the appearance of his waist and downward I saw as it were the appearance of fire, and there was brightness around him. As the appearance of the rainbow that is in the cloud in the day of rain, so was the appearance of the brightness all around. This was the appearance of the likeness of Yahweh’s glory. When I saw it, I fell on my face, and I heard a voice of one that spoke.", "tr": "World English Bible"}, "Ezekiel 36:26": {"t": "I will also give you a new heart, and I will put a new spirit within you; and I will take away the stony heart out of your flesh, and I will give you a heart of flesh.", "tr": "World English Bible"}, "Ezekiel 37:1-14": {"t": "The hand of Yahweh was on me, and he brought me out in the Spirit of Yahweh, and set me down in the midst of the valley; and it was full of bones. He caused me to pass by them all around: and behold, there were very many in the open valley; and behold, they were very dry. He said to me, Son of man, can these bones live? I answered, Lord Yahweh, you know. Again he said to me, Prophesy over these bones, and tell them, you dry bones, hear Yahweh’s word. Thus says the Lord Yahweh to these bones: Behold, I will cause breath to enter into you, and you shall live. I will lay sinews on you, and will bring up flesh on you, and cover you with skin, and put breath in you, and you shall live; and you [the passage continues in your Bible]", "tr": "World English Bible"}, "Ezekiel 37:5": {"t": "Thus says the Lord Yahweh to these bones: Behold, I will cause breath to enter into you, and you shall live.", "tr": "World English Bible"}, "Ezekiel 3:17": {"t": "Son of man, I have made you a watchman to the house of Israel: therefore hear the word from my mouth, and give them warning from me.", "tr": "World English Bible"}, "Ezekiel 48:35": {"t": "It shall be eighteen thousand reeds around: and the name of the city from that day shall be, Yahweh is there.", "tr": "World English Bible"}, "Ezra 10:10-12": {"t": "Ezra the priest stood up, and said to them, “You have trespassed, and have married foreign women, to increase the guilt of Israel. Now therefore make confession to Yahweh, the God of your fathers, and do his pleasure; and separate yourselves from the peoples of the land, and from the foreign women.” Then all the assembly answered with a loud voice, “As you have said concerning us, so must we do.", "tr": "World English Bible"}, "Ezra 1:1": {"t": "Now in the first year of Cyrus king of Persia, that Yahweh’s word by the mouth of Jeremiah might be accomplished, Yahweh stirred up the spirit of Cyrus king of Persia, so that he made a proclamation throughout all his kingdom, and put it also in writing, saying,", "tr": "World English Bible"}, "Ezra 1:1-4": {"t": "Now in the first year of Cyrus king of Persia, that Yahweh’s word by the mouth of Jeremiah might be accomplished, Yahweh stirred up the spirit of Cyrus king of Persia, so that he made a proclamation throughout all his kingdom, and put it also in writing, saying, “Thus says Cyrus king of Persia, ‘Yahweh, the God of heaven, has given me all the kingdoms of the earth; and he has commanded me to build him a house in Jerusalem, which is in Judah. Whoever there is among you of all his people, may his God be with him, and let him go up to Jerusalem, which is in Judah, and build the house of Yahweh, the God of Israel (he is God), which is in Jerusalem. Whoever is left, in any place where he lives, [the passage continues in your Bible]", "tr": "World English Bible"}, "Ezra 1:2-3": {"t": "“Thus says Cyrus king of Persia, ‘Yahweh, the God of heaven, has given me all the kingdoms of the earth; and he has commanded me to build him a house in Jerusalem, which is in Judah. Whoever there is among you of all his people, may his God be with him, and let him go up to Jerusalem, which is in Judah, and build the house of Yahweh, the God of Israel (he is God), which is in Jerusalem.", "tr": "World English Bible"}, "Ezra 2:64-65": {"t": "The whole assembly together was forty-two thousand three hundred sixty, besides their male servants and their female servants, of whom there were seven thousand three hundred thirty-seven: and they had two hundred singing men and singing women.", "tr": "World English Bible"}, "Ezra 3:10-13": {"t": "When the builders laid the foundation of Yahweh’s temple, they set the priests in their clothing with trumpets, with the Levites the sons of Asaph with cymbals, to praise Yahweh, according to the directions of David king of Israel. They sang to one another in praising and giving thanks to Yahweh, “For he is good, for his loving kindness endures forever toward Israel.” All the people shouted with a great shout, when they praised Yahweh, because the foundation of Yahweh’s house had been laid. But many of the priests and Levites and heads of fathers’ households, the old men who had seen the first house, when the foundation of this house was laid before their eyes, wept with a loud voice. Many [the passage continues in your Bible]", "tr": "World English Bible"}, "Ezra 5:1-2": {"t": "Now the prophets, Haggai the prophet, and Zechariah the son of Iddo, prophesied to the Jews who were in Judah and Jerusalem; in the name of the God of Israel they prophesied to them. Then rose up Zerubbabel the son of Shealtiel, and Jeshua the son of Jozadak, and began to build God’s house which is at Jerusalem; and with them were the prophets of God, helping them.", "tr": "World English Bible"}, "Ezra 6:15-16": {"t": "This house was finished on the third day of the month Adar, which was in the sixth year of the reign of Darius the king. The children of Israel, the priests, and the Levites, and the rest of the children of the captivity, kept the dedication of this house of God with joy.", "tr": "World English Bible"}, "Ezra 7:10": {"t": "For Ezra had set his heart to seek Yahweh’s law, and to do it, and to teach in Israel statutes and ordinances.", "tr": "World English Bible"}, "Ezra 7:6-10": {"t": "this Ezra went up from Babylon: and he was a ready scribe in the law of Moses, which Yahweh, the God of Israel, had given; and the king granted him all his request, according to the hand of Yahweh his God on him. There went up some of the children of Israel, and of the priests, and the Levites, and the singers, and the porters, and the Nethinim, to Jerusalem, in the seventh year of Artaxerxes the king. He came to Jerusalem in the fifth month, which was in the seventh year of the king. For on the first day of the first month began he to go up from Babylon; and on the first day of the fifth month came he to Jerusalem, according to the good hand of his God on him. For Ezra had set his heart to [the passage continues in your Bible]", "tr": "World English Bible"}, "Galatians 1:15-16": {"t": "But when it was the good pleasure of God, who separated me from my mother’s womb, and called me through his grace, to reveal his Son in me, that I might preach him among the Gentiles, I didn’t immediately confer with flesh and blood,", "tr": "World English Bible"}, "Galatians 1:18-19": {"t": "Then after three years I went up to Jerusalem to visit Peter, and stayed with him fifteen days. But of the other apostles I saw no one, except James, the Lord’s brother.", "tr": "World English Bible"}, "Galatians 2:20": {"t": "I have been crucified with Christ, and it is no longer I that live, but Christ living in me. That life which I now live in the flesh, I live by faith in the Son of God, who loved me, and gave himself up for me.", "tr": "World English Bible"}, "Galatians 2:9": {"t": "and when they perceived the grace that was given to me, James and Cephas and John, they who were reputed to be pillars, gave to me and Barnabas the right hand of fellowship, that we should go to the Gentiles, and they to the circumcision.", "tr": "World English Bible"}, "Galatians 3:24": {"t": "So that the law has become our tutor to bring us to Christ, that we might be justified by faith.", "tr": "World English Bible"}, "Galatians 3:28": {"t": "There is neither Jew nor Greek, there is neither slave nor free man, there is neither male nor female; for you are all one in Christ Jesus.", "tr": "World English Bible"}, "Galatians 4:28": {"t": "Now we, brothers, as Isaac was, are children of promise.", "tr": "World English Bible"}, "Galatians 5:22-23": {"t": "But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faith, gentleness, and self-control. Against such things there is no law.", "tr": "World English Bible"}, "Galatians 6:1": {"t": "Brothers, even if a man is caught in some fault, you who are spiritual must restore such a one in a spirit of gentleness; looking to yourself so that you also aren’t tempted.", "tr": "World English Bible"}, "Galatians 6:11": {"t": "See with what large letters I write to you with my own hand.", "tr": "World English Bible"}, "Galatians 6:14": {"t": "But far be it from me to boast, except in the cross of our Lord Jesus Christ, through which the world has been crucified to me, and I to the world.", "tr": "World English Bible"}, "Genesis 12:1": {"t": "Now Yahweh said to Abram, “Get out of your country, and from your relatives, and from your father’s house, to the land that I will show you.", "tr": "World English Bible"}, "Genesis 12:1-3": {"t": "Now Yahweh said to Abram, “Get out of your country, and from your relatives, and from your father’s house, to the land that I will show you. I will make of you a great nation. I will bless you and make your name great. You will be a blessing. I will bless those who bless you, and I will curse him who curses you. All of the families of the earth will be blessed in you.”", "tr": "World English Bible"}, "Genesis 12:2-3": {"t": "I will make of you a great nation. I will bless you and make your name great. You will be a blessing. I will bless those who bless you, and I will curse him who curses you. All of the families of the earth will be blessed in you.”", "tr": "World English Bible"}, "Genesis 12:3": {"t": "I will bless those who bless you, and I will curse him who curses you. All of the families of the earth will be blessed in you.”", "tr": "World English Bible"}, "Genesis 14": {"t": "In the days of Amraphel, king of Shinar, Arioch, king of Ellasar, Chedorlaomer, king of Elam, and Tidal, king of Goiim, they made war with Bera, king of Sodom, and with Birsha, king of Gomorrah, Shinab, king of Admah, and Shemeber, king of Zeboiim, and the king of Bela (the same is Zoar). All these joined together in the valley of Siddim (the same is the Salt Sea). Twelve years they served Chedorlaomer, and in the thirteenth year, they rebelled. In the fourteenth year Chedorlaomer came, and the kings who were with him, and struck the Rephaim in Ashteroth Karnaim, and the Zuzim in Ham, and the Emim in Shaveh Kiriathaim, and the Horites in their Mount Seir, to Elparan, which is by the [the passage continues in your Bible]", "tr": "World English Bible"}, "Genesis 15:13-16": {"t": "He said to Abram, “Know for sure that your seed will live as foreigners in a land that is not theirs, and will serve them. They will afflict them four hundred years. I will also judge that nation, whom they will serve. Afterward they will come out with great wealth, but you will go to your fathers in peace. You will be buried in a good old age. In the fourth generation they will come here again, for the iniquity of the Amorite is not yet full.”", "tr": "World English Bible"}, "Genesis 15:16": {"t": "In the fourth generation they will come here again, for the iniquity of the Amorite is not yet full.”", "tr": "World English Bible"}, "Genesis 15:18-21": {"t": "In that day Yahweh made a covenant with Abram, saying, “To your seed I have given this land, from the river of Egypt to the great river, the river Euphrates: the Kenites, the Kenizzites, the Kadmonites, the Hittites, the Perizzites, the Rephaim, the Amorites, the Canaanites, the Girgashites, and the Jebusites.”", "tr": "World English Bible"}, "Genesis 15:5-6": {"t": "Yahweh brought him outside, and said, “Look now toward the sky, and count the stars, if you are able to count them.” He said to Abram, “So will your seed be.” He believed in Yahweh; and he reckoned it to him for righteousness.", "tr": "World English Bible"}, "Genesis 15:6": {"t": "He believed in Yahweh; and he reckoned it to him for righteousness.", "tr": "World English Bible"}, "Genesis 17:4-7": {"t": "“As for me, behold, my covenant is with you. You will be the father of a multitude of nations. Neither will your name any more be called Abram, but your name will be Abraham; for I have made you the father of a multitude of nations. I will make you exceedingly fruitful, and I will make nations of you. Kings will come out of you. I will establish my covenant between me and you and your seed after you throughout their generations for an everlasting covenant, to be a God to you and to your seed after you.", "tr": "World English Bible"}, "Genesis 18:25": {"t": "Be it far from you to do things like that, to kill the righteous with the wicked, so that the righteous should be like the wicked. May that be far from you. Shouldn’t the Judge of all the earth do right?”", "tr": "World English Bible"}, "Genesis 1:1": {"t": "In the beginning, God created the heavens and the earth.", "tr": "World English Bible"}, "Genesis 1:26-27": {"t": "God said, “Let us make man in our image, after our likeness: and let them have dominion over the fish of the sea, and over the birds of the sky, and over the livestock, and over all the earth, and over every creeping thing that creeps on the earth.” God created man in his own image. In God’s image he created him; male and female he created them.", "tr": "World English Bible"}, "Genesis 1:27": {"t": "God created man in his own image. In God’s image he created him; male and female he created them.", "tr": "World English Bible"}, "Genesis 1:27-28": {"t": "God created man in his own image. In God’s image he created him; male and female he created them. God blessed them. God said to them, “Be fruitful, multiply, fill the earth, and subdue it. Have dominion over the fish of the sea, over the birds of the sky, and over every living thing that moves on the earth.”", "tr": "World English Bible"}, "Genesis 1:5": {"t": "God called the light “day”, and the darkness he called “night”. There was evening and there was morning, the first day.", "tr": "World English Bible"}, "Genesis 21:1-2": {"t": "Yahweh visited Sarah as he had said, and Yahweh did to Sarah as he had spoken. Sarah conceived, and bore Abraham a son in his old age, at the set time of which God had spoken to him.", "tr": "World English Bible"}, "Genesis 21:12": {"t": "God said to Abraham, “Don’t let it be grievous in your sight because of the boy, and because of your handmaid. In all that Sarah says to you, listen to her voice. For from Isaac will your seed be called.", "tr": "World English Bible"}, "Genesis 21:6": {"t": "Sarah said, “God has made me laugh. Everyone who hears will laugh with me.”", "tr": "World English Bible"}, "Genesis 25:21-26": {"t": "Isaac entreated Yahweh for his wife, because she was barren. Yahweh was entreated by him, and Rebekah his wife conceived. The children struggled together within her. She said, “If it be so, why do I live?” She went to inquire of Yahweh. Yahweh said to her, “Two nations are in your womb. Two peoples will be separated from your body. The one people will be stronger than the other people. The elder will serve the younger.” When her days to be delivered were fulfilled, behold, there were twins in her womb. The first came out red all over, like a hairy garment. They named him Esau. After that, his brother came out, and his hand had hold on Esau’s heel. He was named Jacob. Isaac was sixty years [the passage continues in your Bible]", "tr": "World English Bible"}, "Genesis 25:23": {"t": "Yahweh said to her, “Two nations are in your womb. Two peoples will be separated from your body. The one people will be stronger than the other people. The elder will serve the younger.”", "tr": "World English Bible"}, "Genesis 25:25-26": {"t": "The first came out red all over, like a hairy garment. They named him Esau. After that, his brother came out, and his hand had hold on Esau’s heel. He was named Jacob. Isaac was sixty years old when she bore them.", "tr": "World English Bible"}, "Genesis 2:24": {"t": "Therefore a man will leave his father and his mother, and will join with his wife, and they will be one flesh.", "tr": "World English Bible"}, "Genesis 37:28": {"t": "Midianites who were merchants passed by, and they drew and lifted up Joseph out of the pit, and sold Joseph to the Ishmaelites for twenty pieces of silver. They brought Joseph into Egypt.", "tr": "World English Bible"}, "Genesis 37:3-4": {"t": "Now Israel loved Joseph more than all his children, because he was the son of his old age, and he made him a coat of many colors. His brothers saw that their father loved him more than all his brothers, and they hated him, and couldn’t speak peaceably to him.", "tr": "World English Bible"}, "Genesis 3:16": {"t": "To the woman he said, “I will greatly multiply your pain in childbirth. In pain you will bear children. Your desire will be for your husband, and he will rule over you.”", "tr": "World English Bible"}, "Genesis 46:27": {"t": "The sons of Joseph, who were born to him in Egypt, were two souls. All the souls of the house of Jacob, who came into Egypt, were seventy.", "tr": "World English Bible"}, "Genesis 46:5-6": {"t": "Jacob rose up from Beersheba, and the sons of Israel carried Jacob, their father, their little ones, and their wives, in the wagons which Pharaoh had sent to carry him. They took their livestock, and their goods, which they had gotten in the land of Canaan, and came into Egypt—Jacob, and all his seed with him,", "tr": "World English Bible"}, "Genesis 49:10": {"t": "The scepter will not depart from Judah, nor the ruler’s staff from between his feet, until he comes to whom it belongs. To him will the obedience of the peoples be.", "tr": "World English Bible"}, "Genesis 50:20": {"t": "As for you, you meant evil against me, but God meant it for good, to bring to pass, as it is this day, to save many people alive.", "tr": "World English Bible"}, "Genesis 5; 11": {"t": "This is the book of the generations of Adam. In the day that God created man, he made him in God’s likeness. He created them male and female, and blessed them. On the day they were created, he named them “Adam”. Adam lived one hundred thirty years, and became the father of a son in his own likeness, after his image, and named him Seth. The days of Adam after he became the father of Seth were eight hundred years, and he became the father of other sons and daughters. All the days that Adam lived were nine hundred thirty years, then he died. Seth lived one hundred five years, then became the father of Enosh. Seth lived after he became the father of Enosh eight hundred seven years, and became [the passage continues in your Bible]", "tr": "World English Bible"}, "Genesis 7:19-20": {"t": "The waters rose very high on the earth. All the high mountains that were under the whole sky were covered. The waters rose fifteen cubits higher, and the mountains were covered.", "tr": "World English Bible"}, "Genesis 9:6": {"t": "Whoever sheds man’s blood, his blood will be shed by man, for God made man in his own image.", "tr": "World English Bible"}, "Habakkuk 1:13": {"t": "You who have purer eyes than to see evil, and who cannot look on perversity, why do you tolerate those who deal treacherously, and keep silent when the wicked swallows up the man who is more righteous than he,", "tr": "World English Bible"}, "Habakkuk 2:4": {"t": "Behold, his soul is puffed up. It is not upright in him, but the righteous will live by his faith.", "tr": "World English Bible"}, "Habakkuk 3:17-18": {"t": "For though the fig tree doesn’t flourish, nor fruit be in the vines; the labor of the olive fails, the fields yield no food; the flocks are cut off from the fold, and there is no herd in the stalls: yet I will rejoice in Yahweh. I will be joyful in the God of my salvation!", "tr": "World English Bible"}, "Haggai 1:1": {"t": "In the second year of Darius the king, in the sixth month, in the first day of the month, Yahweh’s word came by Haggai, the prophet, to Zerubbabel, the son of Shealtiel, governor of Judah, and to Joshua, the son of Jehozadak, the high priest, saying,", "tr": "World English Bible"}, "Haggai 1:14-15": {"t": "Yahweh stirred up the spirit of Zerubbabel, the son of Shealtiel, governor of Judah, and the spirit of Joshua, the son of Jehozadak, the high priest, and the spirit of all the remnant of the people; and they came and worked on the house of Yahweh of Armies, their God, in the twenty-fourth day of the month, in the sixth month, in the second year of Darius the king.", "tr": "World English Bible"}, "Haggai 1:4": {"t": "“Is it a time for you yourselves to dwell in your paneled houses, while this house lies waste?", "tr": "World English Bible"}, "Haggai 2:9": {"t": "‘The latter glory of this house will be greater than the former,’ says Yahweh of Armies; ‘and in this place will I give peace,’ says Yahweh of Armies.”", "tr": "World English Bible"}, "Hebrews 10:11-14": {"t": "Every priest indeed stands day by day serving and often offering the same sacrifices, which can never take away sins, but he, when he had offered one sacrifice for sins forever, sat down on the right hand of God; from that time waiting until his enemies are made the footstool of his feet. For by one offering he has perfected forever those who are being sanctified.", "tr": "World English Bible"}, "Hebrews 11": {"t": "Now faith is assurance of things hoped for, proof of things not seen. For by this, the elders obtained testimony. By faith, we understand that the universe has been framed by the word of God, so that what is seen has not been made out of things which are visible. By faith, Abel offered to God a more excellent sacrifice than Cain, through which he had testimony given to him that he was righteous, God testifying with respect to his gifts; and through it he, being dead, still speaks. By faith, Enoch was taken away, so that he wouldn’t see death, and he was not found, because God translated him. For he has had testimony given to him that before his translation he had been well pleasing to God. [the passage continues in your Bible]", "tr": "World English Bible"}, "Hebrews 11:1": {"t": "Now faith is assurance of things hoped for, proof of things not seen.", "tr": "World English Bible"}, "Hebrews 11:13": {"t": "These all died in faith, not having received the promises, but having seen them and embraced them from afar, and having confessed that they were strangers and pilgrims on the earth.", "tr": "World English Bible"}, "Hebrews 11:13-16": {"t": "These all died in faith, not having received the promises, but having seen them and embraced them from afar, and having confessed that they were strangers and pilgrims on the earth. For those who say such things make it clear that they are seeking a country of their own. If indeed they had been thinking of that country from which they went out, they would have had enough time to return. But now they desire a better country, that is, a heavenly one. Therefore God is not ashamed of them, to be called their God, for he has prepared a city for them.", "tr": "World English Bible"}, "Hebrews 11:23": {"t": "By faith, Moses, when he was born, was hidden for three months by his parents, because they saw that he was a beautiful child, and they were not afraid of the king’s commandment.", "tr": "World English Bible"}, "Hebrews 11:8": {"t": "By faith, Abraham, when he was called, obeyed to go out to the place which he was to receive for an inheritance. He went out, not knowing where he went.", "tr": "World English Bible"}, "Hebrews 13:14": {"t": "For we don’t have here an enduring city, but we seek that which is to come.", "tr": "World English Bible"}, "Hebrews 1:6": {"t": "When he again brings in the firstborn into the world he says, “Let all the angels of God worship him.”", "tr": "World English Bible"}, "Hebrews 4:12": {"t": "For the word of God is living, and active, and sharper than any two-edged sword, and piercing even to the dividing of soul and spirit, of both joints and marrow, and is able to discern the thoughts and intentions of the heart.", "tr": "World English Bible"}, "Hebrews 9:15": {"t": "For this reason he is the mediator of a new covenant, since a death has occurred for the redemption of the transgressions that were under the first covenant, that those who have been called may receive the promise of the eternal inheritance.", "tr": "World English Bible"}, "Hebrews 9:22": {"t": "According to the law, nearly everything is cleansed with blood, and apart from shedding of blood there is no remission.", "tr": "World English Bible"}, "Hosea 11:1": {"t": "“When Israel was a child, then I loved him, and called my son out of Egypt.", "tr": "World English Bible"}, "Hosea 11:8": {"t": "“How can I give you up, Ephraim? How can I hand you over, Israel? How can I make you like Admah? How can I make you like Zeboiim? My heart is turned within me, my compassion is aroused.", "tr": "World English Bible"}, "Hosea 1:1": {"t": "Yahweh’s word that came to Hosea the son of Beeri, in the days of Uzziah, Jotham, Ahaz, and Hezekiah, kings of Judah, and in the days of Jeroboam the son of Joash, king of Israel.", "tr": "World English Bible"}, "Hosea 1:2": {"t": "When Yahweh spoke at first by Hosea, Yahweh said to Hosea, “Go, take for yourself a wife of prostitution and children of unfaithfulness; for the land commits great adultery, forsaking Yahweh.”", "tr": "World English Bible"}, "Hosea 6:6": {"t": "For I desire mercy, and not sacrifice; and the knowledge of God more than burnt offerings.", "tr": "World English Bible"}, "Isaiah 11:1": {"t": "A shoot will come out of the stock of Jesse, and a branch out of his roots will bear fruit.", "tr": "World English Bible"}, "Isaiah 20:1": {"t": "In the year that Tartan came to Ashdod, when Sargon the king of Assyria sent him, and he fought against Ashdod and took it;", "tr": "World English Bible"}, "Isaiah 40:28": {"t": "Haven’t you known? Haven’t you heard? The everlasting God, Yahweh, The Creator of the ends of the earth, doesn’t faint. He isn’t weary. His understanding is unsearchable.", "tr": "World English Bible"}, "Isaiah 43:10": {"t": "“You are my witnesses,” says Yahweh, “With my servant whom I have chosen; that you may know and believe me, and understand that I am he. Before me there was no God formed, neither will there be after me.", "tr": "World English Bible"}, "Isaiah 44:28": {"t": "Who says of Cyrus, ‘He is my shepherd, and shall perform all my pleasure,’ even saying of Jerusalem, ‘She will be built;’ and of the temple, ‘Your foundation will be laid.’”", "tr": "World English Bible"}, "Isaiah 44:6": {"t": "This is what Yahweh, the King of Israel, and his Redeemer, Yahweh of Armies, says: “I am the first, and I am the last; and besides me there is no God.", "tr": "World English Bible"}, "Isaiah 53:11": {"t": "After the suffering of his soul, he will see the light and be satisfied. My righteous servant will justify many by the knowledge of himself; and he will bear their iniquities.", "tr": "World English Bible"}, "Isaiah 53:12": {"t": "Therefore will I divide him a portion with the great, and he shall divide the plunder with the strong; because he poured out his soul to death, and was numbered with the transgressors; yet he bore the sin of many, and made intercession for the transgressors.", "tr": "World English Bible"}, "Isaiah 53:5": {"t": "But he was pierced for our transgressions. He was crushed for our iniquities. The punishment that brought our peace was on him; and by his wounds we are healed.", "tr": "World English Bible"}, "Isaiah 53:5-6": {"t": "But he was pierced for our transgressions. He was crushed for our iniquities. The punishment that brought our peace was on him; and by his wounds we are healed. All we like sheep have gone astray. Everyone has turned to his own way; and Yahweh has laid on him the iniquity of us all.", "tr": "World English Bible"}, "Isaiah 53:6": {"t": "All we like sheep have gone astray. Everyone has turned to his own way; and Yahweh has laid on him the iniquity of us all.", "tr": "World English Bible"}, "Isaiah 53:7": {"t": "He was oppressed, yet when he was afflicted he didn’t open his mouth. As a lamb that is led to the slaughter, and as a sheep that before its shearers is mute, so he didn’t open his mouth.", "tr": "World English Bible"}, "Isaiah 53:9": {"t": "They made his grave with the wicked, and with a rich man in his death; although he had done no violence, neither was any deceit in his mouth.", "tr": "World English Bible"}, "Isaiah 55:11": {"t": "so shall my word be that goes out of my mouth: it shall not return to me void, but it shall accomplish that which I please, and it shall prosper in the thing I sent it to do.", "tr": "World English Bible"}, "Isaiah 57:15": {"t": "For thus says the high and lofty One who inhabits eternity, whose name is Holy: “I dwell in the high and holy place, with him also who is of a contrite and humble spirit, to revive the spirit of the humble, and to revive the heart of the contrite.", "tr": "World English Bible"}, "Isaiah 6:1": {"t": "In the year that king Uzziah died, I saw the Lord sitting on a throne, high and lifted up; and his train filled the temple.", "tr": "World English Bible"}, "Isaiah 6:1-8": {"t": "In the year that king Uzziah died, I saw the Lord sitting on a throne, high and lifted up; and his train filled the temple. Above him stood the seraphim. Each one had six wings. With two he covered his face. With two he covered his feet. With two he flew. One called to another, and said, “Holy, holy, holy, is Yahweh of Armies! The whole earth is full of his glory!” The foundations of the thresholds shook at the voice of him who called, and the house was filled with smoke. Then I said, “Woe is me! For I am undone, because I am a man of unclean lips, and I dwell in the midst of a people of unclean lips: for my eyes have seen the King, Yahweh of Armies!” Then one of the seraphim flew to me, [the passage continues in your Bible]", "tr": "World English Bible"}, "Isaiah 7:10-12": {"t": "Yahweh spoke again to Ahaz, saying, “Ask a sign of Yahweh your God; ask it either in the depth, or in the height above.” But Ahaz said, “I will not ask, neither will I tempt Yahweh.”", "tr": "World English Bible"}, "Isaiah 7:14": {"t": "Therefore the Lord himself will give you a sign. Behold, the virgin will conceive, and bear a son, and shall call his name Immanuel.", "tr": "World English Bible"}, "Isaiah 9:6": {"t": "For to us a child is born. To us a son is given; and the government will be on his shoulders. His name will be called Wonderful, Counselor, Mighty God, Everlasting Father, Prince of Peace.", "tr": "World English Bible"}, "James 1:22": {"t": "But be doers of the word, and not only hearers, deluding your own selves.", "tr": "World English Bible"}, "James 2:17": {"t": "Even so faith, if it has no works, is dead in itself.", "tr": "World English Bible"}, "James 4:14": {"t": "Whereas you don’t know what your life will be like tomorrow. For what is your life? For you are a vapor, that appears for a little time, and then vanishes away.", "tr": "World English Bible"}, "James 4:3": {"t": "You ask, and don’t receive, because you ask with wrong motives, so that you may spend it for your pleasures.", "tr": "World English Bible"}, "Jeremiah 1:1-3": {"t": "The words of Jeremiah the son of Hilkiah, of the priests who were in Anathoth in the land of Benjamin: to whom Yahweh’s word came in the days of Josiah the son of Amon, king of Judah, in the thirteenth year of his reign. It came also in the days of Jehoiakim the son of Josiah, king of Judah, to the end of the eleventh year of Zedekiah, the son of Josiah, king of Judah, to the carrying away of Jerusalem captive in the fifth month.", "tr": "World English Bible"}, "Jeremiah 1:9-10": {"t": "Then Yahweh stretched out his hand, and touched my mouth; and Yahweh said to me, “Behold, I have put my words in your mouth. Behold, I have this day set you over the nations and over the kingdoms, to pluck up and to break down and to destroy and to overthrow, to build and to plant.”", "tr": "World English Bible"}, "Jeremiah 22:11-12": {"t": "For thus says Yahweh touching Shallum the son of Josiah, king of Judah, who reigned instead of Josiah his father, and who went out of this place: He shall not return there any more. But in the place where they have led him captive, there shall he die, and he shall see this land no more.", "tr": "World English Bible"}, "Jeremiah 22:18-19": {"t": "Therefore thus says Yahweh concerning Jehoiakim the son of Josiah, king of Judah: they shall not lament for him, saying, Ah my brother! or, Ah sister! They shall not lament for him, saying Ah lord! or, Ah his glory! He shall be buried with the burial of a donkey, drawn and cast out beyond the gates of Jerusalem.", "tr": "World English Bible"}, "Jeremiah 22:30": {"t": "Thus says Yahweh, Write you this man childless, a man who shall not prosper in his days; for no more shall a man of his seed prosper, sitting on the throne of David, and ruling in Judah.", "tr": "World English Bible"}, "Jeremiah 25:11": {"t": "This whole land shall be a desolation, and an astonishment; and these nations shall serve the king of Babylon seventy years.", "tr": "World English Bible"}, "Jeremiah 29:10": {"t": "For thus says Yahweh, After seventy years are accomplished for Babylon, I will visit you, and perform my good word toward you, in causing you to return to this place.", "tr": "World English Bible"}, "Jeremiah 29:10-11": {"t": "For thus says Yahweh, After seventy years are accomplished for Babylon, I will visit you, and perform my good word toward you, in causing you to return to this place. For I know the thoughts that I think toward you, says Yahweh, thoughts of peace, and not of evil, to give you hope and a future.", "tr": "World English Bible"}, "Jeremiah 29:11": {"t": "For I know the thoughts that I think toward you, says Yahweh, thoughts of peace, and not of evil, to give you hope and a future.", "tr": "World English Bible"}, "Jeremiah 29:13": {"t": "You shall seek me, and find me, when you shall search for me with all your heart.", "tr": "World English Bible"}, "Jeremiah 2:13": {"t": "“For my people have committed two evils: they have forsaken me, the spring of living waters, and cut them out cisterns, broken cisterns, that can hold no water.", "tr": "World English Bible"}, "Jeremiah 31:31-34": {"t": "Behold, the days come, says Yahweh, that I will make a new covenant with the house of Israel, and with the house of Judah: not according to the covenant that I made with their fathers in the day that I took them by the hand to bring them out of the land of Egypt; which my covenant they broke, although I was a husband to them, says Yahweh. But this is the covenant that I will make with the house of Israel after those days, says Yahweh: I will put my law in their inward parts, and in their heart will I write it; and I will be their God, and they shall be my people: and they shall teach no more every man his neighbor, and every man his brother, saying, Know Yahweh; for they shall all know me, [the passage continues in your Bible]", "tr": "World English Bible"}, "Jeremiah 31:33": {"t": "But this is the covenant that I will make with the house of Israel after those days, says Yahweh: I will put my law in their inward parts, and in their heart will I write it; and I will be their God, and they shall be my people:", "tr": "World English Bible"}, "Jeremiah 36:23": {"t": "When Jehudi had read three or four leaves, the king cut it with the penknife, and cast it into the fire that was in the brazier, until all the scroll was consumed in the fire that was in the brazier.", "tr": "World English Bible"}, "Jeremiah 38:17-18": {"t": "Then Jeremiah said to Zedekiah, Thus says Yahweh, the God of Armies, the God of Israel: If you will go out to the king of Babylon’s princes, then your soul shall live, and this city shall not be burned with fire; and you shall live, and your house. But if you will not go out to the king of Babylon’s princes, then shall this city be given into the hand of the Chaldeans, and they shall burn it with fire, and you shall not escape out of their hand.", "tr": "World English Bible"}, "Job 19:25": {"t": "But as for me, I know that my Redeemer lives. In the end, he will stand upon the earth.", "tr": "World English Bible"}, "Job 1:21": {"t": "He said, “Naked I came out of my mother’s womb, and naked shall I return there. Yahweh gave, and Yahweh has taken away. Blessed be Yahweh’s name.”", "tr": "World English Bible"}, "Joel 1:4": {"t": "What the swarming locust has left, the great locust has eaten. What the great locust has left, the grasshopper has eaten. What the grasshopper has left, the caterpillar has eaten.", "tr": "World English Bible"}, "Joel 2:12-13": {"t": "“Yet even now,” says Yahweh, “turn to me with all your heart, and with fasting, and with weeping, and with mourning.” Tear your heart, and not your garments, and turn to Yahweh, your God; for he is gracious and merciful, slow to anger, and abundant in loving kindness, and relents from sending calamity.", "tr": "World English Bible"}, "Joel 2:13": {"t": "Tear your heart, and not your garments, and turn to Yahweh, your God; for he is gracious and merciful, slow to anger, and abundant in loving kindness, and relents from sending calamity.", "tr": "World English Bible"}, "Joel 2:28": {"t": "“It will happen afterward, that I will pour out my Spirit on all flesh; and your sons and your daughters will prophesy. Your old men will dream dreams. Your young men will see visions.", "tr": "World English Bible"}, "Joel 2:28-29": {"t": "“It will happen afterward, that I will pour out my Spirit on all flesh; and your sons and your daughters will prophesy. Your old men will dream dreams. Your young men will see visions. And also on the servants and on the handmaids in those days, I will pour out my Spirit.", "tr": "World English Bible"}, "Joel 2:28-32": {"t": "“It will happen afterward, that I will pour out my Spirit on all flesh; and your sons and your daughters will prophesy. Your old men will dream dreams. Your young men will see visions. And also on the servants and on the handmaids in those days, I will pour out my Spirit. I will show wonders in the heavens and in the earth: blood, fire, and pillars of smoke. The sun will be turned into darkness, and the moon into blood, before the great and terrible day of Yahweh comes. It will happen that whoever will call on Yahweh’s name shall be saved; for in Mount Zion and in Jerusalem there will be those who escape, as Yahweh has said, and among the remnant, those whom Yahweh calls.", "tr": "World English Bible"}, "John 10:22": {"t": "It was the Feast of the Dedication at Jerusalem.", "tr": "World English Bible"}, "John 10:30": {"t": "I and the Father are one.”", "tr": "World English Bible"}, "John 10:33": {"t": "The Jews answered him, “We don’t stone you for a good work, but for blasphemy: because you, being a man, make yourself God.”", "tr": "World English Bible"}, "John 11:1-44": {"t": "Now a certain man was sick, Lazarus from Bethany, of the village of Mary and her sister, Martha. It was that Mary who had anointed the Lord with ointment, and wiped his feet with her hair, whose brother, Lazarus, was sick. The sisters therefore sent to him, saying, “Lord, behold, he for whom you have great affection is sick.” But when Jesus heard it, he said, “This sickness is not to death, but for the glory of God, that God’s Son may be glorified by it.” Now Jesus loved Martha, and her sister, and Lazarus. When therefore he heard that he was sick, he stayed two days in the place where he was. Then after this he said to the disciples, “Let’s go into Judea again.” The disciples told him, [the passage continues in your Bible]", "tr": "World English Bible"}, "John 11:25-26": {"t": "Jesus said to her, “I am the resurrection and the life. He who believes in me will still live, even if he dies. Whoever lives and believes in me will never die. Do you believe this?”", "tr": "World English Bible"}, "John 11:6": {"t": "When therefore he heard that he was sick, he stayed two days in the place where he was.", "tr": "World English Bible"}, "John 12:12-19": {"t": "On the next day a great multitude had come to the feast. When they heard that Jesus was coming to Jerusalem, they took the branches of the palm trees, and went out to meet him, and cried out, “Hosanna! Blessed is he who comes in the name of the Lord, the King of Israel!” Jesus, having found a young donkey, sat on it. As it is written, “Don’t be afraid, daughter of Zion. Behold, your King comes, sitting on a donkey’s colt.” His disciples didn’t understand these things at first, but when Jesus was glorified, then they remembered that these things were written about him, and that they had done these things to him. The multitude therefore that was with him when he called Lazarus out of the [the passage continues in your Bible]", "tr": "World English Bible"}, "John 14:25-26": {"t": "I have said these things to you, while still living with you. But the Counselor, the Holy Spirit, whom the Father will send in my name, he will teach you all things, and will remind you of all that I said to you.", "tr": "World English Bible"}, "John 14:6": {"t": "Jesus said to him, “I am the way, the truth, and the life. No one comes to the Father, except through me.", "tr": "World English Bible"}, "John 14:9": {"t": "Jesus said to him, “Have I been with you such a long time, and do you not know me, Philip? He who has seen me has seen the Father. How do you say, ‘Show us the Father?’", "tr": "World English Bible"}, "John 15:26": {"t": "“When the Counselorhas come, whom I will send to you from the Father, the Spirit of truth, who proceeds from the Father, he will testify about me.", "tr": "World English Bible"}, "John 17:24": {"t": "Father, I desire that they also whom you have given me be with me where I am, that they may see my glory, which you have given me, for you loved me before the foundation of the world.", "tr": "World English Bible"}, "John 18:28-19:16": {"t": "They led Jesus therefore from Caiaphas into the Praetorium. It was early, and they themselves didn’t enter into the Praetorium, that they might not be defiled, but might eat the Passover. Pilate therefore went out to them, and said, “What accusation do you bring against this man?” They answered him, “If this man weren’t an evildoer, we wouldn’t have delivered him up to you.” Pilate therefore said to them, “Take him yourselves, and judge him according to your law.” Therefore the Jews said to him, “It is not lawful for us to put anyone to death,” that the word of Jesus might be fulfilled, which he spoke, signifying by what kind of death he should die. Pilate therefore entered again into the [the passage continues in your Bible]", "tr": "World English Bible"}, "John 18:36": {"t": "Jesus answered, “My Kingdom is not of this world. If my Kingdom were of this world, then my servants would fight, that I wouldn’t be delivered to the Jews. But now my Kingdom is not from here.”", "tr": "World English Bible"}, "John 19:16-37": {"t": "So then he delivered him to them to be crucified. So they took Jesus and led him away. He went out, bearing his cross, to the place called “The Place of a Skull”, which is called in Hebrew, “Golgotha”, where they crucified him, and with him two others, on either side one, and Jesus in the middle. Pilate wrote a title also, and put it on the cross. There was written, “JESUS OF NAZARETH, THE KING OF THE JEWS.” Therefore many of the Jews read this title, for the place where Jesus was crucified was near the city; and it was written in Hebrew, in Latin, and in Greek. The chief priests of the Jews therefore said to Pilate, “Don’t write, ‘The King of the Jews,’ but, ‘he said, I am King of the [the passage continues in your Bible]", "tr": "World English Bible"}, "John 19:34": {"t": "However one of the soldiers pierced his side with a spear, and immediately blood and water came out.", "tr": "World English Bible"}, "John 19:38-42": {"t": "After these things, Joseph of Arimathaea, being a disciple of Jesus, but secretly for fear of the Jews, asked of Pilate that he might take away Jesus’ body. Pilate gave him permission. He came therefore and took away his body. Nicodemus, who at first came to Jesus by night, also came bringing a mixture of myrrh and aloes, about a hundred Roman pounds. So they took Jesus’ body, and bound it in linen cloths with the spices, as the custom of the Jews is to bury. Now in the place where he was crucified there was a garden. In the garden was a new tomb in which no man had ever yet been laid. Then because of the Jews’ Preparation Day (for the tomb was near at hand) they laid Jesus there.", "tr": "World English Bible"}, "John 1:1": {"t": "In the beginning was the Word, and the Word was with God, and the Word was God.", "tr": "World English Bible"}, "John 1:14": {"t": "The Word became flesh, and lived among us. We saw his glory, such glory as of the one and only Son of the Father, full of grace and truth.", "tr": "World English Bible"}, "John 20:1-18": {"t": "Now on the first day of the week, Mary Magdalene went early, while it was still dark, to the tomb, and saw the stone taken away from the tomb. Therefore she ran and came to Simon Peter, and to the other disciple whom Jesus loved, and said to them, “They have taken away the Lord out of the tomb, and we don’t know where they have laid him!” Therefore Peter and the other disciple went out, and they went toward the tomb. They both ran together. The other disciple outran Peter, and came to the tomb first. Stooping and looking in, he saw the linen cloths lying, yet he didn’t enter in. Then Simon Peter came, following him, and entered into the tomb. He saw the linen cloths lying, and the cloth [the passage continues in your Bible]", "tr": "World English Bible"}, "John 20:24-29": {"t": "But Thomas, one of the twelve, called Didymus, wasn’t with them when Jesus came. The other disciples therefore said to him, “We have seen the Lord!” But he said to them, “Unless I see in his hands the print of the nails, and put my hand into his side, I will not believe.” After eight days again his disciples were inside, and Thomas was with them. Jesus came, the doors being locked, and stood in the midst, and said, “Peace be to you.” Then he said to Thomas, “Reach here your finger, and see my hands. Reach here your hand, and put it into my side. Don’t be unbelieving, but believing.” Thomas answered him, “My Lord and my God!” Jesus said to him, “Because you have seen me,you have believed. [the passage continues in your Bible]", "tr": "World English Bible"}, "John 20:28": {"t": "Thomas answered him, “My Lord and my God!”", "tr": "World English Bible"}, "John 21:18-19": {"t": "Most certainly I tell you, when you were young, you dressed yourself, and walked where you wanted to. But when you are old, you will stretch out your hands, and another will dress you, and carry you where you don’t want to go.” Now he said this, signifying by what kind of death he would glorify God. When he had said this, he said to him, “Follow me.”", "tr": "World English Bible"}, "John 21:25": {"t": "There are also many other things which Jesus did, which if they would all be written, I suppose that even the world itself wouldn’t have room for the books that would be written.", "tr": "World English Bible"}, "John 2:1-11": {"t": "The third day, there was a marriage in Cana of Galilee. Jesus’ mother was there. Jesus also was invited, with his disciples, to the marriage. When the wine ran out, Jesus’ mother said to him, “They have no wine.” Jesus said to her, “Woman, what does that have to do with you and me? My hour has not yet come.” His mother said to the servants, “Whatever he says to you, do it.” Now there were six water pots of stone set there after the Jews’ way of purifying, containing two or three metretes apiece. Jesus said to them, “Fill the water pots with water.” They filled them up to the brim. He said to them, “Now draw some out, and take it to the ruler of the feast.” So they took it. When the ruler of [the passage continues in your Bible]", "tr": "World English Bible"}, "John 2:11": {"t": "This beginning of his signs Jesus did in Cana of Galilee, and revealed his glory; and his disciples believed in him.", "tr": "World English Bible"}, "John 2:19-21": {"t": "Jesus answered them, “Destroy this temple, and in three days I will raise it up.” The Jews therefore said, “It took forty-six years to build this temple! Will you raise it up in three days?” But he spoke of the temple of his body.", "tr": "World English Bible"}, "John 2:20": {"t": "The Jews therefore said, “It took forty-six years to build this temple! Will you raise it up in three days?”", "tr": "World English Bible"}, "John 3:16": {"t": "For God so loved the world, that he gave his one and only Son, that whoever believes in him should not perish, but have eternal life.", "tr": "World English Bible"}, "John 4:24": {"t": "God is spirit, and those who worship him must worship in spirit and truth.”", "tr": "World English Bible"}, "John 5:2": {"t": "Now in Jerusalem by the sheep gate, there is a pool, which is called in Hebrew, “Bethesda”, having five porches.", "tr": "World English Bible"}, "John 6:1-14": {"t": "After these things, Jesus went away to the other side of the sea of Galilee, which is also called the Sea of Tiberias. A great multitude followed him, because they saw his signs which he did on those who were sick. Jesus went up into the mountain, and he sat there with his disciples. Now the Passover, the feast of the Jews, was at hand. Jesus therefore lifting up his eyes, and seeing that a great multitude was coming to him, said to Philip, “Where are we to buy bread, that these may eat?” This he said to test him, for he himself knew what he would do. Philip answered him, “Two hundred denarii worth of bread is not sufficient for them, that everyone of them may receive a little.” One of his [the passage continues in your Bible]", "tr": "World English Bible"}, "John 6:16-21": {"t": "When evening came, his disciples went down to the sea, and they entered into the boat, and were going over the sea to Capernaum. It was now dark, and Jesus had not come to them. The sea was tossed by a great wind blowing. When therefore they had rowed about twenty-five or thirty stadia, they saw Jesus walking on the sea, and drawing near to the boat; and they were afraid. But he said to them, “It is I. Don’t be afraid.” They were willing therefore to receive him into the boat. Immediately the boat was at the land where they were going.", "tr": "World English Bible"}, "John 7:24": {"t": "Don’t judge according to appearance, but judge righteous judgment.”", "tr": "World English Bible"}, "John 8:58": {"t": "Jesus said to them, “Most certainly, I tell you, before Abraham came into existence, I AM.”", "tr": "World English Bible"}, "John 9:41": {"t": "Jesus said to them, “If you were blind, you would have no sin; but now you say, ‘We see.’ Therefore your sin remains.", "tr": "World English Bible"}, "Jonah 1:17": {"t": "Yahweh prepared a great fish to swallow up Jonah, and Jonah was in the belly of the fish three days and three nights.", "tr": "World English Bible"}, "Jonah 2:9": {"t": "But I will sacrifice to you with the voice of thanksgiving. I will pay that which I have vowed. Salvation belongs to Yahweh.”", "tr": "World English Bible"}, "Jonah 3:10": {"t": "God saw their works, that they turned from their evil way. God relented of the disaster which he said he would do to them, and he didn’t do it.", "tr": "World English Bible"}, "Jonah 4:11": {"t": "Shouldn’t I be concerned for Nineveh, that great city, in which are more than one hundred twenty thousand persons who can’t discern between their right hand and their left hand; and also much livestock?”", "tr": "World English Bible"}, "Joshua 10-11": {"t": "Now when Adoni-Zedek king of Jerusalem heard how Joshua had taken Ai, and had utterly destroyed it; as he had done to Jericho and her king, so he had done to Ai and her king; and how the inhabitants of Gibeon had made peace with Israel, and were among them; they were very afraid, because Gibeon was a great city, as one of the royal cities, and because it was greater than Ai, and all its men were mighty. Therefore Adoni-Zedek king of Jerusalem sent to Hoham king of Hebron, to Piram king of Jarmuth, to Japhia king of Lachish, and to Debir king of Eglon, saying, “Come up to me, and help me, and let us strike Gibeon; for it has made peace with Joshua and with the children of Israel.” Therefore [the passage continues in your Bible]", "tr": "World English Bible"}, "Joshua 10:12": {"t": "Then Joshua spoke to Yahweh in the day when Yahweh delivered up the Amorites before the children of Israel; and he said in the sight of Israel, “Sun, stand still on Gibeon! You, moon, stop in the valley of Aijalon!”", "tr": "World English Bible"}, "Joshua 1:9": {"t": "Haven’t I commanded you? Be strong and courageous. Don’t be afraid, neither be dismayed: for Yahweh your God is with you wherever you go.”", "tr": "World English Bible"}, "Joshua 21:45": {"t": "Nothing failed of any good thing which Yahweh had spoken to the house of Israel. All came to pass.", "tr": "World English Bible"}, "Joshua 24:15": {"t": "If it seems evil to you to serve Yahweh, choose this day whom you will serve; whether the gods which your fathers served that were beyond the River, or the gods of the Amorites, in whose land you dwell: but as for me and my house, we will serve Yahweh.”", "tr": "World English Bible"}, "Joshua 3:14-17": {"t": "When the people moved from their tents to pass over the Jordan, the priests who bore the ark of the covenant being before the people, and when those who bore the ark had come to the Jordan, and the feet of the priests who bore the ark had dipped in the edge of the water (for the Jordan overflows all its banks all the time of harvest), the waters which came down from above stood, and rose up in one heap, a great way off, at Adam, the city that is beside Zarethan; and those that went down toward the sea of the Arabah, even the Salt Sea, were wholly cut off. Then the people passed over right against Jericho. The priests who bore the ark of the covenant of Yahweh stood firm on dry ground in the [the passage continues in your Bible]", "tr": "World English Bible"}, "Joshua 6:20": {"t": "So the people shouted, and the priests blew the trumpets. When the people heard the sound of the trumpet, the people shouted with a great shout, and the wall fell down flat, so that the people went up into the city, every man straight before him, and they took the city.", "tr": "World English Bible"}, "Jude 1:24-25": {"t": "Now to him who is able to keep them from stumbling, and to present you faultless before the presence of his glory in great joy, to God our Savior, who alone is wise, be glory and majesty, dominion and power, both now and forever. Amen.", "tr": "World English Bible"}, "Jude 1:3": {"t": "Beloved, while I was very eager to write to you about our common salvation, I was constrained to write to you exhorting you to contend earnestly for the faith which was once for all delivered to the saints.", "tr": "World English Bible"}, "Judges 1:27-36": {"t": "Manasseh did not drive out the inhabitants of Beth Shean and its towns, nor Taanach and its towns, nor the inhabitants of Dor and its towns, nor the inhabitants of Ibleam and its towns, nor the inhabitants of Megiddo and its towns; but the Canaanites would dwell in that land. When Israel had grown strong, they put the Canaanites to forced labor, and did not utterly drive them out. Ephraim didn’t drive out the Canaanites who lived in Gezer; but the Canaanites lived in Gezer among them. Zebulun didn’t drive out the inhabitants of Kitron, nor the inhabitants of Nahalol; but the Canaanites lived among them, and became subject to forced labor. Asher didn’t drive out the inhabitants of Acco, nor [the passage continues in your Bible]", "tr": "World English Bible"}, "Judges 21:25": {"t": "In those days there was no king in Israel: every man did that which was right in his own eyes.", "tr": "World English Bible"}, "Judges 2:16": {"t": "Yahweh raised up judges, who saved them out of the hand of those who plundered them.", "tr": "World English Bible"}, "Judges 2:16-19": {"t": "Yahweh raised up judges, who saved them out of the hand of those who plundered them. Yet they didn’t listen to their judges; for they played the prostitute after other gods, and bowed themselves down to them: they turned aside quickly out of the way in which their fathers walked, obeying the commandments of Yahweh. They didn’t do so. When Yahweh raised them up judges, then Yahweh was with the judge, and saved them out of the hand of their enemies all the days of the judge: for it grieved Yahweh because of their groaning by reason of those who oppressed them and troubled them. But when the judge was dead, they turned back, and dealt more corruptly than their fathers, in following other gods [the passage continues in your Bible]", "tr": "World English Bible"}, "Lamentations 1:1": {"t": "How the city sits solitary, that was full of people! She has become as a widow, who was great among the nations! She who was a princess among the provinces has become tributary!", "tr": "World English Bible"}, "Lamentations 1:1-5": {"t": "How the city sits solitary, that was full of people! She has become as a widow, who was great among the nations! She who was a princess among the provinces has become tributary! She weeps bitterly in the night, and her tears are on her cheeks; among all her lovers she has no one to comfort her: All her friends have dealt treacherously with her; they are become her enemies. Judah is gone into captivity because of affliction, and because of great servitude; she dwells among the nations, she finds no rest: all her persecutors overtook her within the straits. The ways of Zion do mourn, because no one come to the solemn assembly; all her gates are desolate, her priests do sigh: her virgins are [the passage continues in your Bible]", "tr": "World English Bible"}, "Lamentations 3:22-23": {"t": "It is because of Yahweh’s loving kindnesses that we are not consumed, because his compassion doesn’t fail. They are new every morning; great is your faithfulness.", "tr": "World English Bible"}, "Leviticus 17:11": {"t": "For the life of the flesh is in the blood; and I have given it to you on the altar to make atonement for your souls: for it is the blood that makes atonement by reason of the life.", "tr": "World English Bible"}, "Leviticus 18:22": {"t": "“‘You shall not lie with a man, as with a woman. That is detestable.", "tr": "World English Bible"}, "Leviticus 19:18": {"t": "“‘You shall not take vengeance, nor bear any grudge against the children of your people; but you shall love your neighbor as yourself. I am Yahweh.", "tr": "World English Bible"}, "Luke 13:34-35": {"t": "“Jerusalem, Jerusalem, that kills the prophets, and stones those who are sent to her! How often I wanted to gather your children together, like a hen gathers her own brood under her wings, and you refused! Behold, your house is left to you desolate. I tell you, you will not see me, until you say, ‘Blessed is he who comes in the name of the Lord!’”", "tr": "World English Bible"}, "Luke 16:19-26": {"t": "“Now there was a certain rich man, and he was clothed in purple and fine linen, living in luxury every day. A certain beggar, named Lazarus, was laid at his gate, full of sores, and desiring to be fed with the crumbs that fell from the rich man’s table. Yes, even the dogs came and licked his sores. The beggar died, and he was carried away by the angels to Abraham’s bosom. The rich man also died, and was buried. In Hades, he lifted up his eyes, being in torment, and saw Abraham far off, and Lazarus at his bosom. He cried and said, ‘Father Abraham, have mercy on me, and send Lazarus, that he may dip the tip of his finger in water, and cool my tongue! For I am in anguish in this flame.’ “But [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 19:10": {"t": "For the Son of Man came to seek and to save that which was lost.”", "tr": "World English Bible"}, "Luke 19:45-48": {"t": "He entered into the temple, and began to drive out those who bought and sold in it, saying to them, “It is written, ‘My house is a house of prayer,’ but you have made it a ‘den of robbers’!” He was teaching daily in the temple, but the chief priests and the scribes and the leading men among the people sought to destroy him. They couldn’t find what they might do, for all the people hung on to every word that he said.", "tr": "World English Bible"}, "Luke 1:1-4": {"t": "Since many have undertaken to set in order a narrative concerning those matters which have been fulfilled among us, even as those who from the beginning were eyewitnesses and servants of the word delivered them to us, it seemed good to me also, having traced the course of all things accurately from the first, to write to you in order, most excellent Theophilus; that you might know the certainty concerning the things in which you were instructed.", "tr": "World English Bible"}, "Luke 22:14-20": {"t": "When the hour had come, he sat down with the twelve apostles. He said to them, “I have earnestly desired to eat this Passover with you before I suffer, for I tell you, I will no longer by any means eat of it until it is fulfilled in the Kingdom of God.” He received a cup, and when he had given thanks, he said, “Take this, and share it among yourselves, for I tell you, I will not drink at all again from the fruit of the vine, until the Kingdom of God comes.” He took bread, and when he had given thanks, he broke it, and gave to them, saying, “This is my body which is given for you. Do this in memory of me.” Likewise, he took the cup after supper, saying, “This cup is the new covenant in my [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 22:27": {"t": "For who is greater, one who sits at the table, or one who serves? Isn’t it he who sits at the table? But I am in your midst as one who serves.", "tr": "World English Bible"}, "Luke 22:39-53": {"t": "He came out, and went, as his custom was, to the Mount of Olives. His disciples also followed him. When he was at the place, he said to them, “Pray that you don’t enter into temptation.” He was withdrawn from them about a stone’s throw, and he knelt down and prayed, saying, “Father, if you are willing, remove this cup from me. Nevertheless, not my will, but yours, be done.” An angel from heaven appeared to him, strengthening him. Being in agony he prayed more earnestly. His sweat became like great drops of blood falling down on the ground. When he rose up from his prayer, he came to the disciples, and found them sleeping because of grief, and said to them, “Why do you sleep? Rise and pray [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 23:1-4": {"t": "The whole company of them rose up and brought him before Pilate. They began to accuse him, saying, “We found this man perverting the nation, forbidding paying taxes to Caesar, and saying that he himself is Christ, a king.” Pilate asked him, “Are you the King of the Jews?” He answered him, “So you say.” Pilate said to the chief priests and the multitudes, “I find no basis for a charge against this man.”", "tr": "World English Bible"}, "Luke 23:26-49": {"t": "When they led him away, they grabbed one Simon of Cyrene, coming from the country, and laid on him the cross, to carry it after Jesus. A great multitude of the people followed him, including women who also mourned and lamented him. But Jesus, turning to them, said, “Daughters of Jerusalem, don’t weep for me, but weep for yourselves and for your children. For behold, the days are coming in which they will say, ‘Blessed are the barren, the wombs that never bore, and the breasts that never nursed.’ Then they will begin to tell the mountains, ‘Fall on us!’ and tell the hills, ‘Cover us.’ For if they do these things in the green tree, what will be done in the dry?” There were also others, two [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 23:34": {"t": "Jesus said, “Father, forgive them, for they don’t know what they are doing.” Dividing his garments among them, they cast lots.", "tr": "World English Bible"}, "Luke 24:1-12": {"t": "But on the first day of the week, at early dawn, they and some others came to the tomb, bringing the spices which they had prepared. They found the stone rolled away from the tomb. They entered in, and didn’t find the Lord Jesus’ body. While they were greatly perplexed about this, behold, two men stood by them in dazzling clothing. Becoming terrified, they bowed their faces down to the earth. They said to them, “Why do you seek the living among the dead? He isn’t here, but is risen. Remember what he told you when he was still in Galilee, saying that the Son of Man must be delivered up into the hands of sinful men, and be crucified, and the third day rise again?” They remembered his words, [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 24:13-35": {"t": "Behold, two of them were going that very day to a village named Emmaus, which was sixty stadia from Jerusalem. They talked with each other about all of these things which had happened. While they talked and questioned together, Jesus himself came near, and went with them. But their eyes were kept from recognizing him. He said to them, “What are you talking about as you walk, and are sad?” One of them, named Cleopas, answered him, “Are you the only stranger in Jerusalem who doesn’t know the things which have happened there in these days?” He said to them, “What things?” They said to him, “The things concerning Jesus, the Nazarene, who was a prophet mighty in deed and word before God and all [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 24:44": {"t": "He said to them, “This is what I told you, while I was still with you, that all things which are written in the law of Moses, the prophets, and the psalms, concerning me must be fulfilled.”", "tr": "World English Bible"}, "Luke 24:50-53": {"t": "He led them out as far as Bethany, and he lifted up his hands, and blessed them. While he blessed them, he withdrew from them, and was carried up into heaven. They worshiped him, and returned to Jerusalem with great joy, and were continually in the temple, praising and blessing God. Amen.", "tr": "World English Bible"}, "Luke 2:1": {"t": "Now in those days, a decree went out from Caesar Augustus that all the world should be enrolled.", "tr": "World English Bible"}, "Luke 2:1-7": {"t": "Now in those days, a decree went out from Caesar Augustus that all the world should be enrolled. This was the first enrollment made when Quirinius was governor of Syria. All went to enroll themselves, everyone to his own city. Joseph also went up from Galilee, out of the city of Nazareth, into Judea, to the city of David, which is called Bethlehem, because he was of the house and family of David; to enroll himself with Mary, who was pledged to be married to him as wife, being pregnant. While they were there, the day had come for her to give birth. She gave birth to her firstborn son. She wrapped him in bands of cloth, and laid him in a feeding trough, because there was no room for them in the inn.", "tr": "World English Bible"}, "Luke 2:11": {"t": "For there is born to you, this day, in the city of David, a Savior, who is Christ the Lord.", "tr": "World English Bible"}, "Luke 2:41-52": {"t": "His parents went every year to Jerusalem at the feast of the Passover. When he was twelve years old, they went up to Jerusalem according to the custom of the feast, and when they had fulfilled the days, as they were returning, the boy Jesus stayed behind in Jerusalem. Joseph and his mother didn’t know it, but supposing him to be in the company, they went a day’s journey, and they looked for him among their relatives and acquaintances. When they didn’t find him, they returned to Jerusalem, looking for him. After three days they found him in the temple, sitting in the midst of the teachers, both listening to them, and asking them questions. All who heard him were amazed at his understanding [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 2:8-20": {"t": "There were shepherds in the same country staying in the field, and keeping watch by night over their flock. Behold, an angel of the Lord stood by them, and the glory of the Lord shone around them, and they were terrified. The angel said to them, “Don’t be afraid, for behold, I bring you good news of great joy which will be to all the people. For there is born to you, this day, in the city of David, a Savior, who is Christ the Lord. This is the sign to you: you will find a baby wrapped in strips of cloth, lying in a feeding trough.” Suddenly, there was with the angel a multitude of the heavenly army praising God, and saying, “Glory to God in the highest, on earth peace, good will toward [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 3:21-22": {"t": "Now when all the people were baptized, Jesus also had been baptized, and was praying. The sky was opened, and the Holy Spirit descended in a bodily form as a dove on him; and a voice came out of the sky, saying “You are my beloved Son. In you I am well pleased.”", "tr": "World English Bible"}, "Luke 3:21-23": {"t": "Now when all the people were baptized, Jesus also had been baptized, and was praying. The sky was opened, and the Holy Spirit descended in a bodily form as a dove on him; and a voice came out of the sky, saying “You are my beloved Son. In you I am well pleased.” Jesus himself, when he began to teach, was about thirty years old, being the son (as was supposed) of Joseph, the son of Heli,", "tr": "World English Bible"}, "Luke 4:1-13": {"t": "Jesus, full of the Holy Spirit, returned from the Jordan, and was led by the Spirit into the wilderness for forty days, being tempted by the devil. He ate nothing in those days. Afterward, when they were completed, he was hungry. The devil said to him, “If you are the Son of God, command this stone to become bread.” Jesus answered him, saying, “It is written, ‘Man shall not live by bread alone, but by every word of God.’” The devil, leading him up on a high mountain, showed him all the kingdoms of the world in a moment of time. The devil said to him, “I will give you all this authority, and their glory, for it has been delivered to me; and I give it to whomever I want. If you therefore will [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 4:40-41": {"t": "When the sun was setting, all those who had any sick with various diseases brought them to him; and he laid his hands on every one of them, and healed them. Demons also came out of many, crying out, and saying, “You are the Christ, the Son of God!” Rebuking them, he didn’t allow them to speak, because they knew that he was the Christ.", "tr": "World English Bible"}, "Luke 5:1-11": {"t": "Now while the multitude pressed on him and heard the word of God, he was standing by the lake of Gennesaret. He saw two boats standing by the lake, but the fishermen had gone out of them, and were washing their nets. He entered into one of the boats, which was Simon’s, and asked him to put out a little from the land. He sat down and taught the multitudes from the boat. When he had finished speaking, he said to Simon, “Put out into the deep, and let down your nets for a catch.” Simon answered him, “Master, we worked all night, and took nothing; but at your word I will let down the net.” When they had done this, they caught a great multitude of fish, and their net was breaking. They beckoned [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 8:1-3": {"t": "Soon afterwards, he went about through cities and villages, preaching and bringing the good news of the Kingdom of God. With him were the twelve, and certain women who had been healed of evil spirits and infirmities: Mary who was called Magdalene, from whom seven demons had gone out; and Joanna, the wife of Chuzas, Herod’s steward; Susanna; and many others; who served them from their possessions.", "tr": "World English Bible"}, "Luke 8:3": {"t": "and Joanna, the wife of Chuzas, Herod’s steward; Susanna; and many others; who served them from their possessions.", "tr": "World English Bible"}, "Luke 9:18-21": {"t": "As he was praying alone, the disciples were with him, and he asked them, “Who do the multitudes say that I am?” They answered, “‘John the Baptizer,’ but others say, ‘Elijah,’ and others, that one of the old prophets is risen again.” He said to them, “But who do you say that I am?” Peter answered, “The Christ of God.” But he warned them, and commanded them to tell this to no one,", "tr": "World English Bible"}, "Luke 9:28-36": {"t": "About eight days after these sayings, he took with him Peter, John, and James, and went up onto the mountain to pray. As he was praying, the appearance of his face was altered, and his clothing became white and dazzling. Behold, two men were talking with him, who were Moses and Elijah, who appeared in glory, and spoke of his departure, which he was about to accomplish at Jerusalem. Now Peter and those who were with him were heavy with sleep, but when they were fully awake, they saw his glory, and the two men who stood with him. As they were parting from him, Peter said to Jesus, “Master, it is good for us to be here. Let’s make three tents: one for you, and one for Moses, and one for [the passage continues in your Bible]", "tr": "World English Bible"}, "Luke 9:36": {"t": "When the voice came, Jesus was found alone. They were silent, and told no one in those days any of the things which they had seen.", "tr": "World English Bible"}, "Malachi 1:6-8": {"t": "“A son honors his father, and a servant his master. If I am a father, then where is my honor? And if I am a master, where is the respect due me? Says Yahweh of Armies to you, priests, who despise my name. You say, ‘How have we despised your name?’ You offer polluted bread on my altar. You say, ‘How have we polluted you?’ In that you say, ‘Yahweh’s table is contemptible.’ When you offer the blind for sacrifice, isn’t that evil? And when you offer the lame and sick, isn’t that evil? Present it now to your governor! Will he be pleased with you? Or will he accept your person?” says Yahweh of Armies.", "tr": "World English Bible"}, "Malachi 3:1": {"t": "“Behold, I send my messenger, and he will prepare the way before me; and the Lord, whom you seek, will suddenly come to his temple; and the messenger of the covenant, whom you desire, behold, he comes!” says Yahweh of Armies.", "tr": "World English Bible"}, "Malachi 3:10": {"t": "Bring the whole tithe into the storehouse, that there may be food in my house, and test me now in this,” says Yahweh of Armies, “if I will not open you the windows of heaven, and pour you out a blessing, that there shall not be room enough for.", "tr": "World English Bible"}, "Malachi 4:2": {"t": "But to you who fear my name shall the sun of righteousness arise with healing in its wings. You will go out, and leap like calves of the stall.", "tr": "World English Bible"}, "Malachi 4:5-6": {"t": "Behold, I will send you Elijah the prophet before the great and terrible day of Yahweh comes. He will turn the hearts of the fathers to the children, and the hearts of the children to their fathers, lest I come and strike the earth with a curse.”", "tr": "World English Bible"}, "Mark 10:45": {"t": "For the Son of Man also came not to be served, but to serve, and to give his life as a ransom for many.”", "tr": "World English Bible"}, "Mark 11:1-11": {"t": "When they drew near to Jerusalem, to Bethsphage and Bethany, at the Mount of Olives, he sent two of his disciples, and said to them, “Go your way into the village that is opposite you. Immediately as you enter into it, you will find a young donkey tied, on which no one has sat. Untie him, and bring him. If anyone asks you, ‘Why are you doing this?’ say, ‘The Lord needs him;’ and immediately he will send him back here.” They went away, and found a young donkey tied at the door outside in the open street, and they untied him. Some of those who stood there asked them, “What are you doing, untying the young donkey?” They said to them just as Jesus had said, and they let them go. They brought [the passage continues in your Bible]", "tr": "World English Bible"}, "Mark 11:15-18": {"t": "They came to Jerusalem, and Jesus entered into the temple, and began to throw out those who sold and those who bought in the temple, and overthrew the tables of the money changers, and the seats of those who sold the doves. He would not allow anyone to carry a container through the temple. He taught, saying to them, “Isn’t it written, ‘My house will be called a house of prayer for all the nations?’ But you have made it a den of robbers!” The chief priests and the scribes heard it, and sought how they might destroy him. For they feared him, because all the multitude was astonished at his teaching.", "tr": "World English Bible"}, "Mark 14:32-50": {"t": "They came to a place which was named Gethsemane. He said to his disciples, “Sit here, while I pray.” He took with him Peter, James, and John, and began to be greatly troubled and distressed. He said to them, “My soul is exceedingly sorrowful, even to death. Stay here, and watch.” He went forward a little, and fell on the ground, and prayed that, if it were possible, the hour might pass away from him. He said, “Abba, Father, all things are possible to you. Please remove this cup from me. However, not what I desire, but what you desire.” He came and found them sleeping, and said to Peter, “Simon, are you sleeping? Couldn’t you watch one hour? Watch and pray, that you may not enter into [the passage continues in your Bible]", "tr": "World English Bible"}, "Mark 14:53-15:15": {"t": "They led Jesus away to the high priest. All the chief priests, the elders, and the scribes came together with him. Peter had followed him from a distance, until he came into the court of the high priest. He was sitting with the officers, and warming himself in the light of the fire. Now the chief priests and the whole council sought witnesses against Jesus to put him to death, and found none. For many gave false testimony against him, and their testimony didn’t agree with each other. Some stood up, and gave false testimony against him, saying, “We heard him say, ‘I will destroy this temple that is made with hands, and in three days I will build another made without hands.’” Even so, their [the passage continues in your Bible]", "tr": "World English Bible"}, "Mark 14:62": {"t": "Jesus said, “I am. You will see the Son of Man sitting at the right hand of Power, and coming with the clouds of the sky.”", "tr": "World English Bible"}, "Mark 15:21-41": {"t": "They compelled one passing by, coming from the country, Simon of Cyrene, the father of Alexander and Rufus, to go with them, that he might bear his cross. They brought him to the place called Golgotha, which is, being interpreted, “The place of a skull.” They offered him wine mixed with myrrh to drink, but he didn’t take it. Crucifying him, they parted his garments among them, casting lots on them, what each should take. It was the third hour, and they crucified him. The superscription of his accusation was written over him, “THE KING OF THE JEWS.” With him they crucified two robbers; one on his right hand, and one on his left. The Scripture was fulfilled, which says, “He was numbered with [the passage continues in your Bible]", "tr": "World English Bible"}, "Mark 15:42-47": {"t": "When evening had now come, because it was the Preparation Day, that is, the day before the Sabbath, Joseph of Arimathaea, a prominent council member who also himself was looking for the Kingdom of God, came. He boldly went in to Pilate, and asked for Jesus’ body. Pilate marveled if he were already dead; and summoning the centurion, he asked him whether he had been dead long. When he found out from the centurion, he granted the body to Joseph. He bought a linen cloth, and taking him down, wound him in the linen cloth, and laid him in a tomb which had been cut out of a rock. He rolled a stone against the door of the tomb. Mary Magdalene and Mary, the mother of Joses, saw where he was laid.", "tr": "World English Bible"}, "Mark 16:1-8": {"t": "When the Sabbath was past, Mary Magdalene, and Mary the mother of James, and Salome, bought spices, that they might come and anoint him. Very early on the first day of the week, they came to the tomb when the sun had risen. They were saying among themselves, “Who will roll away the stone from the door of the tomb for us?” for it was very big. Looking up, they saw that the stone was rolled back. Entering into the tomb, they saw a young man sitting on the right side, dressed in a white robe, and they were amazed. He said to them, “Don’t be amazed. You seek Jesus, the Nazarene, who has been crucified. He has risen. He is not here. Behold, the place where they laid him! But go, tell his [the passage continues in your Bible]", "tr": "World English Bible"}, "Mark 16:15": {"t": "He said to them, “Go into all the world, and preach the Good News to the whole creation.", "tr": "World English Bible"}, "Mark 1:15": {"t": "and saying, “The time is fulfilled, and the Kingdom of God is at hand! Repent, and believe in the Good News.”", "tr": "World English Bible"}, "Mark 1:16-20": {"t": "Passing along by the sea of Galilee, he saw Simon and Andrew the brother of Simon casting a net into the sea, for they were fishermen. Jesus said to them, “Come after me, and I will make you into fishers for men.” Immediately they left their nets, and followed him. Going on a little further from there, he saw James the son of Zebedee, and John, his brother, who were also in the boat mending the nets. Immediately he called them, and they left their father, Zebedee, in the boat with the hired servants, and went after him.", "tr": "World English Bible"}, "Mark 1:32-34": {"t": "At evening, when the sun had set, they brought to him all who were sick, and those who were possessed by demons. All the city was gathered together at the door. He healed many who were sick with various diseases, and cast out many demons. He didn’t allow the demons to speak, because they knew him.", "tr": "World English Bible"}, "Mark 1:9-11": {"t": "In those days, Jesus came from Nazareth of Galilee, and was baptized by John in the Jordan. Immediately coming up from the water, he saw the heavens parting, and the Spirit descending on him like a dove. A voice came out of the sky, “You are my beloved Son, in whom I am well pleased.”", "tr": "World English Bible"}, "Mark 2:5-7": {"t": "Jesus, seeing their faith, said to the paralytic, “Son, your sins are forgiven you.” But there were some of the scribes sitting there, and reasoning in their hearts, “Why does this man speak blasphemies like that? Who can forgive sins but God alone?”", "tr": "World English Bible"}, "Mark 6:30-44": {"t": "The apostles gathered themselves together to Jesus, and they told him all things, whatever they had done, and whatever they had taught. He said to them, “You come apart into a deserted place, and rest awhile.” For there were many coming and going, and they had no leisure so much as to eat. They went away in the boat to a deserted place by themselves. They saw them going, and many recognized him and ran there on foot from all the cities. They arrived before them and came together to him. Jesus came out, saw a great multitude, and he had compassion on them, because they were like sheep without a shepherd, and he began to teach them many things. When it was late in the day, his disciples came [the passage continues in your Bible]", "tr": "World English Bible"}, "Mark 6:45-52": {"t": "Immediately he made his disciples get into the boat, and to go ahead to the other side, to Bethsaida, while he himself sent the multitude away. After he had taken leave of them, he went up the mountain to pray. When evening had come, the boat was in the midst of the sea, and he was alone on the land. Seeing them distressed in rowing, for the wind was contrary to them, about the fourth watch of the night he came to them, walking on the sea, and he would have passed by them, but they, when they saw him walking on the sea, supposed that it was a ghost, and cried out; for they all saw him, and were troubled. But he immediately spoke with them, and said to them, “Cheer up! It is I! Don’t be [the passage continues in your Bible]", "tr": "World English Bible"}, "Mark 8:27-30": {"t": "Jesus went out, with his disciples, into the villages of Caesarea Philippi. On the way he asked his disciples, “Who do men say that I am?” They told him, “John the Baptizer, and others say Elijah, but others: one of the prophets.” He said to them, “But who do you say that I am?” Peter answered, “You are the Christ.” He commanded them that they should tell no one about him.", "tr": "World English Bible"}, "Mark 9:2-8": {"t": "After six days Jesus took with him Peter, James, and John, and brought them up onto a high mountain privately by themselves, and he was changed into another form in front of them. His clothing became glistening, exceedingly white, like snow, such as no launderer on earth can whiten them. Elijah and Moses appeared to them, and they were talking with Jesus. Peter answered Jesus, “Rabbi, it is good for us to be here. Let’s make three tents: one for you, one for Moses, and one for Elijah.” For he didn’t know what to say, for they were very afraid. A cloud came, overshadowing them, and a voice came out of the cloud, “This is my beloved Son. Listen to him.” Suddenly looking around, they saw no [the passage continues in your Bible]", "tr": "World English Bible"}, "Mark 9:9": {"t": "As they were coming down from the mountain, he commanded them that they should tell no one what things they had seen, until after the Son of Man had risen from the dead.", "tr": "World English Bible"}, "Matthew 10:14": {"t": "Whoever doesn’t receive you, nor hear your words, as you go out of that house or that city, shake off the dust from your feet.", "tr": "World English Bible"}, "Matthew 11:21": {"t": "“Woe to you, Chorazin! Woe to you, Bethsaida! For if the mighty works had been done in Tyre and Sidon which were done in you, they would have repented long ago in sackcloth and ashes.", "tr": "World English Bible"}, "Matthew 11:27": {"t": "All things have been delivered to me by my Father. No one knows the Son, except the Father; neither does anyone know the Father, except the Son, and he to whom the Son desires to reveal him.", "tr": "World English Bible"}, "Matthew 11:27-29": {"t": "All things have been delivered to me by my Father. No one knows the Son, except the Father; neither does anyone know the Father, except the Son, and he to whom the Son desires to reveal him. “Come to me, all you who labor and are heavily burdened, and I will give you rest. Take my yoke upon you, and learn from me, for I am gentle and lowly in heart; and you will find rest for your souls.", "tr": "World English Bible"}, "Matthew 11:28": {"t": "“Come to me, all you who labor and are heavily burdened, and I will give you rest.", "tr": "World English Bible"}, "Matthew 14:1-2": {"t": "At that time, Herod the tetrarch heard the report concerning Jesus, and said to his servants, “This is John the Baptizer. He is risen from the dead. That is why these powers work in him.”", "tr": "World English Bible"}, "Matthew 14:13-21": {"t": "Now when Jesus heard this, he withdrew from there in a boat, to a deserted place apart. When the multitudes heard it, they followed him on foot from the cities. Jesus went out, and he saw a great multitude. He had compassion on them, and healed their sick. When evening had come, his disciples came to him, saying, “This place is deserted, and the hour is already late. Send the multitudes away, that they may go into the villages, and buy themselves food.” But Jesus said to them, “They don’t need to go away. You give them something to eat.” They told him, “We only have here five loaves and two fish.” He said, “Bring them here to me.” He commanded the multitudes to sit down on the grass; and he [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 14:22-33": {"t": "Immediately Jesus made the disciples get into the boat, and to go ahead of him to the other side, while he sent the multitudes away. After he had sent the multitudes away, he went up into the mountain by himself to pray. When evening had come, he was there alone. But the boat was now in the middle of the sea, distressed by the waves, for the wind was contrary. In the fourth watch of the night, Jesus came to them, walking on the sea. When the disciples saw him walking on the sea, they were troubled, saying, “It’s a ghost!” and they cried out for fear. But immediately Jesus spoke to them, saying “Cheer up! It is I! Don’t be afraid.” Peter answered him and said, “Lord, if it is you, command me [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 16:13-20": {"t": "Now when Jesus came into the parts of Caesarea Philippi, he asked his disciples, saying, “Who do men say that I, the Son of Man, am?” They said, “Some say John the Baptizer, some, Elijah, and others, Jeremiah, or one of the prophets.” He said to them, “But who do you say that I am?” Simon Peter answered, “You are the Christ, the Son of the living God.” Jesus answered him, “Blessed are you, Simon Bar Jonah, for flesh and blood has not revealed this to you, but my Father who is in heaven. I also tell you that you are Peter,and on this rock I will build my assembly, and the gates of Hadeswill not prevail against it. I will give to you the keys of the Kingdom of Heaven, and whatever you bind on [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 16:18-19": {"t": "I also tell you that you are Peter,and on this rock I will build my assembly, and the gates of Hadeswill not prevail against it. I will give to you the keys of the Kingdom of Heaven, and whatever you bind on earth will have been bound in heaven; and whatever you release on earth will have been released in heaven.”", "tr": "World English Bible"}, "Matthew 16:25": {"t": "For whoever desires to save his life will lose it, and whoever will lose his life for my sake will find it.", "tr": "World English Bible"}, "Matthew 17:1-9": {"t": "After six days, Jesus took with him Peter, James, and John his brother, and brought them up into a high mountain by themselves. He was transfigured before them. His face shone like the sun, and his garments became as white as the light. Behold, Moses and Elijah appeared to them talking with him. Peter answered, and said to Jesus, “Lord, it is good for us to be here. If you want, let’s make three tents here: one for you, one for Moses, and one for Elijah.” While he was still speaking, behold, a bright cloud overshadowed them. Behold, a voice came out of the cloud, saying, “This is my beloved Son, in whom I am well pleased. Listen to him.” When the disciples heard it, they fell on their [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 19:21": {"t": "Jesus said to him, “If you want to be perfect, go, sell what you have, and give to the poor, and you will have treasure in heaven; and come, follow me.”", "tr": "World English Bible"}, "Matthew 19:4-5": {"t": "He answered, “Haven’t you read that he who made them from the beginning made them male and female, and said, ‘For this cause a man shall leave his father and mother, and shall join to his wife; and the two shall become one flesh?’", "tr": "World English Bible"}, "Matthew 19:4-6": {"t": "He answered, “Haven’t you read that he who made them from the beginning made them male and female, and said, ‘For this cause a man shall leave his father and mother, and shall join to his wife; and the two shall become one flesh?’ So that they are no more two, but one flesh. What therefore God has joined together, don’t let man tear apart.”", "tr": "World English Bible"}, "Matthew 1:11-12": {"t": "Josiah became the father of Jechoniah and his brothers, at the time of the exile to Babylon. After the exile to Babylon, Jechoniah became the father of Shealtiel. Shealtiel became the father of Zerubbabel.", "tr": "World English Bible"}, "Matthew 1:12-13": {"t": "After the exile to Babylon, Jechoniah became the father of Shealtiel. Shealtiel became the father of Zerubbabel. Zerubbabel became the father of Abiud. Abiud became the father of Eliakim. Eliakim became the father of Azor.", "tr": "World English Bible"}, "Matthew 1:18-19": {"t": "Now the birth of Jesus Christ was like this; for after his mother, Mary, was engaged to Joseph, before they came together, she was found pregnant by the Holy Spirit. Joseph, her husband, being a righteous man, and not willing to make her a public example, intended to put her away secretly.", "tr": "World English Bible"}, "Matthew 1:18-25": {"t": "Now the birth of Jesus Christ was like this; for after his mother, Mary, was engaged to Joseph, before they came together, she was found pregnant by the Holy Spirit. Joseph, her husband, being a righteous man, and not willing to make her a public example, intended to put her away secretly. But when he thought about these things, behold, an angel of the Lord appeared to him in a dream, saying, “Joseph, son of David, don’t be afraid to take to yourself Mary, your wife, for that which is conceived in her is of the Holy Spirit. She shall give birth to a son. You shall call his name Jesus, for it is he who shall save his people from their sins.” Now all this has happened, that it might be [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 1:23": {"t": "“Behold, the virgin shall be with child, and shall give birth to a son. They shall call his name Immanuel”; which is, being interpreted, “God with us.”", "tr": "World English Bible"}, "Matthew 21:1-11": {"t": "When they drew near to Jerusalem, and came to Bethsphage, to the Mount of Olives, then Jesus sent two disciples, saying to them, “Go into the village that is opposite you, and immediately you will find a donkey tied, and a colt with her. Untie them, and bring them to me. If anyone says anything to you, you shall say, ‘The Lord needs them,’ and immediately he will send them.” All this was done, that it might be fulfilled which was spoken through the prophet, saying, “Tell the daughter of Zion, behold, your King comes to you, humble, and riding on a donkey, on a colt, the foal of a donkey.” The disciples went, and did just as Jesus commanded them, and brought the donkey and the colt, and laid [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 21:12-17": {"t": "Jesus entered into the temple of God, and drove out all of those who sold and bought in the temple, and overthrew the money changers’ tables and the seats of those who sold the doves. He said to them, “It is written, ‘My house shall be called a house of prayer,’but you have made it a den of robbers!” The blind and the lame came to him in the temple, and he healed them. But when the chief priests and the scribes saw the wonderful things that he did, and the children who were crying in the temple and saying, “Hosanna to the son of David!” they were indignant, and said to him, “Do you hear what these are saying?” Jesus said to them, “Yes. Did you never read, ‘Out of the mouth of babes and [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 23:27": {"t": "“Woe to you, scribes and Pharisees, hypocrites! For you are like whitened tombs, which outwardly appear beautiful, but inwardly are full of dead men’s bones, and of all uncleanness.", "tr": "World English Bible"}, "Matthew 23:37": {"t": "“Jerusalem, Jerusalem, who kills the prophets, and stones those who are sent to her! How often I would have gathered your children together, even as a hen gathers her chicks under her wings, and you would not!", "tr": "World English Bible"}, "Matthew 24:2": {"t": "But he answered them, “You see all of these things, don’t you? Most certainly I tell you, there will not be left here one stone on another, that will not be thrown down.”", "tr": "World English Bible"}, "Matthew 25:36": {"t": "I was naked, and you clothed me. I was sick, and you visited me. I was in prison, and you came to me.’", "tr": "World English Bible"}, "Matthew 26:26-29": {"t": "As they were eating, Jesus took bread, gave thanks for it, and broke it. He gave to the disciples, and said, “Take, eat; this is my body.” He took the cup, gave thanks, and gave to them, saying, “All of you drink it, for this is my blood of the new covenant, which is poured out for many for the remission of sins. But I tell you that I will not drink of this fruit of the vine from now on, until that day when I drink it anew with you in my Father’s Kingdom.”", "tr": "World English Bible"}, "Matthew 26:36-56": {"t": "Then Jesus came with them to a place called Gethsemane, and said to his disciples, “Sit here, while I go there and pray.” He took with him Peter and the two sons of Zebedee, and began to be sorrowful and severely troubled. Then he said to them, “My soul is exceedingly sorrowful, even to death. Stay here, and watch with me.” He went forward a little, fell on his face, and prayed, saying, “My Father, if it is possible, let this cup pass away from me; nevertheless, not what I desire, but what you desire.” He came to the disciples, and found them sleeping, and said to Peter, “What, couldn’t you watch with me for one hour? Watch and pray, that you don’t enter into temptation. The spirit indeed [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 26:57-27:26": {"t": "Those who had taken Jesus led him away to Caiaphas the high priest, where the scribes and the elders were gathered together. But Peter followed him from a distance, to the court of the high priest, and entered in and sat with the officers, to see the end. Now the chief priests, the elders, and the whole council sought false testimony against Jesus, that they might put him to death; and they found none. Even though many false witnesses came forward, they found none. But at last two false witnesses came forward, and said, “This man said, ‘I am able to destroy the temple of God, and to build it in three days.’” The high priest stood up, and said to him, “Have you no answer? What is this that [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 27:32-56": {"t": "As they came out, they found a man of Cyrene, Simon by name, and they compelled him to go with them, that he might carry his cross. They came to a place called “Golgotha”, that is to say, “The place of a skull.” They gave him sour wine to drink mixed with gall. When he had tasted it, he would not drink. When they had crucified him, they divided his clothing among them, casting lots, and they sat and watched him there. They set up over his head the accusation against him written, “THIS IS JESUS, THE KING OF THE JEWS.” Then there were two robbers crucified with him, one on his right hand and one on the left. Those who passed by blasphemed him, wagging their heads, and saying, “You who destroy [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 27:55": {"t": "Many women were there watching from afar, who had followed Jesus from Galilee, serving him.", "tr": "World English Bible"}, "Matthew 27:57-66": {"t": "When evening had come, a rich man from Arimathaea, named Joseph, who himself was also Jesus’ disciple came. This man went to Pilate, and asked for Jesus’ body. Then Pilate commanded the body to be given up. Joseph took the body, and wrapped it in a clean linen cloth, and laid it in his own new tomb, which he had cut out in the rock, and he rolled a great stone to the door of the tomb, and departed. Mary Magdalene was there, and the other Mary, sitting opposite the tomb. Now on the next day, which was the day after the Preparation Day, the chief priests and the Pharisees were gathered together to Pilate, saying, “Sir, we remember what that deceiver said while he was still alive: ‘After three [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 28:1-10": {"t": "Now after the Sabbath, as it began to dawn on the first day of the week, Mary Magdalene and the other Mary came to see the tomb. Behold, there was a great earthquake, for an angel of the Lord descended from the sky, and came and rolled away the stone from the door, and sat on it. His appearance was like lightning, and his clothing white as snow. For fear of him, the guards shook, and became like dead men. The angel answered the women, “Don’t be afraid, for I know that you seek Jesus, who has been crucified. He is not here, for he has risen, just like he said. Come, see the place where the Lord was lying. Go quickly and tell his disciples, ‘He has risen from the dead, and behold, he goes [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 28:1-7": {"t": "Now after the Sabbath, as it began to dawn on the first day of the week, Mary Magdalene and the other Mary came to see the tomb. Behold, there was a great earthquake, for an angel of the Lord descended from the sky, and came and rolled away the stone from the door, and sat on it. His appearance was like lightning, and his clothing white as snow. For fear of him, the guards shook, and became like dead men. The angel answered the women, “Don’t be afraid, for I know that you seek Jesus, who has been crucified. He is not here, for he has risen, just like he said. Come, see the place where the Lord was lying. Go quickly and tell his disciples, ‘He has risen from the dead, and behold, he goes [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 28:16-20": {"t": "But the eleven disciples went into Galilee, to the mountain where Jesus had sent them. When they saw him, they bowed down to him, but some doubted. Jesus came to them and spoke to them, saying, “All authority has been given to me in heaven and on earth. Go,and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit, teaching them to observe all things that I commanded you. Behold, I am with you always, even to the end of the age.” Amen.", "tr": "World English Bible"}, "Matthew 28:19": {"t": "Go,and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit,", "tr": "World English Bible"}, "Matthew 28:19-20": {"t": "Go,and make disciples of all nations, baptizing them in the name of the Father and of the Son and of the Holy Spirit, teaching them to observe all things that I commanded you. Behold, I am with you always, even to the end of the age.” Amen.", "tr": "World English Bible"}, "Matthew 2:1": {"t": "Now when Jesus was born in Bethlehem of Judea in the days of King Herod, behold, wise men from the east came to Jerusalem, saying,", "tr": "World English Bible"}, "Matthew 2:1-12": {"t": "Now when Jesus was born in Bethlehem of Judea in the days of King Herod, behold, wise men from the east came to Jerusalem, saying, “Where is he who is born King of the Jews? For we saw his star in the east, and have come to worship him.” When King Herod heard it, he was troubled, and all Jerusalem with him. Gathering together all the chief priests and scribes of the people, he asked them where the Christ would be born. They said to him, “In Bethlehem of Judea, for this is written through the prophet, ‘You Bethlehem, land of Judah, are in no way least among the princes of Judah: for out of you shall come a governor, who shall shepherd my people, Israel.’” Then Herod secretly called the wise [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 2:13-23": {"t": "Now when they had departed, behold, an angel of the Lord appeared to Joseph in a dream, saying, “Arise and take the young child and his mother, and flee into Egypt, and stay there until I tell you, for Herod will seek the young child to destroy him.” He arose and took the young child and his mother by night, and departed into Egypt, and was there until the death of Herod; that it might be fulfilled which was spoken by the Lord through the prophet, saying, “Out of Egypt I called my son.” Then Herod, when he saw that he was mocked by the wise men, was exceedingly angry, and sent out, and killed all the male children who were in Bethlehem and in all the surrounding countryside, from two years [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 3:13-17": {"t": "Then Jesus came from Galilee to the Jordan to John, to be baptized by him. But John would have hindered him, saying, “I need to be baptized by you, and you come to me?” But Jesus, answering, said to him, “Allow it now, for this is the fitting way for us to fulfill all righteousness.” Then he allowed him. Jesus, when he was baptized, went up directly from the water: and behold, the heavens were opened to him. He saw the Spirit of God descending as a dove, and coming on him. Behold, a voice out of the heavens said, “This is my beloved Son, with whom I am well pleased.”", "tr": "World English Bible"}, "Matthew 3:16-17": {"t": "Jesus, when he was baptized, went up directly from the water: and behold, the heavens were opened to him. He saw the Spirit of God descending as a dove, and coming on him. Behold, a voice out of the heavens said, “This is my beloved Son, with whom I am well pleased.”", "tr": "World English Bible"}, "Matthew 4:1-11": {"t": "Then Jesus was led up by the Spirit into the wilderness to be tempted by the devil. When he had fasted forty days and forty nights, he was hungry afterward. The tempter came and said to him, “If you are the Son of God, command that these stones become bread.” But he answered, “It is written, ‘Man shall not live by bread alone, but by every word that proceeds out of the mouth of God.’” Then the devil took him into the holy city. He set him on the pinnacle of the temple, and said to him, “If you are the Son of God, throw yourself down, for it is written, ‘He will put his angels in charge of you.’ and, ‘On their hands they will bear you up, so that you don’t dash your foot against a stone.’” [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 4:18-22": {"t": "Walking by the sea of Galilee, he saw two brothers: Simon, who is called Peter, and Andrew, his brother, casting a net into the sea; for they were fishermen. He said to them, “Come after me, and I will make you fishers for men.” They immediately left their nets and followed him. Going on from there, he saw two other brothers, James the son of Zebedee, and John his brother, in the boat with Zebedee their father, mending their nets. He called them. They immediately left the boat and their father, and followed him.", "tr": "World English Bible"}, "Matthew 5:1-12": {"t": "Seeing the multitudes, he went up onto the mountain. When he had sat down, his disciples came to him. He opened his mouth and taught them, saying, “Blessed are the poor in spirit, for theirs is the Kingdom of Heaven. Blessed are those who mourn, for they shall be comforted. Blessed are the gentle, for they shall inherit the earth. Blessed are those who hunger and thirst after righteousness, for they shall be filled. Blessed are the merciful, for they shall obtain mercy. Blessed are the pure in heart, for they shall see God. Blessed are the peacemakers, for they shall be called children of God. Blessed are those who have been persecuted for righteousness’ sake, for theirs is the Kingdom of [the passage continues in your Bible]", "tr": "World English Bible"}, "Matthew 5:17": {"t": "“Don’t think that I came to destroy the law or the prophets. I didn’t come to destroy, but to fulfill.", "tr": "World English Bible"}, "Matthew 6:7": {"t": "In praying, don’t use vain repetitions, as the Gentiles do; for they think that they will be heard for their much speaking.", "tr": "World English Bible"}, "Matthew 6:9-13": {"t": "Pray like this: ‘Our Father in heaven, may your name be kept holy. Let your Kingdom come. Let your will be done, as in heaven, so on earth. Give us today our daily bread. Forgive us our debts, as we also forgive our debtors. Bring us not into temptation, but deliver us from the evil one. For yours is the Kingdom, the power, and the glory forever. Amen. ’", "tr": "World English Bible"}, "Matthew 7:1": {"t": "“Don’t judge, so that you won’t be judged.", "tr": "World English Bible"}, "Matthew 7:12": {"t": "Therefore whatever you desire for men to do to you, you shall also do to them; for this is the law and the prophets.", "tr": "World English Bible"}, "Matthew 7:24-27": {"t": "“Everyone therefore who hears these words of mine, and does them, I will liken him to a wise man, who built his house on a rock. The rain came down, the floods came, and the winds blew, and beat on that house; and it didn’t fall, for it was founded on the rock. Everyone who hears these words of mine, and doesn’t do them will be like a foolish man, who built his house on the sand. The rain came down, the floods came, and the winds blew, and beat on that house; and it fell—and great was its fall.”", "tr": "World English Bible"}, "Matthew 7:5": {"t": "You hypocrite! First remove the beam out of your own eye, and then you can see clearly to remove the speck out of your brother’s eye.", "tr": "World English Bible"}, "Matthew 7:6": {"t": "“Don’t give that which is holy to the dogs, neither throw your pearls before the pigs, lest perhaps they trample them under their feet, and turn and tear you to pieces.", "tr": "World English Bible"}, "Matthew 7:7": {"t": "“Ask, and it will be given you. Seek, and you will find. Knock, and it will be opened for you.", "tr": "World English Bible"}, "Matthew 9:35": {"t": "Jesus went about all the cities and the villages, teaching in their synagogues, and preaching the Good News of the Kingdom, and healing every disease and every sickness among the people.", "tr": "World English Bible"}, "Micah 1:1": {"t": "Yahweh’s word that came to Micah the Morashtite in the days of Jotham, Ahaz, and Hezekiah, kings of Judah, which he saw concerning Samaria and Jerusalem.", "tr": "World English Bible"}, "Micah 3:11-12": {"t": "Her leaders judge for bribes, and her priests teach for a price, and her prophets of it tell fortunes for money: yet they lean on Yahweh, and say, “Isn’t Yahweh in the midst of us? No disaster will come on us.” Therefore Zion for your sake will be plowed like a field, and Jerusalem will become heaps of rubble, and the mountain of the temple like the high places of a forest.", "tr": "World English Bible"}, "Micah 5:2": {"t": "But you, Bethlehem Ephrathah, being small among the clans of Judah, out of you one will come out to me that is to be ruler in Israel; whose goings out are from of old, from ancient times.", "tr": "World English Bible"}, "Micah 6:8": {"t": "He has shown you, O man, what is good. What does Yahweh require of you, but to act justly, to love mercy, and to walk humbly with your God?", "tr": "World English Bible"}, "Nahum 1:1": {"t": "An oracle about Nineveh. The book of the vision of Nahum the Elkoshite.", "tr": "World English Bible"}, "Nahum 1:3": {"t": "Yahweh is slow to anger, and great in power, and will by no means leave the guilty unpunished. Yahweh has his way in the whirlwind and in the storm, and the clouds are the dust of his feet.", "tr": "World English Bible"}, "Nahum 1:7": {"t": "Yahweh is good, a stronghold in the day of trouble; and he knows those who take refuge in him.", "tr": "World English Bible"}, "Nahum 3:1": {"t": "Woe to the bloody city! It is all full of lies and robbery. The prey doesn’t depart.", "tr": "World English Bible"}, "Nehemiah 2:1": {"t": "In the month Nisan, in the twentieth year of Artaxerxes the king, when wine was before him, I took up the wine, and gave it to the king. Now I had not been sad before in his presence.", "tr": "World English Bible"}, "Nehemiah 2:5-8": {"t": "I said to the king, “If it pleases the king, and if your servant has found favor in your sight, that you would send me to Judah, to the city of my fathers’ tombs, that I may build it.” The king said to me (the queen was also sitting by him), “For how long shall your journey be? And when will you return?” So it pleased the king to send me; and I set him a time. Moreover I said to the king, “If it pleases the king, let letters be given me to the governors beyond the River, that they may let me pass through until I come to Judah; and a letter to Asaph the keeper of the king’s forest, that he may give me timber to make beams for the gates of the citadel by the temple, for the wall of the city, [the passage continues in your Bible]", "tr": "World English Bible"}, "Nehemiah 6:15": {"t": "So the wall was finished in the twenty-fifth day of Elul, in fifty-two days.", "tr": "World English Bible"}, "Nehemiah 6:15-16": {"t": "So the wall was finished in the twenty-fifth day of Elul, in fifty-two days. When all our enemies heard of it, all the nations that were around us were afraid, and were much cast down in their own eyes; for they perceived that this work was worked of our God.", "tr": "World English Bible"}, "Nehemiah 8:10": {"t": "Then he said to them, “Go your way. Eat the fat, drink the sweet, and send portions to him for whom nothing is prepared; for this day is holy to our Lord. Don’t be grieved; for the joy of Yahweh is your strength.”", "tr": "World English Bible"}, "Nehemiah 8:8": {"t": "They read in the book, in the law of God, distinctly; and they gave the sense, so that they understood the reading.", "tr": "World English Bible"}, "Nehemiah 9:1-3": {"t": "Now in the twenty-fourth day of this month the children of Israel were assembled with fasting, and with sackcloth, and earth on them. The seed of Israel separated themselves from all foreigners, and stood and confessed their sins, and the iniquities of their fathers. They stood up in their place, and read in the book of the law of Yahweh their God a fourth part of the day; and a fourth part they confessed, and worshiped Yahweh their God.", "tr": "World English Bible"}, "Numbers 14:18": {"t": "‘Yahweh is slow to anger, and abundant in loving kindness, forgiving iniquity and disobedience; and that will by no means clear the guilty, visiting the iniquity of the fathers on the children, on the third and on the fourth generation.’", "tr": "World English Bible"}, "Numbers 6:24-26": {"t": "‘Yahweh bless you, and keep you. Yahweh make his face to shine on you, and be gracious to you. Yahweh lift up his face toward you, and give you peace.’", "tr": "World English Bible"}, "Obadiah 1:10-14": {"t": "For the violence done to your brother Jacob, shame will cover you, and you will be cut off forever. In the day that you stood on the other side, in the day that strangers carried away his substance, and foreigners entered into his gates, and cast lots for Jerusalem, even you were like one of them. But don’t look down on your brother in the day of his disaster, and don’t rejoice over the children of Judah in the day of their destruction. Don’t speak proudly in the day of distress. Don’t enter into the gate of my people in the day of their calamity. Don’t look down on their affliction in the day of their calamity, neither seize their wealth on the day of their calamity. Don’t stand in the [the passage continues in your Bible]", "tr": "World English Bible"}, "Obadiah 1:15": {"t": "For the day of Yahweh is near all the nations! As you have done, it will be done to you. Your deeds will return upon your own head.", "tr": "World English Bible"}, "Obadiah 1:21": {"t": "Saviors will go up on Mount Zion to judge the mountains of Esau, and the kingdom will be Yahweh’s.", "tr": "World English Bible"}, "Obadiah 1:3-4": {"t": "The pride of your heart has deceived you, you who dwell in the clefts of the rock, whose habitation is high, who says in his heart, ‘Who will bring me down to the ground?’ Though you mount on high as the eagle, and though your nest is set among the stars, I will bring you down from there,” says Yahweh.", "tr": "World English Bible"}, "Obadiah 1:4": {"t": "Though you mount on high as the eagle, and though your nest is set among the stars, I will bring you down from there,” says Yahweh.", "tr": "World English Bible"}, "Philemon 16": {"t": "no longer as a slave, but more than a slave, a beloved brother, especially to me, but how much rather to you, both in the flesh and in the Lord.", "tr": "World English Bible"}, "Philemon 1:16": {"t": "no longer as a slave, but more than a slave, a beloved brother, especially to me, but how much rather to you, both in the flesh and in the Lord.", "tr": "World English Bible"}, "Philemon 1:6": {"t": "that the fellowship of your faith may become effective, in the knowledge of every good thing which is in us in Christ Jesus.", "tr": "World English Bible"}, "Philippians 2:5-7": {"t": "Have this in your mind, which was also in Christ Jesus, who, existing in the form of God, didn’t consider equality with God a thing to be grasped, but emptied himself, taking the form of a servant, being made in the likeness of men.", "tr": "World English Bible"}, "Philippians 2:6-8": {"t": "who, existing in the form of God, didn’t consider equality with God a thing to be grasped, but emptied himself, taking the form of a servant, being made in the likeness of men. And being found in human form, he humbled himself, becoming obedient to death, yes, the death of the cross.", "tr": "World English Bible"}, "Philippians 2:7": {"t": "but emptied himself, taking the form of a servant, being made in the likeness of men.", "tr": "World English Bible"}, "Philippians 4:13": {"t": "I can do all things through Christ, who strengthens me.", "tr": "World English Bible"}, "Philippians 4:3": {"t": "Yes, I beg you also, true partner, help these women, for they labored with me in the Good News, with Clement also, and the rest of my fellow workers, whose names are in the book of life.", "tr": "World English Bible"}, "Philippians 4:6": {"t": "In nothing be anxious, but in everything, by prayer and petition with thanksgiving, let your requests be made known to God.", "tr": "World English Bible"}, "Proverbs 1:7": {"t": "The fear of Yahweh is the beginning of knowledge; but the foolish despise wisdom and instruction.", "tr": "World English Bible"}, "Proverbs 31": {"t": "The words of king Lemuel; the oracle which his mother taught him. “Oh, my son! Oh, son of my womb! Oh, son of my vows! Don’t give your strength to women, nor your ways to that which destroys kings. It is not for kings, Lemuel; it is not for kings to drink wine; nor for princes to say, ‘Where is strong drink?’ lest they drink, and forget the law, and pervert the justice due to anyone who is afflicted. Give strong drink to him who is ready to perish; and wine to the bitter in soul: Let him drink, and forget his poverty, and remember his misery no more. Open your mouth for the mute, in the cause of all who are left desolate. Open your mouth, judge righteously, and serve justice to the poor and [the passage continues in your Bible]", "tr": "World English Bible"}, "Proverbs 3:5-6": {"t": "Trust in Yahweh with all your heart, and don’t lean on your own understanding. In all your ways acknowledge him, and he will make your paths straight.", "tr": "World English Bible"}, "Proverbs 5:18-19": {"t": "Let your spring be blessed. Rejoice in the wife of your youth. A loving doe and a graceful deer— let her breasts satisfy you at all times. Be captivated always with her love.", "tr": "World English Bible"}, "Psalm 113:5-6": {"t": "Who is like Yahweh, our God, who has his seat on high, Who stoops down to see in heaven and in the earth?", "tr": "World English Bible"}, "Psalm 119:105": {"t": "Your word is a lamp to my feet, and a light for my path.", "tr": "World English Bible"}, "Psalm 12:6": {"t": "Yahweh’s words are flawless words, as silver refined in a clay furnace, purified seven times.", "tr": "World English Bible"}, "Psalm 139:13-16": {"t": "For you formed my inmost being. You knit me together in my mother’s womb. I will give thanks to you, for I am fearfully and wonderfully made. Your works are wonderful. My soul knows that very well. My frame wasn’t hidden from you, when I was made in secret, woven together in the depths of the earth. Your eyes saw my body. In your book they were all written, the days that were ordained for me, when as yet there were none of them.", "tr": "World English Bible"}, "Psalm 139:14": {"t": "I will give thanks to you, for I am fearfully and wonderfully made. Your works are wonderful. My soul knows that very well.", "tr": "World English Bible"}, "Psalm 19:1": {"t": "The heavens declare the glory of God. The expanse shows his handiwork.", "tr": "World English Bible"}, "Psalm 19:1-6; Acts 14:17": {"t": "The heavens declare the glory of God. The expanse shows his handiwork. Day after day they pour out speech, and night after night they display knowledge. There is no speech nor language, where their voice is not heard. Their voice has gone out through all the earth, their words to the end of the world. In them he has set a tent for the sun, which is as a bridegroom coming out of his room, like a strong man rejoicing to run his course. His going out is from the end of the heavens, his circuit to its ends; There is nothing hidden from its heat.", "tr": "World English Bible"}, "Psalm 22:1": {"t": "My God, my God, why have you forsaken me? Why are you so far from helping me, and from the words of my groaning?", "tr": "World English Bible"}, "Psalm 22:16": {"t": "For dogs have surrounded me. A company of evildoers have enclosed me. They have pierced my hands and feet.", "tr": "World English Bible"}, "Psalm 22:18": {"t": "They divide my garments among them. They cast lots for my clothing.", "tr": "World English Bible"}, "Psalm 23:1": {"t": "Yahweh is my shepherd: I shall lack nothing.", "tr": "World English Bible"}, "Psalm 34:20": {"t": "He protects all of his bones. Not one of them is broken.", "tr": "World English Bible"}, "Psalm 50:1": {"t": "The Mighty One, God, Yahweh, speaks, and calls the earth from sunrise to sunset.", "tr": "World English Bible"}, "Psalm 51:1-4": {"t": "Have mercy on me, God, according to your loving kindness. According to the multitude of your tender mercies, blot out my transgressions. Wash me thoroughly from my iniquity. Cleanse me from my sin. For I know my transgressions. My sin is constantly before me. Against you, and you only, have I sinned, and done that which is evil in your sight; that you may be proved right when you speak, and justified when you judge.", "tr": "World English Bible"}, "Psalm 69:21": {"t": "They also gave me gall for my food. In my thirst, they gave me vinegar to drink.", "tr": "World English Bible"}, "Psalm 90:2": {"t": "Before the mountains were born, before you had formed the earth and the world, even from everlasting to everlasting, you are God.", "tr": "World English Bible"}, "Psalm 93:1": {"t": "Yahweh reigns! He is clothed with majesty! Yahweh is armed with strength. The world also is established. It can’t be moved.", "tr": "World English Bible"}, "Revelation 1:8": {"t": "“I am the Alpha and the Omega,” says the Lord God, “who is and who was and who is to come, the Almighty.”", "tr": "World English Bible"}, "Revelation 1:9": {"t": "I John, your brother and partner with you in oppression, Kingdom, and perseverance in Christ Jesus, was on the isle that is called Patmos because of God’s Word and the testimony of Jesus Christ.", "tr": "World English Bible"}, "Revelation 21:4": {"t": "He will wipe away from them every tear from their eyes. Death will be no more; neither will there be mourning, nor crying, nor pain, any more. The first things have passed away.”", "tr": "World English Bible"}, "Revelation 21:5": {"t": "He who sits on the throne said, “Behold, I am making all things new.” He said, “Write, for these words of God are faithful and true.”", "tr": "World English Bible"}, "Revelation 2:10": {"t": "Don’t be afraid of the things which you are about to suffer. Behold, the devil is about to throw some of you into prison, that you may be tested; and you will have oppression for ten days. Be faithful to death, and I will give you the crown of life.", "tr": "World English Bible"}, "Revelation 3:20": {"t": "Behold, I stand at the door and knock. If anyone hears my voice and opens the door, then I will come in to him, and will dine with him, and he with me.", "tr": "World English Bible"}, "Revelation 7:9": {"t": "After these things I looked, and behold, a great multitude, which no man could number, out of every nation and of all tribes, peoples, and languages, standing before the throne and before the Lamb, dressed in white robes, with palm branches in their hands.", "tr": "World English Bible"}, "Romans 11:34-36": {"t": "“For who has known the mind of the Lord? Or who has been his counselor?” “Or who has first given to him, and it will be repaid to him again?” For of him, and through him, and to him, are all things. To him be the glory for ever! Amen.", "tr": "World English Bible"}, "Romans 11:36": {"t": "For of him, and through him, and to him, are all things. To him be the glory for ever! Amen.", "tr": "World English Bible"}, "Romans 12:18": {"t": "If it is possible, as much as it is up to you, be at peace with all men.", "tr": "World English Bible"}, "Romans 12:19": {"t": "Don’t seek revenge yourselves, beloved, but give place to God’s wrath. For it is written, “Vengeance belongs to me; I will repay, says the Lord.”", "tr": "World English Bible"}, "Romans 13:13-14": {"t": "Let us walk properly, as in the day; not in reveling and drunkenness, not in sexual promiscuity and lustful acts, and not in strife and jealousy. But put on the Lord Jesus Christ, and make no provision for the flesh, for its lusts.", "tr": "World English Bible"}, "Romans 13:4": {"t": "for he is a servant of God to you for good. But if you do that which is evil, be afraid, for he doesn’t bear the sword in vain; for he is a servant of God, an avenger for wrath to him who does evil.", "tr": "World English Bible"}, "Romans 16": {"t": "I commend to you Phoebe, our sister, who is a servant of the assembly that is at Cenchreae, that you receive her in the Lord, in a way worthy of the saints, and that you assist her in whatever matter she may need from you, for she herself also has been a helper of many, and of my own self. Greet Prisca and Aquila, my fellow workers in Christ Jesus, who for my life, laid down their own necks; to whom not only I give thanks, but also all the assemblies of the Gentiles. Greet the assembly that is in their house. Greet Epaenetus, my beloved, who is the first fruits of Achaia to Christ. Greet Mary, who labored much for us. Greet Andronicus and Junia, my relatives and my fellow prisoners, who are [the passage continues in your Bible]", "tr": "World English Bible"}, "Romans 16:22": {"t": "I, Tertius, who write the letter, greet you in the Lord.", "tr": "World English Bible"}, "Romans 1:16-17": {"t": "For I am not ashamed of the Good News of Christ, for it is the power of God for salvation for everyone who believes; for the Jew first, and also for the Greek. For in it is revealed God’s righteousness from faith to faith. As it is written, “But the righteous shall live by faith.”", "tr": "World English Bible"}, "Romans 1:17": {"t": "For in it is revealed God’s righteousness from faith to faith. As it is written, “But the righteous shall live by faith.”", "tr": "World English Bible"}, "Romans 1:20": {"t": "For the invisible things of him since the creation of the world are clearly seen, being perceived through the things that are made, even his everlasting power and divinity; that they may be without excuse.", "tr": "World English Bible"}, "Romans 1:20; Romans 2:14-15": {"t": "For the invisible things of him since the creation of the world are clearly seen, being perceived through the things that are made, even his everlasting power and divinity; that they may be without excuse.", "tr": "World English Bible"}, "Romans 1:26-27": {"t": "For this reason, God gave them up to vile passions. For their women changed the natural function into that which is against nature. Likewise also the men, leaving the natural function of the woman, burned in their lust toward one another, men doing what is inappropriate with men, and receiving in themselves the due penalty of their error.", "tr": "World English Bible"}, "Romans 1:3-4": {"t": "concerning his Son, who was born of the seed of David according to the flesh, who was declared to be the Son of God with power, according to the Spirit of holiness, by the resurrection from the dead, Jesus Christ our Lord,", "tr": "World English Bible"}, "Romans 2:14-15": {"t": "(for when Gentiles who don’t have the law do by nature the things of the law, these, not having the law, are a law to themselves, in that they show the work of the law written in their hearts, their conscience testifying with them, and their thoughts among themselves accusing or else excusing them)", "tr": "World English Bible"}, "Romans 2:15": {"t": "in that they show the work of the law written in their hearts, their conscience testifying with them, and their thoughts among themselves accusing or else excusing them)", "tr": "World English Bible"}, "Romans 3:23": {"t": "for all have sinned, and fall short of the glory of God;", "tr": "World English Bible"}, "Romans 3:25": {"t": "whom God sent to be an atoning sacrifice, through faith in his blood, for a demonstration of his righteousness through the passing over of prior sins, in God’s forbearance;", "tr": "World English Bible"}, "Romans 3:25-26": {"t": "whom God sent to be an atoning sacrifice, through faith in his blood, for a demonstration of his righteousness through the passing over of prior sins, in God’s forbearance; to demonstrate his righteousness at this present time; that he might himself be just, and the justifier of him who has faith in Jesus.", "tr": "World English Bible"}, "Romans 3:4": {"t": "May it never be! Yes, let God be found true, but every man a liar. As it is written, “That you might be justified in your words, and might prevail when you come into judgment.”", "tr": "World English Bible"}, "Romans 5:8": {"t": "But God commends his own love toward us, in that while we were yet sinners, Christ died for us.", "tr": "World English Bible"}, "Romans 9:11-13": {"t": "For being not yet born, neither having done anything good or bad, that the purpose of God according to election might stand, not of works, but of him who calls, it was said to her, “The elder will serve the younger.” Even as it is written, “Jacob I loved, but Esau I hated.”", "tr": "World English Bible"}, "Ruth 1:16": {"t": "Ruth said, “Don’t entreat me to leave you, and to return from following after you, for where you go, I will go; and where you lodge, I will lodge; your people shall be my people, and your God my God;", "tr": "World English Bible"}, "Ruth 4:17": {"t": "The women, her neighbors, gave him a name, saying, “There is a son born to Naomi”; and they named him Obed. He is the father of Jesse, the father of David.", "tr": "World English Bible"}, "Song of Songs 2:4": {"t": "He brought me to the banquet hall. His banner over me is love.", "tr": "World English Bible"}, "Song of Songs 8:6": {"t": "Set me as a seal on your heart, as a seal on your arm; for love is strong as death. Jealousy is as cruel as Sheol. Its flashes are flashes of fire, a very flame of Yahweh.", "tr": "World English Bible"}, "Titus 2:11-12": {"t": "For the grace of God has appeared, bringing salvation to all men, instructing us to the intent that, denying ungodliness and worldly lusts, we would live soberly, righteously, and godly in this present world;", "tr": "World English Bible"}, "Titus 2:3-5": {"t": "and that older women likewise be reverent in behavior, not slanderers nor enslaved to much wine, teachers of that which is good; that they may train the young women to love their husbands, to love their children, to be sober minded, chaste, workers at home, kind, being in subjection to their own husbands, that God’s word may not be blasphemed.", "tr": "World English Bible"}, "Titus 3:5": {"t": "not by works of righteousness, which we did ourselves, but according to his mercy, he saved us, through the washing of regeneration and renewing by the Holy Spirit,", "tr": "World English Bible"}, "Zechariah 11:12-13": {"t": "I said to them, “If you think it best, give me my wages; and if not, keep them.” So they weighed for my wages thirty pieces of silver. Yahweh said to me, “Throw it to the potter, the handsome price that I was valued at by them!” I took the thirty pieces of silver, and threw them to the potter, in Yahweh’s house.", "tr": "World English Bible"}, "Zechariah 12:10": {"t": "I will pour on the house of David, and on the inhabitants of Jerusalem, the spirit of grace and of supplication; and they will look to me whom they have pierced; and they shall mourn for him, as one mourns for his only son, and will grieve bitterly for him, as one grieves for his firstborn.", "tr": "World English Bible"}, "Zechariah 13:1": {"t": "“In that day there will be a spring opened to the house of David and to the inhabitants of Jerusalem, for sin and for uncleanness.", "tr": "World English Bible"}, "Zechariah 1:1": {"t": "In the eighth month, in the second year of Darius, Yahweh’s word came to Zechariah the son of Berechiah, the son of Iddo, the prophet, saying,", "tr": "World English Bible"}, "Zechariah 2:10-11": {"t": "Sing and rejoice, daughter of Zion; for, behold, I come, and I will dwell in your midst,’ says Yahweh. Many nations shall join themselves to Yahweh in that day, and shall be my people; and I will dwell in your midst, and you shall know that Yahweh of Armies has sent me to you.", "tr": "World English Bible"}, "Zechariah 4:6": {"t": "Then he answered and spoke to me, saying, “This is Yahweh’s word to Zerubbabel, saying, ‘Not by might, nor by power, but by my Spirit,’ says Yahweh of Armies.", "tr": "World English Bible"}, "Zechariah 9:9": {"t": "Rejoice greatly, daughter of Zion! Shout, daughter of Jerusalem! Behold, your King comes to you! He is righteous, and having salvation; lowly, and riding on a donkey, even on a colt, the foal of a donkey.", "tr": "World English Bible"}, "Zephaniah 1:1": {"t": "Yahweh’s word which came to Zephaniah, the son of Cushi, the son of Gedaliah, the son of Amariah, the son of Hezekiah, in the days of Josiah, the son of Amon, king of Judah.", "tr": "World English Bible"}, "Zephaniah 1:14": {"t": "The great day of Yahweh is near. It is near, and hurries greatly, the voice of the day of Yahweh. The mighty man cries there bitterly.", "tr": "World English Bible"}, "Zephaniah 1:14-18": {"t": "The great day of Yahweh is near. It is near, and hurries greatly, the voice of the day of Yahweh. The mighty man cries there bitterly. That day is a day of wrath, a day of distress and anguish, a day of trouble and ruin, a day of darkness and gloom, a day of clouds and blackness, a day of the trumpet and alarm, against the fortified cities, and against the high battlements. I will bring distress on men, that they will walk like blind men, because they have sinned against Yahweh, and their blood will be poured out like dust, and their flesh like dung. Neither their silver nor their gold will be able to deliver them in the day of Yahweh’s wrath, but the whole land will be devoured by the fire [the passage continues in your Bible]", "tr": "World English Bible"}, "Zephaniah 2:3": {"t": "Seek Yahweh, all you humble of the land, who have kept his ordinances. Seek righteousness. Seek humility. It may be that you will be hidden in the day of Yahweh’s anger.", "tr": "World English Bible"}, "Zephaniah 3:17": {"t": "Yahweh, your God, is in your midst, a mighty one who will save. He will rejoice over you with joy. He will calm you in his love. He will rejoice over you with singing.", "tr": "World English Bible"}};
  var st=document.createElement('style');
  st.textContent=".ref{cursor:pointer;border-bottom:0.5px dotted currentColor;}"+
   ".ref:hover{color:var(--accent,#cda94e);}"+
   ".vov{position:fixed;inset:0;background:rgba(8,6,4,0.55);-webkit-backdrop-filter:blur(3px);backdrop-filter:blur(3px);z-index:320;display:none;align-items:center;justify-content:center;padding:22px;}"+
   ".vov.open{display:flex;}"+
   ".vpanel{position:relative;max-width:440px;width:100%;background:#f4eede;color:#241a0e;border-radius:20px;padding:26px 26px 18px;box-shadow:0 30px 80px rgba(0,0,0,0.55);max-height:80vh;overflow-y:auto;border:0.5px solid rgba(0,0,0,0.10);}"+
   ".vref{font-family:'SF Pro Text',system-ui,sans-serif;font-size:12px;font-weight:700;letter-spacing:0.09em;text-transform:uppercase;color:#9a6a2e;margin-bottom:11px;}"+
   ".vtext{font-family:Georgia,'SF Pro Display',serif;font-size:18px;line-height:1.52;font-weight:400;}"+
   ".vtr{font-family:'SF Pro Text',system-ui,sans-serif;font-size:11px;color:#8a7a64;margin-top:16px;padding-top:11px;border-top:0.5px solid rgba(0,0,0,0.12);}"+
   ".vclose{position:absolute;top:13px;right:13px;width:28px;height:28px;border-radius:50%;border:none;background:rgba(0,0,0,0.06);color:#241a0e;font-size:15px;line-height:1;cursor:pointer;}"+
   ".vclose:hover{background:rgba(0,0,0,0.12);}";
  document.head.appendChild(st);
  var ov=document.createElement('div'); ov.className='vov';
  ov.innerHTML='<div class="vpanel"><button class="vclose" aria-label="Close">&times;</button><div class="vref"></div><div class="vtext"></div><div class="vtr"></div></div>';
  function mount(){ if(!ov.parentNode) document.body.appendChild(ov); }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',mount); else mount();
  function show(raw){
    var key=raw.replace(/^[\s(]+|[\s)]+$/g,'').trim();
    var rec=V[key];
    ov.querySelector('.vref').textContent=key;
    if(rec && rec.t){ ov.querySelector('.vtext').textContent=rec.t; ov.querySelector('.vtr').textContent=rec.tr; }
    else { ov.querySelector('.vtext').textContent='Open this passage in your Bible to read it in full.'; ov.querySelector('.vtr').textContent=''; }
    mount(); ov.classList.add('open'); ov.querySelector('.vpanel').scrollTop=0;
  }
  document.addEventListener('click',function(e){
    var r=e.target.closest('.ref');
    if(r){ e.preventDefault(); e.stopPropagation(); show(r.textContent); return; }
    if(e.target===ov||e.target.classList.contains('vclose')){ e.stopPropagation(); ov.classList.remove('open'); }
  },true);
  document.addEventListener('keydown',function(e){
    if(e.key==='Escape'&&ov.classList.contains('open')){ e.stopPropagation(); ov.classList.remove('open'); }
  },true);
})();